export type TransactionType = 'income' | 'expense';

export interface Account {
  id: string;
  name: string;
  type: 'Bank' | 'Cash' | 'Card';
  initialBalance: number;
  currentBalance: number;
  color: string;
}

export interface Saving {
  id: string;
  name: string;
  currentAmount: number;
  targetAmount?: number;
  isInvestment: boolean;
  growthRate?: number; // Annual percentage
  color: string;
}

export interface Refund {
  id: string;
  name: string;
  totalAmount: number;
  paidByMe: number;
  pendingAmount: number;
  status: 'open' | 'closed';
  notes: string;
  date: string;
}

export interface Transaction {
  id: string;
  date: string;
  amount: number;
  description: string;
  category: string;
  type: TransactionType;
  accountId: string;
  isRefund: boolean;
  refundId?: string;
  image?: string;
}

export interface Budget {
  id: string;
  category: string;
  limit: number;
  icon: string;
  spent: number;
}

export interface FinanceState {
  accounts: Account[];
  savings: Saving[];
  refunds: Refund[];
  transactions: Transaction[];
  budgets: Budget[];
  currentDate: string; // ISO format (YYYY-MM)
}

import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { Transaction, Budget } from "../types";

const API_KEY = process.env.API_KEY || "";

export const analyzeReceipt = async (base64Image: string): Promise<Partial<Transaction>[]> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: 'Extrae una lista de transacciones de esta imagen. Para cada una, identifica: descripción, monto, fecha (YYYY-MM-DD), categoría (ej: Comida, Transporte, Ocio) y si es Gasto o Ingreso. Devuelve un JSON puro.' }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            type: { type: Type.STRING, description: 'income or expense' }
          },
          required: ['description', 'amount', 'date', 'category', 'type']
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

export const getFinancialAdvice = async (
  context: string,
  userMessage: string
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Estado Financiero Actual:\n${context}\n\nUsuario: ${userMessage}`,
    config: {
      systemInstruction: 'Eres un asesor financiero experto llamado "Aura". Analiza los datos del usuario y proporciona consejos prácticos para mejorar el ahorro, gestión patrimonial y optimización de gastos. Sé profesional, empático y conciso. Responde siempre en español.',
    }
  });

  return response.text || "Lo siento, no pude procesar tu solicitud.";
};

