const Header = () => {
  const { currentDate, changeMonth, setMonth } = useFinance();
  const [showMonthPicker, setShowMonthPicker] = useState(false);

  const monthNames = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio",
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];

  const currentFormatted = useMemo(() => {
    const [year, month] = currentDate.split('-').map(Number);
    return `${monthNames[month - 1]} ${year}`;
  }, [currentDate]);

  const years = Array.from({ length: 5 }, (_, i) => new Date().getFullYear() - 2 + i);

  return (
    <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 h-16 flex items-center justify-between px-6 sticky top-0 z-20">
      <div className="flex items-center gap-4">
        <button className="md:hidden p-2 hover:bg-slate-100 rounded-lg">
          <Menu size={20} />
        </button>
        <div className="flex items-center gap-2 bg-slate-100 p-1 rounded-xl">
          <button 
            onClick={() => changeMonth(-1)}
            className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"
          >
            <ChevronLeft size={20} />
          </button>

          <div className="relative">
            <button 
              onClick={() => setShowMonthPicker(!showMonthPicker)}
              className="px-4 py-1 text-sm font-semibold text-slate-700 min-w-[140px] text-center"
            >
              {currentFormatted}
            </button>

            {showMonthPicker && (
              <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 w-72 bg-white border border-slate-200 rounded-2xl shadow-xl p-4 grid grid-cols-3 gap-2 z-50 animate-in fade-in zoom-in duration-200">
                {monthNames.map((name, idx) => (
                  <button
                    key={name}
                    onClick={() => {
                      const year = currentDate.split('-')[0];
                      setMonth(`${year}-${String(idx + 1).padStart(2, '0')}`);
                      setShowMonthPicker(false);
                    }}
                    className={`p-2 text-xs rounded-lg ${
                      currentDate.split('-')[1] === String(idx + 1).padStart(2, '0')
                        ? 'bg-blue-600 text-white'
                        : 'hover:bg-slate-100 text-slate-600'
                    }`}
                  >
                    {name}
                  </button>
                ))}
                <div className="col-span-3 border-t border-slate-100 mt-2 pt-2 flex justify-between">
                  {years.map(y => (
                    <button 
                      key={y}
                      onClick={() => {
                        const month = currentDate.split('-')[1];
                        setMonth(`${y}-${month}`);
                      }}
                      className={`px-2 py-1 text-[10px] rounded ${currentDate.startsWith(String(y)) ? 'bg-slate-200' : 'hover:bg-slate-50'}`}
                    >
                      {y}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>

          <button 
            onClick={() => changeMonth(1)}
            className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"
          >
            <ChevronRight size={20} />
          </button>
        </div>
      </div>

      <div className="flex items-center gap-3">
        <div className="hidden sm:block text-right">
          <p className="text-xs text-slate-500 font-medium">Bienvenido</p>
          <p className="text-sm font-bold text-slate-800">Usuario Demo</p>
        </div>
        <div className="w-10 h-10 rounded-full bg-blue-100 border-2 border-white shadow-sm overflow-hidden">
          <img src="https://picsum.photos/100/100" alt="avatar" />
        </div>
      </div>
    </header>
  );
};

const QuickAddButton = () => {
  const [open, setOpen] = useState(false);
  const { addTransaction, accounts } = useFinance();

  const handleAddQuick = () => {
    if (accounts.length === 0) return alert("Crea una cuenta primero");
    // Mock simple expense
    addTransaction({
      date: new Date().toISOString().split('T')[0],
      amount: 10,
      description: 'Gasto rápido',
      category: 'Ocio',
      type: 'expense',
      accountId: accounts[0].id,
      isRefund: false
    });
    setOpen(false);
  };

  return (
    <div className="fixed bottom-8 right-8 z-40">
      {open && (
        <div className="absolute bottom-16 right-0 mb-2 flex flex-col gap-2 animate-in slide-in-from-bottom-4 duration-300">
          <Link 
            to="/transactions" 
            className="flex items-center gap-2 bg-white text-slate-800 px-4 py-3 rounded-2xl shadow-lg hover:bg-slate-50 border border-slate-100 transition-all"
          >
            <Receipt size={18} className="text-blue-500" />
