    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
    const income = monthTx.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0);
    const expense = monthTx.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);

    // Previous balance calculation (simplified for demo)
    // In a real app we'd sum all transactions before currentDate + initial balances
    const totalCurrentAssets = accounts.reduce((sum, acc) => sum + acc.currentBalance, 0);
    const previousBalance = totalCurrentAssets - (income - expense);

    return {
      income,
      expense,
      previousBalance,
      monthResult: income - expense,
      finalBalance: totalCurrentAssets
