                  <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                    <div 
                      className={`h-full rounded-full transition-all duration-1000 ${progress > 90 ? 'bg-rose-500' : 'bg-blue-500'}`} 
                      style={{ width: `${progress}%` }}
                    ></div>
                  </div>
                </div>
              );
            })}
            {budgets.length === 0 && (
              <p className="text-sm text-slate-400 italic text-center py-10">No hay presupuestos activos</p>
            )}
          </div>
        </div>
      </div>

      {/* Account summary horizontal scroll */}
      <div className="space-y-4">
        <h3 className="font-bold text-slate-800">Tus Cuentas</h3>
        <div className="flex gap-4 overflow-x-auto pb-4 custom-scrollbar">
          {accounts.map(acc => (
            <div key={acc.id} className="min-w-[280px] bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-start gap-4">
              <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-white" style={{ backgroundColor: acc.color }}>
                <Wallet size={24} />
              </div>
              <div className="flex-1">
                <p className="text-sm font-semibold text-slate-800">{acc.name}</p>
                <p className="text-xs text-slate-400 capitalize">{acc.type}</p>
                <p className="text-lg font-bold mt-2 text-slate-900">{acc.currentBalance.toLocaleString('es-ES')}€</p>
              </div>
            </div>
          ))}
          <Link to="/accounts" className="min-w-[280px] border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 hover:border-blue-400 hover:text-blue-500 transition-all">
            <Plus size={24} />
            <span className="text-sm font-medium mt-1">Añadir cuenta</span>
          </Link>
        </div>
      </div>
    </div>
  );
};

const Link = ({ to, children, className }: any) => <a href={`#${to}`} className={className}>{children}</a>;
const Plus = ({ size, className }: any) => <Plus size={size} className={className} />;

export default Dashboard;

import React, { useState } from 'react';
