  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    if (fromId === toId) return alert("Las cuentas deben ser diferentes");

    // Create two transactions to represent the transfer
    const date = new Date().toISOString().split('T')[0];
    addTransaction({
      date,
      amount,
      description: `Transferencia a ${accounts.find(a => a.id === toId)?.name}`,
      category: 'Transferencia',
      type: 'expense',
      accountId: fromId,
      isRefund: false
    });
    addTransaction({
      date,
      amount,
      description: `Transferencia desde ${accounts.find(a => a.id === fromId)?.name}`,
      category: 'Transferencia',
      type: 'income',
      accountId: toId,
      isRefund: false
    });

