import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, PiggyBank, TrendingUp, TrendingDown, ArrowUp, ArrowDown } from 'lucide-react';
import { Saving } from '../types';

const Savings: React.FC = () => {
  const { savings, addSaving, updateSaving, deleteSaving } = useFinance();
  const [isAdding, setIsAdding] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [amount, setAmount] = useState(0);
  const [target, setTarget] = useState(0);
  const [isInvestment, setIsInvestment] = useState(false);
  const [growth, setGrowth] = useState(0);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    addSaving({
      name,
      currentAmount: amount,
      targetAmount: target || undefined,
      isInvestment,
      growthRate: isInvestment ? growth : undefined,
      color: '#f59e0b'
    });
    setIsAdding(false);
    resetForm();
  };

  const resetForm = () => {
    setName(''); setAmount(0); setTarget(0); setIsInvestment(false); setGrowth(0);
  };

  const adjustFunds = (id: string, delta: number) => {
    const s = savings.find(x => x.id === id);
    if (!s) return;
    updateSaving({ ...s, currentAmount: Math.max(0, s.currentAmount + delta) });
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Ahorros e Inversiones</h2>
          <p className="text-slate-500">Haz crecer tu patrimonio y visualiza tus metas.</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-md"
        >
          <Plus size={18} />
          Crear Hucha
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {savings.map(s => {
          const progress = s.targetAmount ? Math.min((s.currentAmount / s.targetAmount) * 100, 100) : null;
          return (
            <div key={s.id} className="bg-white rounded-3xl p-6 border border-slate-100 shadow-sm">
              <div className="flex items-center gap-4 mb-6">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white bg-amber-500 shadow-lg shadow-amber-100`}>
                  {s.isInvestment ? <TrendingUp size={24} /> : <PiggyBank size={24} />}
                </div>
                <div>
                  <h4 className="font-bold text-slate-800">{s.name}</h4>
                  <p className="text-xs text-slate-400 font-medium">{s.isInvestment ? `Inversión (${s.growthRate}% anual)` : 'Hucha de ahorro'}</p>
                </div>
              </div>

              <div className="mb-6">
                <p className="text-3xl font-black text-slate-900">{s.currentAmount.toLocaleString('es-ES')}€</p>
                {progress !== null && (
                  <div className="mt-4">
                    <div className="flex justify-between text-xs font-bold mb-1.5">
                      <span className="text-blue-600">{progress.toFixed(0)}% de la meta</span>
                      <span className="text-slate-400">Meta: {s.targetAmount}€</span>
                    </div>
                    <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
                      <div className="h-full bg-blue-500 rounded-full transition-all duration-700" style={{ width: `${progress}%` }}></div>
                    </div>
                  </div>
                )}
              </div>

              <div className="flex gap-2">
                <button 
                  onClick={() => adjustFunds(s.id, 50)}
                  className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-emerald-50 text-emerald-600 rounded-xl font-bold text-sm hover:bg-emerald-100 transition-all"
                >
                  <ArrowUp size={16} /> +50€
                </button>
                <button 
                  onClick={() => adjustFunds(s.id, -50)}
                  className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-rose-50 text-rose-600 rounded-xl font-bold text-sm hover:bg-rose-100 transition-all"
                >
                  <ArrowDown size={16} /> -50€
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl animate-in fade-in zoom-in duration-200">
            <h3 className="text-xl font-bold mb-6">Nueva Hucha de Ahorro</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Nombre</label>
                <input 
                  type="text" 
                  value={name} 
                  onChange={e => setName(e.target.value)}
                  className="w-full bg-slate-50 border-none rounded-xl p-3 focus:ring-2 focus:ring-blue-500" 
                  placeholder="Ej: Vacaciones" 
                  required 
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Cantidad Inicial</label>
                  <input 
                    type="number" 
                    value={amount} 
                    onChange={e => setAmount(Number(e.target.value))}
                    className="w-full bg-slate-50 border-none rounded-xl p-3 focus:ring-2 focus:ring-blue-500" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Meta (Opcional)</label>
                  <input 
                    type="number" 
                    value={target} 
                    onChange={e => setTarget(Number(e.target.value))}
                    className="w-full bg-slate-50 border-none rounded-xl p-3 focus:ring-2 focus:ring-blue-500" 
                  />
                </div>
              </div>
              <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl">
                <input 
                  type="checkbox" 
                  id="inv" 
                  checked={isInvestment} 
                  onChange={e => setIsInvestment(e.target.checked)}
                  className="w-5 h-5 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                />
                <label htmlFor="inv" className="text-sm font-semibold text-slate-700">Es una inversión (Bolsa)</label>
              </div>
              {isInvestment && (
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Crecimiento Anual Estimado (%)</label>
                  <input 
                    type="number" 
                    value={growth} 
                    onChange={e => setGrowth(Number(e.target.value))}
                    className="w-full bg-slate-50 border-none rounded-xl p-3 focus:ring-2 focus:ring-blue-500" 
                  />
                </div>
              )}
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200">Cancelar</button>
                <button type="submit" className="flex-1 py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700">Crear</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Savings;

import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, CheckCircle2, Circle, Users, DollarSign, XCircle } from 'lucide-react';
import { Refund } from '../types';

const Refunds: React.FC = () => {
  const { refunds, addRefund, updateRefund } = useFinance();
  const [isAdding, setIsAdding] = useState(false);

  // Form
  const [name, setName] = useState('');
  const [total, setTotal] = useState(0);
  const [myPart, setMyPart] = useState(0);
  const [notes, setNotes] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    addRefund({
      name,
      totalAmount: total,
      paidByMe: myPart,
      pendingAmount: total - myPart,
      status: 'open',
      notes,
      date: new Date().toISOString()
    });
    setIsAdding(false);
    reset();
  };

  const reset = () => { setName(''); setTotal(0); setMyPart(0); setNotes(''); };

  const closeRefund = (id: string) => {
    const r = refunds.find(x => x.id === id);
    if (r) updateRefund({ ...r, status: 'closed', pendingAmount: 0 });
  };

  const addPayment = (id: string, amount: number) => {
    const r = refunds.find(x => x.id === id);
    if (!r) return;
    const newPending = Math.max(0, r.pendingAmount - amount);
    updateRefund({ ...r, pendingAmount: newPending, status: newPending <= 0 ? 'closed' : 'open' });
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Reembolsos</h2>
          <p className="text-slate-500">Lleva el control de gastos compartidos y quién te debe dinero.</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-md"
        >
          <Plus size={18} />
          Nuevo Gasto Compartido
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {refunds.map(r => (
          <div key={r.id} className={`bg-white rounded-3xl p-6 border transition-all ${r.status === 'closed' ? 'border-slate-100 opacity-60' : 'border-blue-100 shadow-sm'}`}>
