const API_KEY = process.env.API_KEY || "";

export const analyzeReceipt = async (base64Image: string): Promise<Partial<Transaction>[]> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: 'Extrae una lista de transacciones de esta imagen. Para cada una, identifica: descripción, monto, fecha (YYYY-MM-DD), categoría (ej: Comida, Transporte, Ocio) y si es Gasto o Ingreso. Devuelve un JSON puro.' }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            type: { type: Type.STRING, description: 'income or expense' }
          },
          required: ['description', 'amount', 'date', 'category', 'type']
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

