const Dashboard: React.FC = () => {
  const { accounts, savings, transactions, budgets, challenges, toggleChallenge, currentDate } = useFinance();

  const metrics = useMemo(() => {
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
    const income = monthTx.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0);
    const expense = monthTx.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);
    const savingsInMonth = 0; // Calculado si detectamos transferencias a cuentas de ahorro

    // Saldo anterior (suma de balances de cuentas - resultado mes actual)
    const totalAssets = accounts.reduce((sum, acc) => sum + acc.currentBalance, 0);
    const monthResult = income - expense;
    const previousBalance = totalAssets - monthResult;

    return { income, expense, previousBalance, monthResult, totalAssets };
  }, [transactions, currentDate, accounts]);

  const savingsTotal = useMemo(() => savings.reduce((sum, s) => sum + s.currentAmount, 0), [savings]);

  const chartData = useMemo(() => {
    // Generar datos aproximados para el gráfico basados en el patrimonio actual
    const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun'];
    return months.map((m, i) => ({
      name: m,
      balance: metrics.totalAssets * (0.8 + (i * 0.05)) // Simulación ascendente basada en real
