const Accounts: React.FC = () => {
  const { accounts, addAccount, updateAccount, deleteAccount, addTransaction } = useFinance();
  const [modal, setModal] = useState<{ type: 'add' | 'edit' | 'transfer' | null, account?: Account }>({ type: null });

  // Form state
  const [formData, setFormData] = useState({ name: '', type: 'Bank' as Account['type'], initialBalance: 0, color: '#3b82f6', emoji: '🏦' });
  const [transferData, setTransferData] = useState({ fromId: '', toId: '', amount: 0 });

  const openAdd = () => {
    setFormData({ name: '', type: 'Bank', initialBalance: 0, color: '#3b82f6', emoji: '🏦' });
    setModal({ type: 'add' });
  };

  const openEdit = (acc: Account) => {
    setFormData({ ...acc });
    setModal({ type: 'edit', account: acc });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (modal.type === 'add') {
      addAccount(formData);
    } else if (modal.type === 'edit' && modal.account) {
      updateAccount({ ...modal.account, ...formData });
    }
    setModal({ type: null });
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    const fromAcc = accounts.find(a => a.id === transferData.fromId);
    const toAcc = accounts.find(a => a.id === transferData.toId);
    if (!fromAcc || !toAcc || fromAcc.id === toAcc.id) return;

    const date = new Date().toISOString().split('T')[0];
    addTransaction({ date, amount: transferData.amount, description: `Traspaso a ${toAcc.name}`, category: 'Transferencia', type: 'expense', accountId: fromAcc.id, isRefund: false, emoji: '🔄' });
    addTransaction({ date, amount: transferData.amount, description: `Traspaso desde ${fromAcc.name}`, category: 'Transferencia', type: 'income', accountId: toAcc.id, isRefund: false, emoji: '🔄' });
    setModal({ type: null });
  };

  return (
    <div className="space-y-8 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
