          <button onClick={openAdd} className="flex items-center gap-2 px-6 py-4 bg-blue-600 text-white font-bold rounded-[1.5rem] hover:bg-blue-700 transition-all shadow-xl shadow-blue-200">
            <Plus size={20} /> Nueva Cuenta
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {accounts.map(acc => (
          <div key={acc.id} className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm relative group">
            <div className="flex justify-between items-start mb-8">
              <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-3xl shadow-inner bg-slate-50 border border-slate-100">
