              </div>
              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => openEdit(acc)} className="p-2.5 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-xl"><Edit2 size={18} /></button>
                <button onClick={() => deleteAccount(acc.id)} className="p-2.5 bg-slate-50 text-slate-400 hover:text-rose-600 rounded-xl"><Trash2 size={18} /></button>
