import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, CheckCircle2, Circle, Users, DollarSign, XCircle, Trash2, Merge } from 'lucide-react';
import { Refund } from '../types';

const Refunds: React.FC = () => {
  const { refunds, updateRefund, deleteRefund, mergeRefunds } = useFinance();
  const [selection, setSelection] = useState<string[]>([]);

  const toggleSelect = (id: string) => {
    setSelection(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const handleMerge = () => {
    if (selection.length !== 2) return alert("Selecciona exactamente 2 reembolsos para fusionar");
    mergeRefunds(selection[0], selection[1]);
    setSelection([]);
  };

  return (
    <div className="space-y-8 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800">Reembolsos</h2>
          <p className="text-slate-500 font-medium">Gastos compartidos pendientes de cobro.</p>
        </div>
        <div className="flex gap-2">
          {selection.length === 2 && (
            <button onClick={handleMerge} className="flex items-center gap-2 px-6 py-4 bg-indigo-600 text-white font-bold rounded-[1.5rem] shadow-xl shadow-indigo-100 animate-in zoom-in">
              <Merge size={20} /> Unificar Reembolsos
            </button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {refunds.map(r => (
          <div 
            key={r.id} 
            onClick={() => toggleSelect(r.id)}
            className={`bg-white rounded-[2.5rem] p-8 border-2 transition-all cursor-pointer relative ${selection.includes(r.id) ? 'border-blue-500 ring-4 ring-blue-50' : 'border-slate-100 hover:border-slate-200'} ${r.status === 'closed' ? 'opacity-50' : ''}`}
          >
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${r.status === 'closed' ? 'bg-slate-100 text-slate-400' : 'bg-blue-50 text-blue-600'}`}>
                  <Users size={22} />
                </div>
                <h4 className="font-bold text-slate-800 text-lg">{r.name}</h4>
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); deleteRefund(r.id); }}
                className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
              >
                <Trash2 size={18} />
              </button>
            </div>

            <p className="text-xs text-slate-400 font-medium leading-relaxed mb-6 h-12 line-clamp-2">{r.notes}</p>

            <div className="p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">Por Cobrar</p>
                  <p className="text-3xl font-black text-blue-600">{r.pendingAmount.toLocaleString()}€</p>
                </div>
                <div className="text-right">
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">Total</p>
                  <p className="text-sm font-bold text-slate-600">{r.totalAmount}€</p>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Refunds;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Loader2, Check, X } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { Transaction } from '../types';

const Transactions: React.FC = () => {
  const { transactions, accounts, addTransaction, deleteTransaction, currentDate, refunds, addRefund } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [unidentifiedTx, setUnidentifiedTx] = useState<any[]>([]);

  // AI OCR Handler
  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);
        setUnidentifiedTx(results);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      alert("Error al analizar el ticket");
    } finally {
      setIsScanning(false);
    }
  };

  const confirmTx = (index: number, updated: any) => {
    addTransaction({
      ...updated,
      accountId: accounts[0].id,
      isRefund: false,
      emoji: updated.type === 'income' ? '💰' : '💸'
    });
    setUnidentifiedTx(prev => prev.filter((_, i) => i !== index));
  };

  return (
    <div className="space-y-8 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800">Transacciones</h2>
          <p className="text-slate-500 font-medium">Listado histórico de movimientos.</p>
        </div>
        <div className="flex gap-2">
          <label className="flex items-center gap-2 px-8 py-4 bg-slate-900 text-white font-bold rounded-[1.5rem] shadow-xl shadow-slate-200 cursor-pointer">
            {isScanning ? <Loader2 size={20} className="animate-spin" /> : <Camera size={20} />}
            Escanear Ticket/Extracto
            <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
        </div>
      </div>

      {/* Unidentified Verification Area */}
      {unidentifiedTx.length > 0 && (
        <div className="bg-amber-50 border-2 border-amber-100 rounded-[2rem] p-8 animate-in slide-in-from-top-4 duration-300">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-amber-800">Verificar transacciones detectadas ({unidentifiedTx.length})</h3>
            <button onClick={() => setUnidentifiedTx([])} className="text-amber-800 hover:bg-amber-100 p-2 rounded-full"><X size={20} /></button>
          </div>
          <div className="space-y-4">
            {unidentifiedTx.map((tx, idx) => (
              <div key={idx} className="bg-white p-6 rounded-2xl flex flex-wrap gap-4 items-center justify-between border border-amber-100">
                <div className="flex-1 min-w-[200px]">
                  <input type="text" value={tx.description} onChange={e => {
                    const next = [...unidentifiedTx]; next[idx].description = e.target.value; setUnidentifiedTx(next);
                  }} className="font-bold text-slate-800 bg-transparent border-none p-0 w-full focus:ring-0" />
                  <p className="text-[10px] text-slate-400 font-black uppercase mt-1">{tx.date}</p>
                </div>
                <div className="flex items-center gap-4">
                  <select value={tx.category} onChange={e => {
                    const next = [...unidentifiedTx]; next[idx].category = e.target.value; setUnidentifiedTx(next);
                  }} className="text-xs font-bold bg-slate-50 border-none rounded-xl py-2 px-4 focus:ring-0">
                    <option>Alimentación</option><option>Transporte</option><option>Ocio</option><option>Otros</option>
                  </select>
                  <p className={`font-black text-lg ${tx.type === 'income' ? 'text-emerald-500' : 'text-slate-800'}`}>
                    {tx.amount}€
                  </p>
                  <button onClick={() => confirmTx(idx, tx)} className="p-3 bg-emerald-500 text-white rounded-xl shadow-lg shadow-emerald-100"><Check size={18} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Main List */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row justify-between gap-4">
          <div className="flex items-center gap-3 bg-white px-6 py-3 rounded-2xl border border-slate-200 w-full md:w-96 shadow-inner">
            <Search size={20} className="text-slate-400" />
            <input type="text" placeholder="Buscar movimientos..." className="bg-transparent border-none focus:ring-0 text-sm font-medium w-full" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 text-[10px] uppercase tracking-[0.2em] text-slate-400 font-black border-b border-slate-100">
                <th className="px-8 py-6">Fecha</th>
                <th className="px-8 py-6">Descripción</th>
                <th className="px-8 py-6">Categoría</th>
                <th className="px-8 py-6 text-right">Cantidad</th>
                <th className="px-8 py-6"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactions.map(tx => (
                <tr key={tx.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 text-sm font-bold text-slate-400">{tx.date}</td>
                  <td className="px-8 py-6 font-bold text-slate-800">
                    <div className="flex items-center gap-3">
                      <span className="text-xl">{tx.emoji || (tx.type === 'income' ? '💰' : '💸')}</span>
                      {tx.description}
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <span className="px-3 py-1 bg-slate-100 rounded-full text-[10px] font-black uppercase tracking-widest text-slate-500">{tx.category}</span>
                  </td>
                  <td className={`px-8 py-6 text-right font-black text-lg ${tx.type === 'income' ? 'text-emerald-500' : 'text-slate-800'}`}>
                    {tx.type === 'income' ? '+' : '-'}{tx.amount}€
                  </td>
                  <td className="px-8 py-6 text-right">
                    <button onClick={() => deleteTransaction(tx.id)} className="p-2 text-slate-300 hover:text-rose-500 opacity-0 group-hover:opacity-100"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../App';
import { Edit2, ShoppingBag, ArrowLeft, Receipt, Users } from 'lucide-react';
import { Budget } from '../types';

const BudgetManager: React.FC = () => {
