                    <button onClick={(e) => { e.stopPropagation(); setIsEditing(b.id); setEditValue(b.limit); }} className="p-3 hover:bg-slate-50 rounded-xl text-slate-300 hover:text-blue-500">
                      <Edit2 size={20} />
