        </>
      )}

      {isEditing && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-sm p-10 shadow-2xl">
            <h3 className="text-2xl font-black mb-8">Editar Límite</h3>
            <input type="number" autoFocus value={editValue} onChange={e => setEditValue(Number(e.target.value))} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-8 text-center text-4xl font-black mb-8 focus:border-blue-500 transition-colors" />
            <div className="flex gap-4">
              <button onClick={() => setIsEditing(null)} className="flex-1 py-4 bg-slate-100 font-bold rounded-2xl">Cerrar</button>
              <button onClick={() => { 
                const b = budgets.find(x => x.id === isEditing);
                if (b) updateBudget({ ...b, limit: editValue });
                setIsEditing(null);
              }} className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg">Guardar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

