import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Wallet, 
  PiggyBank, 
  Receipt, 
  BarChart3, 
  MessageSquare,
  ChevronLeft,
  ChevronRight,
  Menu,
  X,
  Plus
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';

interface FinanceContextType extends FinanceState {
  addTransaction: (t: Omit<Transaction, 'id'>) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon'>) => void;
  updateBudget: (b: Budget) => void;
  toggleChallenge: (id: string) => void;
  changeMonth: (offset: number) => void;
  setMonth: (date: string) => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<FinanceState>(() => {
    const saved = localStorage.getItem('finance_data');
    return saved ? JSON.parse(saved) : { ...INITIAL_DATA, challenges: [
      { id: '1', title: 'Ahorro Cafetería', description: 'Gasta menos de 20€ en cafés este mes', completed: false, category: 'Ocio' },
      { id: '2', title: 'Meta Supermercado', description: 'Mantente por debajo de 300€ en alimentación', completed: false, category: 'Alimentación' }
    ]};
  });
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('finance_data', JSON.stringify(state));
  }, [state]);

  const contextValue: FinanceContextType = {
    ...state,
    addTransaction: (t) => {
      const id = Math.random().toString(36).substr(2, 9);
      const newTransaction = { ...t, id };
      setState(prev => {
        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? t.amount : -t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        // Update refund if linked
        // Fix: Explicitly typing the mapped array and casting the status ternary result to the literal union type.
        const refunds: Refund[] = prev.refunds.map(r => {
          if (t.isRefund && t.refundId === r.id && t.type === 'income') {
             const newPending = Math.max(0, r.pendingAmount - t.amount);
             return { ...r, pendingAmount: newPending, status: (newPending <= 0 ? 'closed' : 'open') as 'open' | 'closed' };
          }
          return r;
        });

        const budgets = prev.budgets.map(b => {
          if (t.type === 'expense' && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: b.spent + t.amount };
          }
          return b;
        });

        return {
          ...prev,
          transactions: [newTransaction, ...prev.transactions],
          accounts,
          budgets,
          refunds
        };
      });
    },
    deleteTransaction: (id) => {
      setState(prev => {
        const t = prev.transactions.find(tx => tx.id === id);
        if (!t) return prev;

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? -t.amount : t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        // If it's the main transaction of a refund, delete the refund
        const refunds = prev.refunds.filter(r => r.transactionId !== id);

        // If it's a payment to a refund, restore pending amount
        // Fix: Explicitly typing the mapped array and casting the status literal to the union type.
        const updatedRefunds: Refund[] = refunds.map(r => {
           if (t.isRefund && t.refundId === r.id && t.type === 'income') {
             return { ...r, pendingAmount: r.pendingAmount + t.amount, status: 'open' as 'open' | 'closed' };
           }
           return r;
        });

        return {
          ...prev,
          transactions: prev.transactions.filter(tx => tx.id !== id),
          accounts,
          refunds: updatedRefunds
        };
      });
    },
    addAccount: (a) => {
      const id = 'acc_' + Date.now();
      setState(prev => ({
        ...prev,
        accounts: [...prev.accounts, { ...a, id, currentBalance: a.initialBalance }]
      }));
    },
    updateAccount: (a) => {
      setState(prev => ({
        ...prev,
        accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc)
      }));
    },
    deleteAccount: (id) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) }));
    },
    addSaving: (s) => {
      const id = 'sav_' + Date.now();
      setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id }] }));
    },
    updateSaving: (s) => {
      setState(prev => ({
        ...prev,
        savings: prev.savings.map(sv => sv.id === s.id ? s : sv)
      }));
    },
    deleteSaving: (id) => {
      setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) }));
    },
    addRefund: (r) => {
      const id = 'ref_' + Date.now();
      setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id }] }));
    },
    updateRefund: (r) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf)
      }));
    },
    deleteRefund: (id) => {
      setState(prev => ({ ...prev, refunds: prev.refunds.filter(r => r.id !== id) }));
    },
    mergeRefunds: (id1, id2) => {
      setState(prev => {
        const r1 = prev.refunds.find(r => r.id === id1);
        const r2 = prev.refunds.find(r => r.id === id2);
        if (!r1 || !r2) return prev;

        const merged: Refund = {
          ...r1,
          id: 'ref_merged_' + Date.now(),
          name: `${r1.name} + ${r2.name}`,
          totalAmount: r1.totalAmount + r2.totalAmount,
          paidByMe: r1.paidByMe + r2.paidByMe,
          pendingAmount: r1.pendingAmount + r2.pendingAmount,
          notes: `${r1.notes}\n---\n${r2.notes}`,
          status: 'open'
        };

        return {
          ...prev,
          refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), merged]
        };
      });
    },
    addBudget: (b) => {
      const id = 'budget_' + Date.now();
      setState(prev => ({
        ...prev,
        budgets: [...prev.budgets, { ...b, id, spent: 0, icon: 'ShoppingBag' }]
      }));
    },
    updateBudget: (b) => {
      setState(prev => ({
        ...prev,
        budgets: prev.budgets.map(bg => bg.id === b.id ? b : bg)
      }));
    },
    toggleChallenge: (id) => {
      setState(prev => ({
        ...prev,
        challenges: prev.challenges.map(c => c.id === id ? { ...c, completed: !c.completed } : c)
      }));
    },
    changeMonth: (offset) => {
      setState(prev => {
        const [year, month] = prev.currentDate.split('-').map(Number);
        const date = new Date(year, month - 1 + offset, 1);
        return { ...prev, currentDate: date.toISOString().substring(0, 7) };
      });
    },
    setMonth: (date) => {
      setState(prev => ({ ...prev, currentDate: date }));
    }
  };

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);
  const closeMenu = () => setIsMenuOpen(false);

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 overflow-hidden">
          <Sidebar isOpen={isMenuOpen} onClose={closeMenu} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={toggleMenu} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

