import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    currentDate,
    dashboardLayout,
    updateLayout 
  } = useFinance();

  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');

  // Exact Financial Metrics
  const metrics = useMemo(() => {
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
    const income = monthTx.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0);
    const expense = monthTx.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);

    // User Formula: Balance = income - expense - (-ahorros) => income - expense + ahorros
    // Interpretamos "ahorros" como la suma de dinero movida a huchas este mes.
    // Para simplificar, usamos el total acumulado de ahorros como parte del patrimonio.

    const totalLiquid = accounts.reduce((sum, acc) => sum + acc.currentBalance, 0);
    const totalSavings = savings.reduce((sum, s) => sum + s.currentAmount, 0);
    const netWorth = totalLiquid + totalSavings;

    const monthResult = income - expense; // Flujo de caja
    const previousBalance = netWorth - monthResult;

    return {
      income,
      expense,
      previousBalance,
      monthResult,
      netWorth,
      totalSavings
    };
  }, [transactions, currentDate, accounts, savings]);

  // AI Challenges Auto-Evaluator
  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;

      if (ch.type === 'spending_limit') {
        const spent = monthTx
          .filter(t => t.type === 'expense' && t.category === ch.category)
          .reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavings >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.income >= ch.target;
      }

      return { ...ch, completed: isCompleted };
    });
  }, [challenges, transactions, currentDate, metrics]);

  // Chart Data for Patrimonio (Accounts + Savings)
  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;

    return Array.from({ length: limit }, (_, i) => {
      const valBase = metrics.netWorth;
      // Simulación de histórico basada en el valor actual
      const factor = 1 - ( (limit - 1 - i) * 0.05 ); 
      return {
        name: monthNames[i % 12],
        patrimonio: Math.round(valBase * factor)
      };
    });
  }, [metrics.netWorth, chartFilter]);

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newLayout = [...dashboardLayout];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLayout.length) return;

    [newLayout[index], newLayout[targetIndex]] = [newLayout[targetIndex], newLayout[index]];
    updateLayout(newLayout);
  };

  const renderBlock = (key: string, index: number) => {
    const moveControls = isEditMode && (
      <div className="absolute top-4 right-4 flex gap-1 z-10">
        <button onClick={() => moveBlock(index, 'up')} className="p-1 bg-white border rounded shadow-sm hover:bg-slate-50"><ChevronUp size={14}/></button>
        <button onClick={() => moveBlock(index, 'down')} className="p-1 bg-white border rounded shadow-sm hover:bg-slate-50"><ChevronDown size={14}/></button>
      </div>
    );

    switch (key) {
      case 'balance':
        return (
          <div key={key} className="relative bg-gradient-to-br from-slate-900 to-slate-800 rounded-[2.5rem] p-10 text-white shadow-2xl overflow-hidden">
            {moveControls}
            <div className="relative z-10">
              <div className="flex justify-between items-start">
                <div>
                  <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">Resultado Final (Patrimonio)</p>
                  <h2 className="text-5xl font-black">{metrics.netWorth.toLocaleString()}€</h2>
                </div>
                <div className={`px-4 py-2 rounded-2xl flex items-center gap-2 text-sm font-bold ${metrics.monthResult >= 0 ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'}`}>
                  {metrics.monthResult >= 0 ? <TrendingUp size={18} /> : <TrendingDown size={18} />}
                  {metrics.monthResult >= 0 ? '+' : ''}{metrics.monthResult}€ este mes
                </div>
              </div>

              <div className="grid grid-cols-3 gap-8 mt-12 pt-8 border-t border-white/10">
                <div>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Saldo Pasado</p>
                  <p className="text-lg font-bold">{metrics.previousBalance.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Resultado Mes</p>
                  <p className="text-lg font-bold text-blue-400">{metrics.monthResult.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Total Ahorros</p>
                  <p className="text-lg font-bold text-amber-400">{metrics.totalSavings.toLocaleString()}€</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center">
                <Target size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Retos AI Aura</h3>
            </div>
            <div className="space-y-3">
              {evaluatedChallenges.map(ch => (
                <div key={ch.id} className={`p-4 rounded-2xl border flex items-center gap-3 transition-all ${ch.completed ? 'bg-emerald-50 border-emerald-100' : 'bg-slate-50 border-slate-100'}`}>
                  {ch.completed ? <CheckCircle2 className="text-emerald-500" size={20}/> : <Circle className="text-slate-300" size={20}/>}
                  <div>
                    <p className={`text-sm font-bold ${ch.completed ? 'text-emerald-700' : 'text-slate-700'}`}>{ch.title}</p>
                    <p className="text-[10px] text-slate-500 font-medium">Meta: {ch.target}€</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'savings':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-amber-50 text-amber-600 rounded-xl flex items-center justify-center">
                <PiggyBank size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Ahorro General</h3>
            </div>
            <div className="text-center py-6">
              <p className="text-4xl font-black text-slate-900">{metrics.totalSavings.toLocaleString()}€</p>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-2">Suma de todas tus huchas</p>
            </div>
            <div className="grid grid-cols-2 gap-2 mt-4">
               {savings.slice(0, 4).map(s => (
                 <div key={s.id} className="p-3 bg-slate-50 rounded-xl">
                   <p className="text-[10px] text-slate-400 font-bold truncate">{s.name}</p>
                   <p className="text-xs font-black text-slate-700">{s.currentAmount}€</p>
                 </div>
               ))}
            </div>
          </div>
        );
      case 'chart':
        return (
          <div key={key} className="relative bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm lg:col-span-2">
            {moveControls}
            <div className="flex items-center justify-between mb-8">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <TrendingUp size={20} className="text-emerald-500" /> Evolución del Patrimonio
              </h3>
              <div className="flex gap-1 bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setChartFilter('6m')} className={`px-3 py-1 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '6m' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>6 Meses</button>
                <button onClick={() => setChartFilter('12m')} className={`px-3 py-1 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '12m' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>Todo el Año</button>
              </div>
            </div>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorPat" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} />
                  <YAxis hide />
                  <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} />
                  <Area type="monotone" dataKey="patrimonio" stroke="#3b82f6" strokeWidth={3} fill="url(#colorPat)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        );
      case 'accounts':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center">
                <Wallet size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Cuentas</h3>
            </div>
            <div className="space-y-4">
              {accounts.map(acc => (
                <div key={acc.id} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <div className="flex items-center gap-3">
                    <span className="text-xl">{acc.emoji || '🏦'}</span>
                    <span className="font-bold text-slate-700 text-sm">{acc.name}</span>
                  </div>
                  <span className="font-black text-slate-900">{acc.currentBalance.toLocaleString()}€</span>
                </div>
              ))}
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="space-y-6 pb-20 animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h2 className="text-3xl font-black text-slate-800">Dashboard</h2>
          <p className="text-slate-500 font-medium">Control total de tu patrimonio neto.</p>
        </div>
        <button 
          onClick={() => setIsEditMode(!isEditMode)}
          className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold text-xs transition-all ${isEditMode ? 'bg-blue-600 text-white shadow-lg' : 'bg-white border text-slate-500 hover:bg-slate-50'}`}
        >
          <Settings2 size={16}/> {isEditMode ? 'Guardar Layout' : 'Personalizar Dashboard'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Renderizamos el bloque de balance primero si existe o según layout */}
        <div className="lg:col-span-2 space-y-6">
          {dashboardLayout.map((key, idx) => {
            if (key === 'balance' || key === 'chart') return renderBlock(key, idx);
            return null;
          })}
        </div>

        <div className="space-y-6">
          {dashboardLayout.map((key, idx) => {
            if (key === 'challenges' || key === 'savings' || key === 'accounts') return renderBlock(key, idx);
            return null;
          })}
        </div>
      </div>
    </div>
  );
};

