import { GoogleGenAI, Type, FunctionDeclaration, GenerateContentResponse } from "@google/genai";
import { Transaction, Budget, AIChallenge } from "../types";

export const analyzeReceipt = async (base64Image: string): Promise<Partial<Transaction>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: 'Extrae una lista de transacciones de esta imagen. Para cada una, identifica: descripción, monto, fecha (YYYY-MM-DD), categoría (ej: Comida, Transporte, Ocio) y si es Gasto o Ingreso. Devuelve un JSON puro.' }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            type: { type: Type.STRING, description: 'income or expense' }
          },
          required: ['description', 'amount', 'date', 'category', 'type']
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

export const generateAIChallenges = async (context: string): Promise<AIChallenge[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Basado en este estado financiero: ${context}, genera 3 retos financieros realistas para este mes. Devuelve un JSON puro con este formato: [{ "id": "string", "title": "string", "target": number, "type": "spending_limit" | "savings_goal" | "income_target", "category": "string (opcional)", "completed": false }].`,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            title: { type: Type.STRING },
            target: { type: Type.NUMBER },
            type: { type: Type.STRING },
            category: { type: Type.STRING },
            completed: { type: Type.BOOLEAN }
          },
          required: ['id', 'title', 'target', 'type', 'completed']
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

