import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2,
  ChevronRight,
  Sparkles,
  Loader2,
  ShoppingBag
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { generateAIChallenges } from '../services/geminiService';

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    budgets,
    currentDate,
    dashboardLayout,
    updateLayout,
    setChallenges
  } = useFinance();

  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');
  const [showBreakdown, setShowBreakdown] = useState(false);
  const [isGeneratingChallenges, setIsGeneratingChallenges] = useState(false);

  // Exact Financial Metrics
  const metrics = useMemo(() => {
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));

    // Calculate income and regular expenses
    const income = monthTx.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0);
    const expense = monthTx.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);

    // Track monthly savings (movements to savings accounts/categories)
    // We assume any transaction tagged as 'Ahorro' contributes to this month's savings bucket
    const monthSavings = monthTx.filter(t => t.category === 'Ahorro' || t.category === 'Ahorros').reduce((sum, t) => sum + t.amount, 0);

    const totalLiquid = accounts.reduce((sum, acc) => sum + acc.currentBalance, 0);
    const totalSavings = savings.reduce((sum, s) => sum + s.currentAmount, 0);
    const netWorth = totalLiquid + totalSavings;

    // Formula: income - expense + monthSavings
    const monthResult = income - expense; 
    const previousBalance = netWorth - (monthResult + monthSavings);

    return {
      income,
      expense,
      monthSavings,
      previousBalance,
      monthResult: monthResult + monthSavings,
      netWorth,
      totalSavings
    };
  }, [transactions, currentDate, accounts, savings]);

  // AI Challenges Auto-Evaluator
  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;

      if (ch.type === 'spending_limit') {
        const spent = monthTx
          .filter(t => t.type === 'expense' && t.category === ch.category)
          .reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavings >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.income >= ch.target;
      }

      return { ...ch, completed: isCompleted || ch.completed };
    });
  }, [challenges, transactions, currentDate, metrics]);

  // Chart Data
  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;
    return Array.from({ length: limit }, (_, i) => {
      const valBase = metrics.netWorth;
      const factor = 1 - ( (limit - 1 - i) * 0.05 ); 
      return {
        name: monthNames[i % 12],
        patrimonio: Math.round(valBase * factor)
      };
    });
  }, [metrics.netWorth, chartFilter]);

  const handleGenerateChallenges = async () => {
    setIsGeneratingChallenges(true);
    try {
      const context = `Presupuestos: ${budgets.map(b => b.category + ": " + b.spent + "/" + b.limit).join(", ")}. Patrimonio: ${metrics.netWorth}€. Ahorros: ${metrics.totalSavings}€.`;
      const newChallenges = await generateAIChallenges(context);
      setChallenges(newChallenges);
    } catch (error) {
      console.error("Error generating challenges:", error);
    } finally {
      setIsGeneratingChallenges(false);
    }
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newLayout = [...dashboardLayout];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLayout.length) return;

    // Swap elements
    [newLayout[index], newLayout[targetIndex]] = [newLayout[targetIndex], newLayout[index]];
    updateLayout(newLayout);
  };

  const renderBlock = (key: string, index: number) => {
    const moveControls = isEditMode && (
      <div className="absolute top-4 right-4 flex gap-1 z-20">
        <button 
          onClick={(e) => { e.stopPropagation(); moveBlock(index, 'up'); }} 
          className="p-2 bg-white border border-slate-200 rounded-xl shadow-sm hover:bg-slate-50 transition-all active:scale-95"
          disabled={index === 0}
        >
          <ChevronUp size={16} className="text-slate-600" />
        </button>
        <button 
          onClick={(e) => { e.stopPropagation(); moveBlock(index, 'down'); }} 
          className="p-2 bg-white border border-slate-200 rounded-xl shadow-sm hover:bg-slate-50 transition-all active:scale-95"
          disabled={index === dashboardLayout.length - 1}
        >
          <ChevronDown size={16} className="text-slate-600" />
        </button>
      </div>
    );

    switch (key) {
      case 'balance':
        return (
          <div key={key} className="relative bg-gradient-to-br from-blue-700 to-blue-600 rounded-[2.5rem] p-10 text-white shadow-2xl shadow-blue-200/50 overflow-hidden">
            {moveControls}
            <div className="relative z-10">
              <div className="flex justify-between items-start">
                <div>
                  <p className="text-blue-100 text-xs font-bold uppercase tracking-widest mb-1">Patrimonio Neto Total</p>
                  <h2 className="text-5xl font-black">{metrics.netWorth.toLocaleString()}€</h2>
                </div>
                <button 
                  onClick={() => setShowBreakdown(!showBreakdown)}
                  className={`px-4 py-2 rounded-2xl flex items-center gap-2 text-sm font-bold transition-all shadow-lg ${metrics.monthResult >= 0 ? 'bg-white/20 text-white hover:bg-white/30' : 'bg-rose-500/20 text-rose-100 hover:bg-rose-500/30'}`}
                >
                  {metrics.monthResult >= 0 ? <TrendingUp size={18} /> : <TrendingDown size={18} />}
                  {metrics.monthResult >= 0 ? '+' : ''}{metrics.monthResult.toLocaleString()}€ este mes
                  <ChevronRight size={14} className={`transition-transform duration-300 ${showBreakdown ? 'rotate-90' : ''}`} />
                </button>
              </div>

              {showBreakdown && (
                <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-4 animate-in slide-in-from-top-4 duration-300">
                  <div className="p-5 bg-emerald-500/20 backdrop-blur-md rounded-3xl border border-white/10">
                    <p className="text-[10px] font-bold uppercase text-emerald-100 mb-1">Ingresos</p>
                    <p className="text-2xl font-black">{metrics.income.toLocaleString()}€</p>
                  </div>
                  <div className="p-5 bg-rose-500/20 backdrop-blur-md rounded-3xl border border-white/10">
                    <p className="text-[10px] font-bold uppercase text-rose-100 mb-1">Gastos</p>
                    <p className="text-2xl font-black">{metrics.expense.toLocaleString()}€</p>
                  </div>
                  <div className="p-5 bg-amber-400/30 backdrop-blur-md rounded-3xl border border-white/10">
                    <p className="text-[10px] font-bold uppercase text-amber-100 mb-1">Ahorrado</p>
                    <p className="text-2xl font-black">{metrics.monthSavings.toLocaleString()}€</p>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-3 gap-8 mt-10 pt-8 border-t border-white/10">
                <div>
                  <p className="text-[10px] text-blue-200 font-bold uppercase mb-1">Saldo Pasado</p>
                  <p className="text-lg font-bold">{metrics.previousBalance.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[10px] text-blue-200 font-bold uppercase mb-1">Resultado Mes</p>
                  <p className="text-lg font-bold">{(metrics.monthResult).toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[10px] text-blue-200 font-bold uppercase mb-1">Total Huchas</p>
                  <p className="text-lg font-bold">{metrics.totalSavings.toLocaleString()}€</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center">
                  <Target size={20} />
                </div>
                <h3 className="font-bold text-slate-800">Retos AI Aura</h3>
              </div>
              <button 
                onClick={handleGenerateChallenges}
                disabled={isGeneratingChallenges}
                className="p-2.5 bg-blue-600 text-white rounded-xl transition-all disabled:opacity-50 hover:bg-blue-700 shadow-md shadow-blue-100"
                title="Generar nuevos retos"
              >
                {isGeneratingChallenges ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              </button>
            </div>
            <div className="space-y-3">
              {evaluatedChallenges.map(ch => (
                <div key={ch.id} className={`p-4 rounded-2xl border flex items-center gap-3 transition-all ${ch.completed ? 'bg-emerald-50 border-emerald-100' : 'bg-slate-50 border-slate-100'}`}>
                  {ch.completed ? <CheckCircle2 className="text-emerald-500" size={20}/> : <Circle className="text-slate-300" size={20}/>}
                  <div className="flex-1">
                    <p className={`text-sm font-bold ${ch.completed ? 'text-emerald-700' : 'text-slate-700'}`}>{ch.title}</p>
                    <p className="text-[10px] text-slate-500 font-medium">Objetivo: {ch.target}€</p>
                  </div>
                </div>
              ))}
              {evaluatedChallenges.length === 0 && (
                <p className="text-slate-400 text-xs text-center py-4 italic">No hay retos. Pulsa en el destello para que Aura te proponga algunos.</p>
              )}
            </div>
          </div>
        );
      case 'savings':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-amber-50 text-amber-600 rounded-xl flex items-center justify-center">
                <PiggyBank size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Ahorro General</h3>
            </div>
            <div className="text-center py-6">
              <p className="text-4xl font-black text-slate-900">{metrics.totalSavings.toLocaleString()}€</p>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-2">Capital en huchas</p>
            </div>
            <div className="grid grid-cols-2 gap-2 mt-4">
               {savings.slice(0, 4).map(s => (
                 <div key={s.id} className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                   <p className="text-[10px] text-slate-400 font-bold truncate uppercase">{s.name}</p>
                   <p className="text-xs font-black text-slate-700">{s.currentAmount}€</p>
                 </div>
               ))}
            </div>
          </div>
        );
      case 'chart':
        return (
          <div key={key} className="relative bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm">
            {moveControls}
            <div className="flex items-center justify-between mb-8">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <TrendingUp size={20} className="text-emerald-500" /> Evolución del Patrimonio
              </h3>
              <div className="flex gap-1 bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setChartFilter('6m')} className={`px-4 py-1.5 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '6m' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>6 M</button>
                <button onClick={() => setChartFilter('12m')} className={`px-4 py-1.5 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '12m' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>12 M</button>
              </div>
            </div>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorPat" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} />
                  <YAxis hide />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                    formatter={(value: any) => [`${value}€`, 'Patrimonio']}
                  />
                  <Area type="monotone" dataKey="patrimonio" stroke="#3b82f6" strokeWidth={3} fill="url(#colorPat)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        );
      case 'accounts':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center">
                <Wallet size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Cuentas Bancarias</h3>
            </div>
            <div className="space-y-4">
              {accounts.map(acc => (
                <div key={acc.id} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <div className="flex items-center gap-3">
                    <span className="text-xl">{acc.emoji || '🏦'}</span>
                    <span className="font-bold text-slate-700 text-sm">{acc.name}</span>
                  </div>
                  <span className="font-black text-slate-900">{acc.currentBalance.toLocaleString()}€</span>
                </div>
              ))}
            </div>
          </div>
        );
      case 'budget':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-purple-50 text-purple-600 rounded-xl flex items-center justify-center">
                <ShoppingBag size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Presupuestos</h3>
            </div>
            <div className="space-y-5">
              {budgets.slice(0, 3).map(b => {
                const progress = Math.min((b.spent / b.limit) * 100, 100);
                return (
                  <div key={b.id}>
                    <div className="flex justify-between text-[10px] font-bold text-slate-500 mb-1.5 uppercase tracking-wider">
                      <span>{b.category}</span>
                      <span className={progress > 90 ? 'text-rose-500' : 'text-blue-600'}>{Math.round(progress)}%</span>
                    </div>
                    <div className="w-full h-2 bg-slate-100 rounded-full overflow-hidden">
                      <div 
                        className={`h-full transition-all duration-700 ${progress > 90 ? 'bg-rose-500' : progress > 70 ? 'bg-amber-400' : 'bg-blue-600'}`} 
                        style={{ width: `${progress}%` }}
                      ></div>
                    </div>
                  </div>
                );
              })}
              {budgets.length === 0 && <p className="text-xs text-slate-400 italic text-center py-4">Sin límites de gasto definidos.</p>}
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="space-y-6 pb-20 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Dashboard</h2>
          <p className="text-slate-500 font-medium">Resumen general de tu salud financiera.</p>
        </div>
        <button 
          onClick={() => setIsEditMode(!isEditMode)}
          className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-sm transition-all shadow-sm ${isEditMode ? 'bg-blue-600 text-white shadow-xl shadow-blue-200' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'}`}
        >
          <Settings2 size={18}/> {isEditMode ? 'Guardar Cambios' : 'Personalizar Diseño'}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 auto-rows-min">
        {dashboardLayout.map((key, idx) => {
          // Some blocks might want to be double-width on large screens
          const isFullWidth = key === 'balance' || key === 'chart';
          return (
            <div key={key} className={`${isFullWidth ? 'lg:col-span-2' : 'lg:col-span-1'} transition-all duration-300`}>
              {renderBlock(key, idx)}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, Trash2, Edit2, ArrowRightLeft, CreditCard, Banknote, Landmark, X } from 'lucide-react';
import { Account } from '../types';

const Accounts: React.FC = () => {
  const { accounts, addAccount, updateAccount, deleteAccount, addTransaction } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [editingAccount, setEditingAccount] = useState<Account | null>(null);
  const [isTransferring, setIsTransferring] = useState(false);

  // New/Edit account form state
  const [name, setName] = useState('');
  const [type, setType] = useState<Account['type']>('Bank');
  const [balanceInput, setBalanceInput] = useState<number | ''>('');
  const [color, setColor] = useState('#3b82f6');
  const [emoji, setEmoji] = useState('🏦');

  // Transfer form
  const [fromId, setFromId] = useState('');
  const [toId, setToId] = useState('');
  const [transferAmount, setTransferAmount] = useState<number | ''>('');

  const resetForm = () => {
    setName('');
    setType('Bank');
    setBalanceInput('');
    setColor('#3b82f6');
    setEmoji('🏦');
  };

  const handleOpenAdd = () => {
    resetForm();
    setIsAdding(true);
  };

  const handleOpenEdit = (acc: Account) => {
    setName(acc.name);
    setType(acc.type);
    setBalanceInput(acc.currentBalance);
    setColor(acc.color);
    setEmoji(acc.emoji || '🏦');
    setEditingAccount(acc);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalBalance = balanceInput === '' ? 0 : balanceInput;
    if (editingAccount) {
      updateAccount({ 
        ...editingAccount, 
        name, 
        type, 
        currentBalance: finalBalance, 
        color, 
        emoji 
      });
      setEditingAccount(null);
    } else {
      addAccount({ 
        name, 
        type, 
        initialBalance: finalBalance, 
        color, 
        emoji 
      });
      setIsAdding(false);
    }
    resetForm();
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    const amountValue = transferAmount === '' ? 0 : transferAmount;
    if (!fromId || !toId) return alert("Selecciona ambas cuentas");
    if (fromId === toId) return alert("Las cuentas deben ser diferentes");
    if (amountValue <= 0) return alert("Introduce una cantidad válida");

    const date = new Date().toISOString().split('T')[0];
    addTransaction({
      date,
      amount: amountValue,
      description: `Transferencia a ${accounts.find(a => a.id === toId)?.name}`,
      category: 'Transferencia',
      type: 'expense',
      accountId: fromId,
      isRefund: false
    });
    addTransaction({
      date,
      amount: amountValue,
      description: `Transferencia desde ${accounts.find(a => a.id === fromId)?.name}`,
      category: 'Transferencia',
      type: 'income',
      accountId: toId,
      isRefund: false
    });

    setIsTransferring(false);
    setTransferAmount('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Cuentas y Efectivo</h2>
          <p className="text-slate-500 font-medium">Gestiona tu liquidez y realiza movimientos entre cuentas.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsTransferring(true)}
            className="flex items-center gap-2 px-6 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all shadow-sm active:scale-95"
          >
            <ArrowRightLeft size={18} />
            Transferir
          </button>
          <button 
            onClick={handleOpenAdd}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
          >
            <Plus size={18} />
            Nueva Cuenta
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {accounts.map(acc => (
          <div key={acc.id} className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm relative group overflow-hidden hover:shadow-md transition-all">
            <div className="flex justify-between items-start mb-6">
              <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner" style={{ backgroundColor: `${acc.color}20` }}>
                {acc.emoji || (acc.type === 'Bank' ? '🏦' : acc.type === 'Cash' ? '💵' : '💳')}
              </div>
              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => handleOpenEdit(acc)}
                  className="p-2.5 hover:bg-blue-50 rounded-xl text-blue-500 transition-colors"
                >
                  <Edit2 size={18} />
                </button>
                <button 
                  onClick={() => { if(confirm('¿Seguro que quieres eliminar esta cuenta?')) deleteAccount(acc.id); }}
                  className="p-2.5 hover:bg-rose-50 rounded-xl text-rose-400 transition-colors"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>

            <h4 className="text-xl font-bold text-slate-800">{acc.name}</h4>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mb-4">{acc.type}</p>

            <div className="flex items-baseline gap-2">
              <span className="text-3xl font-black text-slate-900">{acc.currentBalance.toLocaleString('es-ES')}€</span>
              <span className="text-[10px] text-slate-400 font-bold uppercase">Saldo disponible</span>
            </div>
          </div>
        ))}
      </div>

      {/* Add/Edit Modal */}
      {(isAdding || editingAccount) && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800">{editingAccount ? 'Editar Cuenta' : 'Nueva Cuenta'}</h3>
              <button onClick={() => { setIsAdding(false); setEditingAccount(null); }} className="p-2 hover:bg-slate-100 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Nombre de la cuenta</label>
                <input 
                  type="text" 
                  value={name} 
                  onChange={e => setName(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium" 
                  placeholder="Ej: Nómina Santander" 
                  required 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Tipo</label>
                  <select 
                    value={type} 
                    onChange={e => setType(e.target.value as any)}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-medium outline-none"
                  >
                    <option value="Bank">Banco</option>
                    <option value="Cash">Efectivo</option>
                    <option value="Card">Tarjeta</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Saldo Actual</label>
                  <input 
                    type="number" 
                    value={balanceInput} 
                    onChange={e => setBalanceInput(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" 
                    placeholder="0"
                    required 
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Emoji</label>
                  <input 
                    type="text" 
                    value={emoji} 
                    onChange={e => setEmoji(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-center text-xl outline-none" 
                    placeholder="🏦"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Color</label>
                  <input 
                    type="color" 
                    value={color} 
                    onChange={e => setColor(e.target.value)}
                    className="w-full h-[60px] bg-slate-50 border border-slate-100 rounded-2xl p-2 outline-none cursor-pointer" 
                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={() => { setIsAdding(false); setEditingAccount(null); }} 
                  className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  {editingAccount ? 'Guardar Cambios' : 'Crear Cuenta'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Transfer Modal */}
      {isTransferring && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800">Transferencia</h3>
              <button onClick={() => setIsTransferring(false)} className="p-2 hover:bg-slate-100 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <form onSubmit={handleTransfer} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Desde</label>
                <select 
                  value={fromId} 
                  onChange={e => setFromId(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-medium outline-none"
                  required
                >
                  <option value="">Selecciona origen</option>
                  {accounts.map(a => <option key={a.id} value={a.id}>{a.name} ({a.currentBalance}€)</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Hacia</label>
                <select 
                  value={toId} 
                  onChange={e => setToId(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-medium outline-none"
                  required
                >
                  <option value="">Selecciona destino</option>
                  {accounts.map(a => <option key={a.id} value={a.id}>{a.name} ({a.currentBalance}€)</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Cantidad</label>
                <input 
                  type="number" 
                  value={transferAmount} 
                  onChange={e => setTransferAmount(e.target.value === '' ? '' : Number(e.target.value))}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-center text-3xl font-black outline-none" 
                  placeholder="0"
                  required 
                />
              </div>
              <div className="flex gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={() => setIsTransferring(false)} 
                  className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all"
                >
                  Confirmar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Accounts;

import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, PiggyBank, TrendingUp, ArrowRightLeft, Percent, X, ArrowUpCircle, ArrowDownCircle } from 'lucide-react';
import { Saving } from '../types';

const Savings: React.FC = () => {
  const { savings, addSaving, updateSaving, deleteSaving } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [adjustingSaving, setAdjustingSaving] = useState<Saving | null>(null);
  const [adjustmentMode, setAdjustmentMode] = useState<'amount' | 'percent'>('amount');

  // New Saving Form State
  const [name, setName] = useState('');
  const [amountInput, setAmountInput] = useState<number | ''>('');
  const [targetInput, setTargetInput] = useState<number | ''>('');
  const [isInvestment, setIsInvestment] = useState(false);
  const [growthRateInput, setGrowthRateInput] = useState<number | ''>('');

  // Adjustment Modal State
  const [adjValue, setAdjValue] = useState<number | ''>('');

  const handleCreateSaving = (e: React.FormEvent) => {
    e.preventDefault();
    addSaving({
      name,
      currentAmount: amountInput === '' ? 0 : amountInput,
      targetAmount: targetInput === '' ? undefined : targetInput,
      isInvestment,
      growthRate: isInvestment && growthRateInput !== '' ? growthRateInput : undefined,
      color: '#f59e0b',
      emoji: isInvestment ? '📈' : '💰'
    });
    setIsAdding(false);
    resetForm();
  };

  const resetForm = () => {
    setName('');
    setAmountInput('');
    setTargetInput('');
    setIsInvestment(false);
    setGrowthRateInput('');
  };

  const applyAdjustment = () => {
    if (!adjustingSaving || adjValue === '') return;

    let newAmount = adjustingSaving.currentAmount;
    if (adjustmentMode === 'amount') {
      newAmount += adjValue;
    } else {
      newAmount = newAmount * (1 + adjValue / 100);
    }

    updateSaving({ ...adjustingSaving, currentAmount: Math.max(0, newAmount) });
    setAdjustingSaving(null);
    setAdjValue('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Huchas e Inversiones</h2>
          <p className="text-slate-500 font-medium">Gestiona tus objetivos de ahorro y el rendimiento de tus activos.</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
        >
          <Plus size={18} />
          Crear Hucha
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {savings.map(s => {
          const progress = s.targetAmount ? Math.min((s.currentAmount / s.targetAmount) * 100, 100) : null;
          return (
            <div key={s.id} className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm relative group hover:shadow-md transition-all">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner ${s.isInvestment ? 'bg-indigo-50 text-indigo-600' : 'bg-amber-50 text-amber-600'}`}>
                    {s.emoji || (s.isInvestment ? '📈' : '💰')}
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-800">{s.name}</h4>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                      {s.isInvestment ? 'Inversión' : 'Ahorro Manual'}
                    </p>
                  </div>
                </div>
                <button 
                  onClick={() => { if(confirm('¿Eliminar hucha?')) deleteSaving(s.id); }}
                  className="p-2 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500 transition-all"
                >
                  <X size={18} />
                </button>
              </div>

              <div className="mb-6">
                <div className="flex items-baseline gap-2">
                  <span className="text-4xl font-black text-slate-900">{s.currentAmount.toLocaleString('es-ES', { maximumFractionDigits: 2 })}€</span>
                  {s.growthRate && (
                    <span className="text-xs font-bold text-emerald-500 flex items-center gap-0.5">
                      <TrendingUp size={12} /> {s.growthRate}%
                    </span>
                  )}
                </div>

                {progress !== null && (
                  <div className="mt-6">
                    <div className="flex justify-between text-[10px] font-black uppercase tracking-wider mb-2">
                      <span className="text-blue-600">{progress.toFixed(1)}% Completado</span>
                      <span className="text-slate-400">Meta: {s.targetAmount}€</span>
                    </div>
                    <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-blue-600 rounded-full transition-all duration-1000 ease-out" 
                        style={{ width: `${progress}%` }}
                      ></div>
                    </div>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={() => { setAdjustingSaving(s); setAdjustmentMode('amount'); }}
                  className="flex items-center justify-center gap-2 py-3 bg-slate-50 text-slate-700 rounded-2xl font-bold text-xs hover:bg-slate-100 transition-all border border-slate-100"
                >
                  <ArrowRightLeft size={16} className="text-blue-500" /> Ajustar Saldo
                </button>
                <button 
                  onClick={() => { setAdjustingSaving(s); setAdjustmentMode('percent'); }}
