    if (!adjustingSaving || adjValue === '') return;

    let newAmount = adjustingSaving.currentAmount;
    if (adjustmentMode === 'amount') {
      newAmount += adjValue;
    } else {
      newAmount = newAmount * (1 + adjValue / 100);
