              <button onClick={() => { setAdjustingSaving(null); setAdjValue(''); }} className="p-2 hover:bg-slate-100 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <div className="space-y-6">
              <div className="text-center">
                <p className="text-xs font-bold text-slate-400 uppercase mb-2">Hucha: {adjustingSaving.name}</p>
                <div className="flex items-center justify-center gap-3">
                  <input 
                    type="number" 
                    value={adjValue} 
                    onChange={e => setAdjValue(e.target.value === '' ? '' : Number(e.target.value))}
                    autoFocus
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-6 text-center text-4xl font-black outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                    placeholder="0"
                  />
                  <span className="text-2xl font-black text-slate-400">
                    {adjustmentMode === 'amount' ? '€' : '%'}
                  </span>
                </div>
                <p className="mt-4 text-xs text-slate-400 font-medium">
                  {adjustmentMode === 'amount' 
                    ? 'Escribe un número positivo para sumar o negativo para restar.' 
                    : 'Aplica un porcentaje directamente al saldo total.'}
                </p>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => { setAdjustingSaving(null); setAdjValue(''); }}
                  className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200"
