              </div>
            </div>
          </div>
        </div>
      )}

      {/* Creation/Edit Modal */}
      {(isAdding || editingSaving) && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800">{editingSaving ? 'Editar Hucha' : 'Nueva Meta'}</h3>
