                <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isInvestment ? 'bg-indigo-600 text-white' : 'bg-white text-slate-400 shadow-sm'}`}>
                  {isInvestment ? <TrendingUp size={20} /> : <PiggyBank size={20} />}
