          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Huchas e Inversiones</h2>
          <p className="text-slate-500 font-medium">Gestiona tus objetivos de ahorro y el rendimiento de tus activos.</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
        >
          <Plus size={18} />
          Crear Hucha
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {savings.map(s => {
          const progress = s.targetAmount ? Math.min((s.currentAmount / s.targetAmount) * 100, 100) : null;
          return (
            <div key={s.id} className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm relative group hover:shadow-md transition-all">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner ${s.isInvestment ? 'bg-indigo-50 text-indigo-600' : 'bg-amber-50 text-amber-600'}`}>
                    {s.emoji || (s.isInvestment ? '📈' : '💰')}
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-800">{s.name}</h4>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                      {s.isInvestment ? 'Inversión' : 'Ahorro Manual'}
                    </p>
                  </div>
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                  <button 
                    onClick={() => handleOpenEdit(s)}
                    className="p-2 text-slate-300 hover:text-blue-500 transition-all"
                  >
                    <Edit2 size={18} />
                  </button>
                  <button 
                    onClick={() => { if(confirm('¿Eliminar hucha?')) deleteSaving(s.id); }}
                    className="p-2 text-slate-300 hover:text-rose-500 transition-all"
                  >
                    <X size={18} />
                  </button>
                </div>
              </div>

              <div className="mb-6">
                <div className="flex items-baseline gap-2">
                  <span className="text-4xl font-black text-slate-900">{s.currentAmount.toLocaleString('es-ES', { maximumFractionDigits: 2 })}€</span>
                  {s.growthRate && (
                    <span className="text-xs font-bold text-emerald-500 flex items-center gap-0.5">
                      <TrendingUp size={12} /> {s.growthRate}%
                    </span>
                  )}
                </div>

                {progress !== null && (
                  <div className="mt-6">
                    <div className="flex justify-between text-[10px] font-black uppercase tracking-wider mb-2">
                      <span className="text-blue-600">{progress.toFixed(1)}% Completado</span>
                      <span className="text-slate-400">Meta: {s.targetAmount}€</span>
                    </div>
                    <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-blue-600 rounded-full transition-all duration-1000 ease-out" 
                        style={{ width: `${progress}%` }}
                      ></div>
                    </div>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={() => { setAdjustingSaving(s); setAdjustmentMode('amount'); }}
                  className="flex items-center justify-center gap-2 py-3 bg-slate-50 text-slate-700 rounded-2xl font-bold text-xs hover:bg-slate-100 transition-all border border-slate-100"
                >
                  <ArrowRightLeft size={16} className="text-blue-500" /> Ajustar Saldo
                </button>
                <button 
                  onClick={() => { setAdjustingSaving(s); setAdjustmentMode('percent'); }}
                  className="flex items-center justify-center gap-2 py-3 bg-slate-50 text-slate-700 rounded-2xl font-bold text-xs hover:bg-slate-100 transition-all border border-slate-100"
                >
                  <Percent size={16} className="text-emerald-500" /> Aplicar %
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Adjustment Modal */}
      {adjustingSaving && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-sm p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-slate-800">
                {adjustmentMode === 'amount' ? 'Ajustar Cantidad' : 'Ajuste Porcentual'}
              </h3>
              <button onClick={() => { setAdjustingSaving(null); setAdjValue(''); }} className="p-2 hover:bg-slate-100 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <div className="space-y-6">
              <div className="text-center">
                <p className="text-xs font-bold text-slate-400 uppercase mb-2">Hucha: {adjustingSaving.name}</p>
                <div className="flex items-center justify-center gap-3">
                  <input 
                    type="number" 
                    value={adjValue} 
                    onChange={e => setAdjValue(e.target.value === '' ? '' : Number(e.target.value))}
                    autoFocus
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-6 text-center text-4xl font-black outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                    placeholder="0"
                  />
                  <span className="text-2xl font-black text-slate-400">
                    {adjustmentMode === 'amount' ? '€' : '%'}
                  </span>
                </div>
                <p className="mt-4 text-xs text-slate-400 font-medium">
                  {adjustmentMode === 'amount' 
                    ? 'Escribe un número positivo para sumar o negativo para restar.' 
                    : 'Aplica un porcentaje directamente al saldo total.'}
                </p>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => { setAdjustingSaving(null); setAdjValue(''); }}
                  className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200"
                >
                  Cancelar
                </button>
                <button 
                  onClick={applyAdjustment}
                  disabled={adjValue === ''}
                  className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95 disabled:opacity-50"
                >
                  Confirmar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Creation/Edit Modal */}
      {(isAdding || editingSaving) && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800">{editingSaving ? 'Editar Hucha' : 'Nueva Meta'}</h3>
              <button onClick={resetForm} className="p-2 hover:bg-slate-100 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Nombre del objetivo</label>
                <input 
                  type="text" 
                  value={name} 
                  onChange={e => setName(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium" 
                  placeholder="Ej: Fondo para el Coche" 
                  required 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Monto Actual</label>
                  <input 
                    type="number" 
                    value={amountInput} 
                    onChange={e => setAmountInput(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" 
                    placeholder="0"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Meta Final</label>
                  <input 
                    type="number" 
                    value={targetInput} 
                    onChange={e => setTargetInput(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" 
                    placeholder="Opcional"
                  />
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Emoticono</label>
                <input 
                  type="text" 
                  value={emoji} 
                  onChange={e => setEmoji(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-center text-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all" 
                  placeholder="💰"
                />
              </div>

              <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100 cursor-pointer hover:bg-slate-100 transition-colors" onClick={() => setIsInvestment(!isInvestment)}>
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isInvestment ? 'bg-indigo-600 text-white' : 'bg-white text-slate-400 shadow-sm'}`}>
                  {isInvestment ? <TrendingUp size={20} /> : <PiggyBank size={20} />}
                </div>
                <div className="flex-1">
                  <p className="text-sm font-bold text-slate-700">¿Es una inversión?</p>
                  <p className="text-[10px] text-slate-400 font-medium">Habilita seguimiento de rendimiento.</p>
                </div>
                <div className={`w-6 h-6 rounded-full border-2 transition-all flex items-center justify-center ${isInvestment ? 'border-indigo-600 bg-indigo-600' : 'border-slate-300'}`}>
                  {isInvestment && <div className="w-2 h-2 bg-white rounded-full"></div>}
                </div>
              </div>

              {isInvestment && (
                <div className="animate-in slide-in-from-top-2 duration-200">
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Rendimiento Estimado Anual (%)</label>
                  <input 
                    type="number" 
                    value={growthRateInput} 
                    onChange={e => setGrowthRateInput(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" 
                    placeholder="Opcional"
                  />
                </div>
              )}

              <div className="flex gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={resetForm} 
                  className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  {editingSaving ? 'Guardar Cambios' : 'Crear Hucha'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Savings;

export type TransactionType = 'income' | 'expense';

export interface Account {
  id: string;
  name: string;
  type: 'Bank' | 'Cash' | 'Card';
  initialBalance: number;
  currentBalance: number;
  color: string;
  emoji?: string;
}

export interface Saving {
  id: string;
  name: string;
  currentAmount: number;
  targetAmount?: number;
  isInvestment: boolean;
  growthRate?: number;
  color: string;
  emoji?: string;
}

export interface Refund {
  id: string;
  name: string;
  totalAmount: number;
  paidByMe: number;
  pendingAmount: number;
  status: 'open' | 'closed';
  notes: string;
  date: string;
  originTransactionId?: string; // El gasto que originó el reembolso
}

export interface Transaction {
  id: string;
  date: string;
  amount: number;
  description: string;
  category: string;
  type: TransactionType;
  accountId: string;
  isRefund: boolean;
  refundId?: string; // Para ingresos vinculados a un reembolso o gastos que son reembolsos
  image?: string;
  emoji?: string;
}

export interface Budget {
  id: string;
  category: string;
  limit: number;
  icon: string;
  spent: number;
}

export interface AIChallenge {
  id: string;
  title: string;
  target: number;
  type: 'spending_limit' | 'savings_goal' | 'income_target';
  category?: string;
  completed: boolean;
}

export interface FinanceState {
  accounts: Account[];
  savings: Saving[];
  refunds: Refund[];
  transactions: Transaction[];
  budgets: Budget[];
  challenges: AIChallenge[];
  currentDate: string;
  dashboardLayout: string[]; 
}

import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Wallet, 
  PiggyBank, 
  Receipt, 
  BarChart3, 
  MessageSquare,
  ChevronLeft,
  ChevronRight,
  Menu,
  X,
  Plus
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';

interface FinanceContextType extends FinanceState {
  addTransaction: (t: Omit<Transaction, 'id'>) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon'>) => void;
  updateBudget: (b: Budget) => void;
  changeMonth: (offset: number) => void;
  setMonth: (date: string) => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<FinanceState>(() => {
    const saved = localStorage.getItem('finance_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('finance_data', JSON.stringify(state));
  }, [state]);

  const contextValue: FinanceContextType = {
    ...state,
    addTransaction: (t) => {
      const id = Math.random().toString(36).substr(2, 9);
      const newTransaction = { ...t, id };

      setState(prev => {
        let updatedRefunds = [...prev.refunds];

        // Si el gasto genera un reembolso
        if (t.type === 'expense' && t.isRefund) {
          const refundId = 'ref_' + Date.now();
          updatedRefunds.push({
            id: refundId,
            name: t.description,
            totalAmount: t.amount,
            paidByMe: t.amount, // El usuario pagó todo inicialmente
            pendingAmount: t.amount, // Alguien le debe el total
            status: 'open',
            notes: 'Creado desde gasto: ' + t.description,
            date: t.date,
            originTransactionId: id
          });
          newTransaction.refundId = refundId;
        }

        // Si el ingreso está vinculado a cobrar un reembolso existente
        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = Math.max(0, r.pendingAmount - t.amount);
              return { ...r, pendingAmount: newPending, status: newPending <= 0 ? 'closed' : 'open' };
            }
            return r;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? t.amount : -t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        const budgets = prev.budgets.map(b => {
          if (t.type === 'expense' && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: b.spent + t.amount };
          }
          return b;
        });

        return {
          ...prev,
          transactions: [newTransaction, ...prev.transactions],
          accounts,
          budgets,
          refunds: updatedRefunds
        };
      });
    },
    deleteTransaction: (id) => {
      setState(prev => {
        const t = prev.transactions.find(tx => tx.id === id);
        if (!t) return prev;

        let updatedRefunds = [...prev.refunds];

        // 1. Si era el gasto que originó un reembolso, eliminamos el reembolso (eliminación en cascada)
        updatedRefunds = updatedRefunds.filter(r => r.originTransactionId !== id);

        // 2. Si era un ingreso que pagaba un reembolso, devolvemos la deuda al reembolso
        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = r.pendingAmount + t.amount;
              return { ...r, pendingAmount: newPending, status: 'open' };
            }
            return r;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? -t.amount : t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        // Actualizar presupuestos si era un gasto del mes actual
        const budgets = prev.budgets.map(b => {
          if (t.type === 'expense' && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: Math.max(0, b.spent - t.amount) };
          }
          return b;
        });

        return {
          ...prev,
          transactions: prev.transactions.filter(tx => tx.id !== id),
          accounts,
          refunds: updatedRefunds,
          budgets
        };
      });
    },
    addAccount: (a) => {
      const id = 'acc_' + Date.now();
      setState(prev => ({
        ...prev,
        accounts: [...prev.accounts, { ...a, id, currentBalance: a.initialBalance }]
      }));
    },
    updateAccount: (a) => {
      setState(prev => ({
        ...prev,
        accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc)
      }));
    },
    deleteAccount: (id) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) }));
    },
    addSaving: (s) => {
      const id = 'sav_' + Date.now();
      setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id }] }));
    },
    updateSaving: (s) => {
      setState(prev => ({
        ...prev,
        savings: prev.savings.map(sv => sv.id === s.id ? s : sv)
      }));
    },
    deleteSaving: (id) => {
      setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) }));
    },
    addRefund: (r) => {
      const id = 'ref_' + Date.now();
      setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id }] }));
    },
    updateRefund: (r) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf)
      }));
    },
    deleteRefund: (id) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.filter(r => r.id !== id),
        // Desvincular transacciones asociadas para que no queden huérfanas
        transactions: prev.transactions.map(t => t.refundId === id ? { ...t, refundId: undefined, isRefund: false } : t)
      }));
    },
    mergeRefunds: (id1, id2) => {
      setState(prev => {
        const r1 = prev.refunds.find(r => r.id === id1);
        const r2 = prev.refunds.find(r => r.id === id2);
        if (!r1 || !r2) return prev;

        const newId = 'ref_merged_' + Date.now();
        const mergedRefund: Refund = {
          id: newId,
          name: `${r1.name} + ${r2.name}`,
          totalAmount: r1.totalAmount + r2.totalAmount,
          paidByMe: r1.paidByMe + r2.paidByMe,
          pendingAmount: r1.pendingAmount + r2.pendingAmount,
          status: (r1.pendingAmount + r2.pendingAmount) > 0 ? 'open' : 'closed',
          notes: `Unificado desde "${r1.name}" y "${r2.name}".\nNotas R1: ${r1.notes}\nNotas R2: ${r2.notes}`,
          date: new Date().toISOString().split('T')[0]
        };

        return {
          ...prev,
          refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), mergedRefund],
          transactions: prev.transactions.map(t => 
            (t.refundId === id1 || t.refundId === id2) ? { ...t, refundId: newId } : t
          )
        };
      });
    },
    addBudget: (b) => {
      const id = 'budget_' + Date.now();
      setState(prev => ({
        ...prev,
        budgets: [...prev.budgets, { ...b, id, spent: 0, icon: 'ShoppingBag' }]
      }));
    },
    updateBudget: (b) => {
      setState(prev => ({
        ...prev,
        budgets: prev.budgets.map(bg => bg.id === b.id ? b : bg)
      }));
    },
    changeMonth: (offset) => {
      setState(prev => {
        const [year, month] = prev.currentDate.split('-').map(Number);
        const date = new Date(year, month - 1 + offset, 1);
        return { ...prev, currentDate: date.toISOString().substring(0, 7) };
      });
    },
    setMonth: (date) => {
      setState(prev => ({ ...prev, currentDate: date }));
    },
    updateLayout: (newLayout) => {
      setState(prev => ({ ...prev, dashboardLayout: newLayout }));
    },
    setChallenges: (challenges) => {
      setState(prev => ({ ...prev, challenges }));
    }
  };

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);
  const closeMenu = () => setIsMenuOpen(false);

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 overflow-hidden">
          <Sidebar isOpen={isMenuOpen} onClose={closeMenu} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={toggleMenu} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

