import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, CheckCircle2, Circle, Users, DollarSign, XCircle, Trash2, Merge, X } from 'lucide-react';
import { Refund } from '../types';

const Refunds: React.FC = () => {
  const { refunds, addRefund, updateRefund, deleteRefund, mergeRefunds } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [isMerging, setIsMerging] = useState(false);
  const [mergeSelection, setMergeSelection] = useState<string[]>([]);

  // Form
  const [name, setName] = useState('');
  const [total, setTotal] = useState(0);
  const [myPart, setMyPart] = useState(0);
  const [notes, setNotes] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    addRefund({
      name,
      totalAmount: total,
      paidByMe: myPart,
      pendingAmount: total - myPart,
      status: 'open',
      notes,
      date: new Date().toISOString()
    });
    setIsAdding(false);
    reset();
  };

  const reset = () => { setName(''); setTotal(0); setMyPart(0); setNotes(''); };

  const closeRefund = (id: string) => {
    const r = refunds.find(x => x.id === id);
    if (r) updateRefund({ ...r, status: 'closed', pendingAmount: 0 });
  };

  const addPayment = (id: string, amount: number) => {
    const r = refunds.find(x => x.id === id);
    if (!r) return;
    const newPending = Math.max(0, r.pendingAmount - amount);
    updateRefund({ ...r, pendingAmount: newPending, status: newPending <= 0 ? 'closed' : 'open' });
  };

  const handleMergeToggle = (id: string) => {
    setMergeSelection(prev => {
      if (prev.includes(id)) return prev.filter(x => x !== id);
      if (prev.length >= 2) return prev; // Solo unificar 2
      return [...prev, id];
    });
  };

  const confirmMerge = () => {
    if (mergeSelection.length === 2) {
      mergeRefunds(mergeSelection[0], mergeSelection[1]);
      setMergeSelection([]);
      setIsMerging(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Reembolsos</h2>
          <p className="text-slate-500 font-medium">Controla quién te debe dinero y unifica deudas.</p>
        </div>
        <div className="flex gap-2">
          {refunds.length >= 2 && (
            <button 
              onClick={() => setIsMerging(!isMerging)}
              className={`flex items-center gap-2 px-6 py-3 font-bold rounded-2xl transition-all shadow-sm ${isMerging ? 'bg-amber-600 text-white' : 'bg-white border border-slate-200 text-slate-700'}`}
            >
              <Merge size={18} />
              {isMerging ? 'Cancelar Unificación' : 'Unificar Deudas'}
            </button>
          )}
          <button 
            onClick={() => setIsAdding(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200"
          >
            <Plus size={18} />
            Nuevo Reembolso
          </button>
        </div>
      </div>

      {isMerging && (
        <div className="bg-amber-50 border border-amber-200 p-6 rounded-[2rem] flex flex-col md:flex-row items-center justify-between gap-4 animate-in slide-in-from-top-4">
          <div>
            <p className="text-amber-800 font-bold">Modo Unificación Activo</p>
            <p className="text-amber-600 text-sm">Selecciona 2 reembolsos para combinarlos en uno solo.</p>
          </div>
          <div className="flex items-center gap-3">
             <span className="text-xs font-bold text-amber-700 bg-amber-200/50 px-3 py-1 rounded-full">{mergeSelection.length} / 2 seleccionados</span>
             <button 
                onClick={confirmMerge}
                disabled={mergeSelection.length !== 2}
                className="bg-amber-600 text-white px-6 py-2 rounded-xl font-bold text-sm shadow-md disabled:opacity-50 transition-all"
             >
                Confirmar Unión
             </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {refunds.map(r => (
          <div 
            key={r.id} 
            onClick={() => isMerging && handleMergeToggle(r.id)}
            className={`bg-white rounded-[2.5rem] p-8 border transition-all cursor-pointer group relative ${
              isMerging && mergeSelection.includes(r.id) ? 'border-amber-500 ring-4 ring-amber-100 scale-105' : 
              r.status === 'closed' ? 'border-slate-100 opacity-60' : 'border-slate-100 shadow-sm hover:shadow-md'
            }`}
          >
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${r.status === 'closed' ? 'bg-slate-100 text-slate-400' : 'bg-blue-50 text-blue-600'}`}>
                  <Users size={22} />
                </div>
                <div>
                  <h4 className="font-bold text-slate-800">{r.name}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{new Date(r.date).toLocaleDateString()}</p>
                </div>
              </div>
              <div className="flex gap-1">
                <button 
                  onClick={(e) => { e.stopPropagation(); if(confirm('¿Eliminar definitivamente este reembolso?')) deleteRefund(r.id); }}
                  className="p-2 text-slate-300 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100"
                  title="Eliminar reembolso"
                >
                  <Trash2 size={18} />
                </button>
                {r.status === 'closed' ? <CheckCircle2 className="text-emerald-500" size={24} /> : <Circle className="text-slate-200" size={24} />}
              </div>
            </div>

            <p className="text-sm text-slate-500 mb-6 h-12 overflow-hidden line-clamp-2 italic">{r.notes || 'Sin descripción adicional'}</p>

            <div className="bg-slate-50 rounded-3xl p-6 mb-6 border border-slate-100">
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest mb-1">Pendiente</p>
                  <p className="text-3xl font-black text-blue-600">{r.pendingAmount.toLocaleString('es-ES')}€</p>
                </div>
                <div className="text-right">
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest mb-1">Total</p>
                  <p className="text-lg font-bold text-slate-700">{r.totalAmount}€</p>
                </div>
              </div>
            </div>

            {r.status === 'open' && !isMerging && (
              <div className="flex gap-2">
                <button 
                  onClick={(e) => { e.stopPropagation(); addPayment(r.id, 10); }}
                  className="flex-1 py-3 bg-slate-900 text-white rounded-2xl font-bold text-xs hover:bg-slate-800 transition-all active:scale-95"
                >
                  Cobrar 10€
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); closeRefund(r.id); }}
                  className="p-3 bg-white border border-slate-200 text-slate-400 rounded-2xl hover:bg-slate-50 transition-all"
                  title="Cerrar liquidando deuda"
                >
                  <XCircle size={20} />
                </button>
              </div>
            )}

            {isMerging && (
              <div className="absolute inset-0 bg-blue-600/5 rounded-[2.5rem] flex items-center justify-center pointer-events-none">
                {mergeSelection.includes(r.id) && (
                  <div className="bg-amber-500 text-white w-8 h-8 rounded-full flex items-center justify-center font-bold shadow-lg">
                    {mergeSelection.indexOf(r.id) + 1}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}

        {refunds.length === 0 && (
          <div className="col-span-full py-32 text-center bg-white rounded-[2.5rem] border border-dashed border-slate-200">
             <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                <DollarSign size={40} />
             </div>
             <p className="text-slate-400 font-bold text-lg">No tienes reembolsos activos</p>
             <p className="text-slate-300 text-sm mt-2">Los gastos que marques como reembolso aparecerán aquí.</p>
          </div>
        )}
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
               <h3 className="text-2xl font-black text-slate-800 tracking-tight">Nuevo Reembolso</h3>
               <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-100 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Descripción del gasto</label>
                <input 
                  type="text" 
                  value={name} 
                  onChange={e => setName(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all" 
                  placeholder="Ej: Gasolina viaje" 
                  required 
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Monto Total</label>
                  <input 
                    type="number" 
                    value={total} 
                    onChange={e => setTotal(Number(e.target.value))}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" 
                    required
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Tu parte (Pagado)</label>
                  <input 
                    type="number" 
                    value={myPart} 
                    onChange={e => setMyPart(Number(e.target.value))}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" 
                    required
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Detalles / Personas</label>
                <textarea 
                  value={notes} 
                  onChange={e => setNotes(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 h-28 outline-none" 
                  placeholder="Ej: Pablo debe 20€, Ana debe 15€..."
                />
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95">Crear</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

