import React, { useState, useMemo } from 'react';
import { useFinance } from '../App';
import { Plus, Search, Filter, Camera, ArrowUpRight, ArrowDownRight, Trash2, ImageIcon, Loader2, X, Receipt } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { Transaction } from '../types';
import { CATEGORIES } from '../constants';

const Transactions: React.FC = () => {
  const { transactions, accounts, refunds, addTransaction, deleteTransaction, currentDate } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);

  // Form state para manual
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(CATEGORIES[0].name);
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');

  // Filtered transactions
  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setType('expense');
    setCategory(CATEGORIES[0].name);
    setIsRefundLink(false);
    setSelectedRefundId('');
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    addTransaction({
      date: new Date().toISOString().split('T')[0],
      amount: Number(amount),
      description: desc,
      category: category,
      type: type,
      accountId: accountId,
      isRefund: type === 'expense' && isRefundLink,
      refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
    });

    setIsAdding(false);
    resetForm();
  };

  // AI OCR Handler
  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);

        // Simplemente abrimos el modal con el primer resultado para que el usuario confirme y elija reembolso si quiere
        if (results.length > 0) {
            const first = results[0];
            setDesc(first.description || '');
            setAmount(first.amount || 0);
            setType(first.type === 'income' ? 'income' : 'expense');
            setCategory(first.category || 'Otros');
            setIsAdding(true);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar el ticket con IA");
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial</h2>
          <p className="text-slate-500 font-medium">Gestiona tus movimientos y vincula cobros de reembolsos.</p>
        </div>
        <div className="flex gap-2">
          <label className="flex items-center gap-2 px-6 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all shadow-sm cursor-pointer active:scale-95">
            {isScanning ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Camera size={18} className="text-blue-600" />}
            Escanear con IA
            <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button 
            onClick={() => setIsAdding(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
          >
            <Plus size={18} />
            Nueva Manual
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        {/* Toolbar */}
        <div className="p-8 border-b border-slate-100 flex flex-col md:flex-row gap-6 justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-5 py-3 rounded-2xl border border-slate-100 w-full md:w-[400px] shadow-sm">
            <Search size={20} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="Buscar por descripción o categoría..." 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-medium"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1.5 rounded-2xl border border-slate-100 self-start shadow-sm">
            <button 
              onClick={() => setFilter('all')}
              className={`px-6 py-2 text-xs font-bold rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
            >
