                        <label className="block text-[10px] font-bold text-blue-500 uppercase tracking-widest mb-2">Selecciona Reembolso</label>
                        <select 
                          value={selectedRefundId} 
                          onChange={e => setSelectedRefundId(e.target.value)}
                          className="w-full bg-white border border-blue-200 rounded-2xl p-3 font-bold text-sm outline-none"
                          required={isRefundLink}
                        >
                          <option value="">-- Elige deuda pendiente --</option>
                          {refunds.filter(r => r.status === 'open').map(r => (
                            <option key={r.id} value={r.id}>{r.name} (Pendiente: {r.pendingAmount}€)</option>
                          ))}
                        </select>
                        {refunds.filter(r => r.status === 'open').length === 0 && (
                          <p className="text-[10px] text-rose-500 mt-2 font-bold">No hay reembolsos abiertos disponibles.</p>
                        )}
                      </div>
                    )}

                    {isRefundLink && type === 'expense' && (
                       <p className="text-[10px] text-blue-500 font-medium">Se creará automáticamente un nuevo reembolso con el total de este gasto.</p>
                    )}
                  </div>

                  <div className="flex gap-3 pt-4">
                    <button 
                      type="button" 
                      onClick={() => { setIsAdding(false); resetForm(); }} 
                      className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200"
                    >
                      Cancelar
                    </button>
                    <button 
                      type="submit" 
                      className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                    >
                      Confirmar
                    </button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

