                onClick={confirmMerge}
                disabled={mergeSelection.length !== 2}
                className="bg-amber-600 text-white px-6 py-2 rounded-xl font-bold text-sm shadow-md disabled:opacity-50 hover:bg-amber-700 transition-all"
             >
                Confirmar Unión
             </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
