                  title="Eliminar reembolso"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>

            {/* Sección de Notas con Edición */}
            <div className="mb-6 bg-slate-50/50 p-4 rounded-2xl border border-slate-100/50">
              <div className="flex items-center justify-between mb-2">
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest flex items-center gap-2">
                  <MessageSquare size={12} /> Notas
                </p>
                {editingNotesId !== r.id ? (
                  <button 
                    onClick={(e) => { e.stopPropagation(); startEditingNotes(r); }}
                    className="p-1 text-slate-400 hover:text-blue-600 transition-colors opacity-0 group-hover:opacity-100"
