                    required
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Notas / Personas implicadas</label>
                <textarea 
                  value={notes} 
                  onChange={e => setNotes(e.target.value)}
