              <p className="text-amber-600 text-sm">Selecciona 2 reembolsos para sumarlos en uno solo.</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <span className="text-xs font-bold text-amber-700 bg-amber-200/50 px-3 py-1 rounded-full">{mergeSelection.length} / 2 seleccionados</span>
             <button 
                onClick={confirmMerge}
                disabled={mergeSelection.length !== 2}
                className="bg-amber-600 text-white px-6 py-2 rounded-xl font-bold text-sm shadow-md disabled:opacity-50 hover:bg-amber-700 transition-all active:scale-95"
             >
                Confirmar Unión
             </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredRefunds.map(r => (
          <div 
            key={r.id} 
