              {editingNotesId === r.id ? (
                <textarea
                  value={tempNotes}
                  onChange={(e) => setTempNotes(e.target.value)}
                  onClick={(e) => e.stopPropagation()}
                  className="w-full text-xs bg-white border border-blue-200 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all h-24 resize-none font-medium text-slate-700 shadow-inner"
