            {/* Resumen Financiero con "Mi Parte" */}
            <div className={`rounded-3xl p-6 border transition-all space-y-4 ${r.status === 'closed' ? 'bg-slate-50 border-slate-200' : 'bg-blue-50/50 border-blue-100 shadow-sm'}`}>
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest mb-1">Pendiente de cobro</p>
                  <p className={`text-3xl font-black ${r.status === 'closed' ? 'text-slate-400 line-through' : 'text-blue-600'}`}>
                    {r.pendingAmount.toLocaleString('es-ES')}€
                  </p>
                </div>
                <div className="text-right">
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest mb-1">Total original</p>
                  <p className="text-lg font-bold text-slate-700">{r.totalAmount}€</p>
