export default Refunds;

import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2,
  ChevronRight,
  Sparkles,
  Loader2,
  ShoppingBag
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { generateAIChallenges } from '../services/geminiService';

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    budgets,
    currentDate,
    dashboardLayout,
    updateLayout,
    setChallenges
  } = useFinance();

  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');
  const [showBreakdown, setShowBreakdown] = useState(false);
  const [isGeneratingChallenges, setIsGeneratingChallenges] = useState(false);

  // Lógica Financiera Corregida: Reembolsos restan de gastos
  const metrics = useMemo(() => {
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));

    // Ingresos reales (que no son cobros de deudas)
    const income = monthTx
      .filter(t => t.type === 'income' && !t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    // Recuperaciones de dinero (cobros de reembolsos)
    const refundRecoveries = monthTx
      .filter(t => t.type === 'income' && t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    // Gasto Bruto
    const grossExpense = monthTx
      .filter(t => t.type === 'expense')
      .reduce((sum, t) => sum + t.amount, 0);

    // Gasto Neto (Gasto real tras recuperar reembolsos)
    const expense = Math.max(0, grossExpense - refundRecoveries);

    const monthSavings = monthTx
      .filter(t => t.category === 'Ahorro' || t.category === 'Ahorros')
      .reduce((sum, t) => sum + t.amount, 0);

    const totalLiquid = accounts.reduce((sum, acc) => sum + acc.currentBalance, 0);
    const totalSavings = savings.reduce((sum, s) => sum + s.currentAmount, 0);
    const netWorth = totalLiquid + totalSavings;

    const monthResult = income - expense; 

    return {
      income,
      expense,
      refundRecoveries,
      monthSavings,
      monthResult,
      netWorth,
      totalSavings
    };
  }, [transactions, currentDate, accounts, savings]);

  // AI Challenges Auto-Evaluator
  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;

      if (ch.type === 'spending_limit') {
        const spent = monthTx
          .filter(t => t.type === 'expense' && t.category === ch.category)
          .reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavings >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.income >= ch.target;
      }

      return { ...ch, completed: isCompleted || ch.completed };
    });
  }, [challenges, transactions, currentDate, metrics]);

  // Chart Data
  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;
    return Array.from({ length: limit }, (_, i) => {
      const valBase = metrics.netWorth;
      const factor = 1 - ( (limit - 1 - i) * 0.05 ); 
      return {
        name: monthNames[i % 12],
        patrimonio: Math.round(valBase * factor)
      };
    });
  }, [metrics.netWorth, chartFilter]);

  const handleGenerateChallenges = async () => {
    setIsGeneratingChallenges(true);
    try {
      const context = `Presupuestos: ${budgets.map(b => b.category + ": " + b.spent + "/" + b.limit).join(", ")}. Patrimonio: ${metrics.netWorth}€. Ahorros: ${metrics.totalSavings}€.`;
      const newChallenges = await generateAIChallenges(context);
      setChallenges(newChallenges);
    } catch (error) {
      console.error("Error generating challenges:", error);
    } finally {
      setIsGeneratingChallenges(false);
    }
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newLayout = [...dashboardLayout];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLayout.length) return;
    [newLayout[index], newLayout[targetIndex]] = [newLayout[targetIndex], newLayout[index]];
    updateLayout(newLayout);
  };

  const renderBlock = (key: string, index: number) => {
    const moveControls = isEditMode && (
      <div className="absolute top-4 right-4 flex gap-1 z-20">
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'up'); }} className="p-2 bg-white border border-slate-200 rounded-xl shadow-sm hover:bg-slate-50 transition-all active:scale-95" disabled={index === 0}>
          <ChevronUp size={16} className="text-slate-600" />
        </button>
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'down'); }} className="p-2 bg-white border border-slate-200 rounded-xl shadow-sm hover:bg-slate-50 transition-all active:scale-95" disabled={index === dashboardLayout.length - 1}>
          <ChevronDown size={16} className="text-slate-600" />
        </button>
      </div>
    );

    switch (key) {
      case 'balance':
        return (
          <div key={key} className="relative bg-gradient-to-br from-blue-700 to-blue-600 rounded-[2.5rem] p-10 text-white shadow-2xl shadow-blue-200/50 overflow-hidden">
            {moveControls}
            <div className="relative z-10">
              <div className="flex justify-between items-start">
                <div>
                  <p className="text-blue-100 text-xs font-bold uppercase tracking-widest mb-1">Patrimonio Neto Total</p>
                  <h2 className="text-5xl font-black">{metrics.netWorth.toLocaleString()}€</h2>
                </div>
                <button 
                  onClick={() => setShowBreakdown(!showBreakdown)}
                  className={`px-4 py-2 rounded-2xl flex items-center gap-2 text-sm font-bold transition-all shadow-lg ${metrics.monthResult >= 0 ? 'bg-white/20 text-white hover:bg-white/30' : 'bg-rose-500/20 text-rose-100 hover:bg-rose-500/30'}`}
                >
                  {metrics.monthResult >= 0 ? <TrendingUp size={18} /> : <TrendingDown size={18} />}
                  {metrics.monthResult >= 0 ? '+' : ''}{metrics.monthResult.toLocaleString()}€ este mes
                  <ChevronRight size={14} className={`transition-transform duration-300 ${showBreakdown ? 'rotate-90' : ''}`} />
                </button>
              </div>

              {showBreakdown && (
                <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-4 animate-in slide-in-from-top-4 duration-300">
                  <div className="p-5 bg-emerald-500/20 backdrop-blur-md rounded-3xl border border-white/10">
                    <p className="text-[10px] font-bold uppercase text-emerald-100 mb-1">Ingresos</p>
                    <p className="text-2xl font-black">{metrics.income.toLocaleString()}€</p>
                  </div>
                  <div className="p-5 bg-rose-500/20 backdrop-blur-md rounded-3xl border border-white/10">
                    <p className="text-[10px] font-bold uppercase text-rose-100 mb-1">Gasto Real (Neto)</p>
                    <p className="text-2xl font-black">{metrics.expense.toLocaleString()}€</p>
                  </div>
                  <div className="p-5 bg-blue-400/30 backdrop-blur-md rounded-3xl border border-white/10">
                    <p className="text-[10px] font-bold uppercase text-blue-100 mb-1">Recuperado (Reembolsos)</p>
                    <p className="text-2xl font-black">{metrics.refundRecoveries.toLocaleString()}€</p>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-3 gap-8 mt-10 pt-8 border-t border-white/10">
                <div>
                  <p className="text-[10px] text-blue-200 font-bold uppercase mb-1">Resultado Neto</p>
                  <p className="text-lg font-bold">{(metrics.monthResult).toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[10px] text-blue-200 font-bold uppercase mb-1">Ahorro del Mes</p>
                  <p className="text-lg font-bold">{(metrics.monthSavings).toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[10px] text-blue-200 font-bold uppercase mb-1">Total en Huchas</p>
                  <p className="text-lg font-bold">{metrics.totalSavings.toLocaleString()}€</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center">
                  <Target size={20} />
                </div>
                <h3 className="font-bold text-slate-800">Retos AI Aura</h3>
              </div>
              <button 
                onClick={handleGenerateChallenges}
                disabled={isGeneratingChallenges}
                className="p-2.5 bg-blue-600 text-white rounded-xl transition-all disabled:opacity-50 hover:bg-blue-700 shadow-md shadow-blue-100"
              >
                {isGeneratingChallenges ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
              </button>
            </div>
            <div className="space-y-3">
              {evaluatedChallenges.map(ch => (
                <div key={ch.id} className={`p-4 rounded-2xl border flex items-center gap-3 transition-all ${ch.completed ? 'bg-emerald-50 border-emerald-100' : 'bg-slate-50 border-slate-100'}`}>
                  {ch.completed ? <CheckCircle2 className="text-emerald-500" size={20}/> : <Circle className="text-slate-300" size={20}/>}
                  <div className="flex-1">
                    <p className={`text-sm font-bold ${ch.completed ? 'text-emerald-700' : 'text-slate-700'}`}>{ch.title}</p>
                    <p className="text-[10px] text-slate-500 font-medium">Objetivo: {ch.target}€</p>
                  </div>
                </div>
              ))}
              {evaluatedChallenges.length === 0 && (
                <p className="text-slate-400 text-xs text-center py-4 italic">Pulsa en el destello para que Aura te proponga retos.</p>
              )}
            </div>
          </div>
        );
      case 'savings':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-amber-50 text-amber-600 rounded-xl flex items-center justify-center">
                <PiggyBank size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Ahorro General</h3>
            </div>
            <div className="text-center py-6">
              <p className="text-4xl font-black text-slate-900">{metrics.totalSavings.toLocaleString()}€</p>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-2">Capital en huchas</p>
            </div>
            <div className="grid grid-cols-2 gap-2 mt-4">
               {savings.slice(0, 4).map(s => (
                 <div key={s.id} className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                   <p className="text-[10px] text-slate-400 font-bold truncate uppercase">{s.name}</p>
                   <p className="text-xs font-black text-slate-700">{s.currentAmount}€</p>
                 </div>
               ))}
            </div>
          </div>
        );
      case 'chart':
        return (
          <div key={key} className="relative bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm">
            {moveControls}
            <div className="flex items-center justify-between mb-8">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <TrendingUp size={20} className="text-emerald-500" /> Evolución del Patrimonio
              </h3>
              <div className="flex gap-1 bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setChartFilter('6m')} className={`px-4 py-1.5 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '6m' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>6 M</button>
                <button onClick={() => setChartFilter('12m')} className={`px-4 py-1.5 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '12m' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>12 M</button>
              </div>
            </div>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorPat" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} />
                  <YAxis hide />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                    formatter={(value: any) => [`${value}€`, 'Patrimonio']}
                  />
                  <Area type="monotone" dataKey="patrimonio" stroke="#3b82f6" strokeWidth={3} fill="url(#colorPat)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        );
      case 'accounts':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center">
                <Wallet size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Cuentas Bancarias</h3>
            </div>
            <div className="space-y-4">
              {accounts.map(acc => (
                <div key={acc.id} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <div className="flex items-center gap-3">
                    <span className="text-xl">{acc.emoji || '🏦'}</span>
                    <span className="font-bold text-slate-700 text-sm">{acc.name}</span>
                  </div>
                  <span className="font-black text-slate-900">{acc.currentBalance.toLocaleString()}€</span>
                </div>
              ))}
            </div>
          </div>
        );
      case 'budget':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-purple-50 text-purple-600 rounded-xl flex items-center justify-center">
                <ShoppingBag size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Presupuestos</h3>
            </div>
            <div className="space-y-5">
              {budgets.slice(0, 3).map(b => {
                const progress = Math.min((b.spent / b.limit) * 100, 100);
                return (
                  <div key={b.id}>
                    <div className="flex justify-between text-[10px] font-bold text-slate-500 mb-1.5 uppercase tracking-wider">
                      <span>{b.category}</span>
                      <span className={progress > 90 ? 'text-rose-500' : 'text-blue-600'}>{Math.round(progress)}%</span>
                    </div>
                    <div className="w-full h-2 bg-slate-100 rounded-full overflow-hidden">
                      <div 
                        className={`h-full transition-all duration-700 ${progress > 90 ? 'bg-rose-500' : progress > 70 ? 'bg-amber-400' : 'bg-blue-600'}`} 
                        style={{ width: `${progress}%` }}
                      ></div>
                    </div>
                  </div>
                );
              })}
              {budgets.length === 0 && <p className="text-xs text-slate-400 italic text-center py-4">Sin límites definidos.</p>}
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="space-y-6 pb-20 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Dashboard</h2>
          <p className="text-slate-500 font-medium">Lógica de gasto real activa (Reembolsos restan de gastos).</p>
        </div>
        <button 
          onClick={() => setIsEditMode(!isEditMode)}
          className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-sm transition-all shadow-sm ${isEditMode ? 'bg-blue-600 text-white shadow-xl shadow-blue-200' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'}`}
        >
          <Settings2 size={18}/> {isEditMode ? 'Guardar Cambios' : 'Personalizar Diseño'}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 auto-rows-min">
        {dashboardLayout.map((key, idx) => {
          const isFullWidth = key === 'balance' || key === 'chart';
          return (
            <div key={key} className={`${isFullWidth ? 'lg:col-span-2' : 'lg:col-span-1'} transition-all duration-300`}>
              {renderBlock(key, idx)}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Wallet, 
  PiggyBank, 
  Receipt, 
  BarChart3, 
  MessageSquare,
  ChevronLeft,
  ChevronRight,
  Menu,
  X,
  Plus
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';

interface FinanceContextType extends FinanceState {
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon'>) => void;
  updateBudget: (b: Budget) => void;
  changeMonth: (offset: number) => void;
  setMonth: (date: string) => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<FinanceState>(() => {
    const saved = localStorage.getItem('finance_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('finance_data', JSON.stringify(state));
  }, [state]);

  const contextValue: FinanceContextType = {
    ...state,
    addTransaction: (t, myPart) => {
      const id = Math.random().toString(36).substr(2, 9);
      const newTransaction = { ...t, id };

      setState(prev => {
        let updatedRefunds = [...prev.refunds];

        // Si el gasto genera un reembolso
        if (t.type === 'expense' && t.isRefund) {
          const refundId = 'ref_' + Date.now();
          const partToPay = myPart !== undefined ? myPart : t.amount / 2;
          updatedRefunds.push({
            id: refundId,
            name: t.description,
            totalAmount: t.amount,
            paidByMe: partToPay, 
            pendingAmount: t.amount - partToPay, 
            status: (t.amount - partToPay) <= 0 ? 'closed' : 'open',
            notes: 'Creado desde gasto: ' + t.description,
            date: t.date,
            originTransactionId: id
          });
          newTransaction.refundId = refundId;
        }

        // Si el ingreso está vinculado a cobrar un reembolso existente
        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = Math.max(0, r.pendingAmount - t.amount);
              return { ...r, pendingAmount: newPending, status: newPending <= 0 ? 'closed' : 'open' };
            }
            return r;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? t.amount : -t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        const budgets = prev.budgets.map(b => {
          if (t.type === 'expense' && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: b.spent + t.amount };
          }
          return b;
        });

        return {
          ...prev,
          transactions: [newTransaction, ...prev.transactions],
          accounts,
          budgets,
          refunds: updatedRefunds
        };
      });
    },
    deleteTransaction: (id) => {
      setState(prev => {
        const t = prev.transactions.find(tx => tx.id === id);
        if (!t) return prev;

        let updatedRefunds = [...prev.refunds];
        updatedRefunds = updatedRefunds.filter(r => r.originTransactionId !== id);

        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = r.pendingAmount + t.amount;
              return { ...r, pendingAmount: newPending, status: 'open' };
            }
            return r;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? -t.amount : t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        const budgets = prev.budgets.map(b => {
          if (t.type === 'expense' && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: Math.max(0, b.spent - t.amount) };
          }
          return b;
        });

        return {
          ...prev,
          transactions: prev.transactions.filter(tx => tx.id !== id),
          accounts,
          refunds: updatedRefunds,
          budgets
        };
      });
    },
    addAccount: (a) => {
      const id = 'acc_' + Date.now();
      setState(prev => ({
        ...prev,
        accounts: [...prev.accounts, { ...a, id, currentBalance: a.initialBalance }]
      }));
    },
    updateAccount: (a) => {
      setState(prev => ({
        ...prev,
        accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc)
      }));
    },
    deleteAccount: (id) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) }));
    },
    addSaving: (s) => {
      const id = 'sav_' + Date.now();
      setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id }] }));
    },
    updateSaving: (s) => {
      setState(prev => ({
        ...prev,
        savings: prev.savings.map(sv => sv.id === s.id ? s : sv)
      }));
    },
    deleteSaving: (id) => {
      setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) }));
    },
    addRefund: (r) => {
      const id = 'ref_' + Date.now();
      setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id }] }));
    },
    updateRefund: (r) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf)
      }));
    },
    deleteRefund: (id) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.filter(r => r.id !== id),
        transactions: prev.transactions.map(t => t.refundId === id ? { ...t, refundId: undefined, isRefund: false } : t)
      }));
    },
    mergeRefunds: (id1, id2) => {
      setState(prev => {
        const r1 = prev.refunds.find(r => r.id === id1);
        const r2 = prev.refunds.find(r => r.id === id2);
        if (!r1 || !r2) return prev;

        const newId = 'ref_merged_' + Date.now();
        const mergedRefund: Refund = {
          id: newId,
          name: `${r1.name} + ${r2.name}`,
          totalAmount: r1.totalAmount + r2.totalAmount,
          paidByMe: r1.paidByMe + r2.paidByMe,
          pendingAmount: r1.pendingAmount + r2.pendingAmount,
          status: (r1.pendingAmount + r2.pendingAmount) > 0 ? 'open' : 'closed',
          notes: `Unificado desde "${r1.name}" y "${r2.name}".\nNotas R1: ${r1.notes}\nNotas R2: ${r2.notes}`,
          date: new Date().toISOString().split('T')[0]
        };

        return {
          ...prev,
          refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), mergedRefund],
          transactions: prev.transactions.map(t => 
            (t.refundId === id1 || t.refundId === id2) ? { ...t, refundId: newId } : t
          )
        };
      });
    },
    addBudget: (b) => {
      const id = 'budget_' + Date.now();
      setState(prev => ({
        ...prev,
        budgets: [...prev.budgets, { ...b, id, spent: 0, icon: 'ShoppingBag' }]
      }));
    },
    updateBudget: (b) => {
      setState(prev => ({
        ...prev,
        budgets: prev.budgets.map(bg => bg.id === b.id ? b : bg)
      }));
    },
    changeMonth: (offset) => {
      setState(prev => {
        const [year, month] = prev.currentDate.split('-').map(Number);
        const date = new Date(year, month - 1 + offset, 1);
        return { ...prev, currentDate: date.toISOString().substring(0, 7) };
      });
    },
    setMonth: (date) => {
      setState(prev => ({ ...prev, currentDate: date }));
    },
    updateLayout: (newLayout) => {
      setState(prev => ({ ...prev, dashboardLayout: newLayout }));
    },
    setChallenges: (challenges) => {
      setState(prev => ({ ...prev, challenges }));
    }
  };

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);
  const closeMenu = () => setIsMenuOpen(false);

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 overflow-hidden">
          <Sidebar isOpen={isMenuOpen} onClose={closeMenu} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={toggleMenu} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

