};

const Header = ({ onMenuClick }: { onMenuClick: () => void }) => {
  const { currentDate, changeMonth, setMonth } = useFinance();
  const [showMonthPicker, setShowMonthPicker] = useState(false);

  const monthNames = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio",
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];

  const currentFormatted = useMemo(() => {
    const [year, month] = currentDate.split('-').map(Number);
    return `${monthNames[month - 1]} ${year}`;
  }, [currentDate]);

  return (
    <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 h-16 flex items-center justify-between px-4 md:px-6 sticky top-0 z-20">
      <div className="flex items-center gap-3">
        <button 
          onClick={onMenuClick}
          className="md:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
        >
          <Menu size={22} />
        </button>

        <div className="flex items-center gap-1 md:gap-2 bg-slate-100 p-1 rounded-xl shadow-inner scale-90 md:scale-100">
          <button 
            onClick={() => changeMonth(-1)}
            className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"
          >
            <ChevronLeft size={18} />
          </button>

          <div className="relative">
            <button 
              onClick={() => setShowMonthPicker(!showMonthPicker)}
              className="px-2 py-1.5 text-xs font-semibold text-slate-700 min-w-[100px] text-center hover:bg-white/50 rounded-lg transition-colors"
            >
              {currentFormatted}
            </button>

            {showMonthPicker && (
              <div className="absolute top-full mt-2 left-0 w-64 bg-white border border-slate-200 rounded-2xl shadow-2xl p-4 grid grid-cols-3 gap-2 z-50 animate-in fade-in zoom-in duration-200">
                {monthNames.map((name, idx) => (
                  <button
                    key={name}
                    onClick={() => {
                      const year = currentDate.split('-')[0];
                      setMonth(`${year}-${String(idx + 1).padStart(2, '0')}`);
                      setShowMonthPicker(false);
                    }}
                    className={`p-2 text-xs rounded-lg font-medium transition-colors ${
                      currentDate.split('-')[1] === String(idx + 1).padStart(2, '0')
                        ? 'bg-blue-600 text-white'
                        : 'hover:bg-slate-100 text-slate-600'
                    }`}
                  >
                    {name.substring(0, 3)}
                  </button>
                ))}
              </div>
            )}
          </div>

          <button 
            onClick={() => changeMonth(1)}
            className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"
          >
            <ChevronRight size={18} />
          </button>
        </div>
      </div>
      <div className="flex items-center gap-3">
        <div className="w-8 h-8 rounded-full bg-blue-100 border-2 border-white shadow-sm overflow-hidden flex items-center justify-center">
          <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Felix" alt="avatar" />
        </div>
      </div>
    </header>
  );
};

