export default App;

import React, { useState } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  CheckCircle2, 
  Users, 
  DollarSign, 
  Trash2, 
  Merge, 
  X, 
  Edit3, 
  Save, 
  MessageSquare,
  AlertCircle,
  Check,
  TrendingUp
} from 'lucide-react';
import { Refund } from '../types';

const Refunds: React.FC = () => {
  const { refunds, addRefund, updateRefund, deleteRefund, mergeRefunds } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [isMerging, setIsMerging] = useState(false);
  const [mergeSelection, setMergeSelection] = useState<string[]>([]);
  const [filter, setFilter] = useState<'all' | 'open' | 'closed'>('open');

  // Estados para la edición de notas
  const [editingNotesId, setEditingNotesId] = useState<string | null>(null);
  const [tempNotes, setTempNotes] = useState('');

  // Formulario de nuevo reembolso
  const [name, setName] = useState('');
  const [total, setTotal] = useState(0);
  const [myPart, setMyPart] = useState(0);
  const [notes, setNotes] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const pending = total - myPart;
    addRefund({
      name,
      totalAmount: total,
      paidByMe: myPart,
      pendingAmount: pending,
      status: pending <= 0 ? 'closed' : 'open',
      notes,
      date: new Date().toISOString()
    });
    setIsAdding(false);
    reset();
  };

  const reset = () => { setName(''); setTotal(0); setMyPart(0); setNotes(''); };

  const handleMergeToggle = (id: string) => {
    setMergeSelection(prev => {
      if (prev.includes(id)) return prev.filter(x => x !== id);
      if (prev.length >= 2) return prev; 
      return [...prev, id];
    });
  };

  const confirmMerge = () => {
    if (mergeSelection.length === 2) {
      mergeRefunds(mergeSelection[0], mergeSelection[1]);
      setMergeSelection([]);
      setIsMerging(false);
    }
  };

  const startEditingNotes = (r: Refund) => {
    setEditingNotesId(r.id);
    setTempNotes(r.notes);
  };

  const saveNotes = () => {
    const r = refunds.find(x => x.id === editingNotesId);
    if (r) {
      updateRefund({ ...r, notes: tempNotes });
    }
    setEditingNotesId(null);
  };

  const handleManualComplete = (r: Refund) => {
    if (confirm('¿Quieres marcar este reembolso como completado manualmente? El saldo pendiente se ajustará a 0€.')) {
      updateRefund({
        ...r,
        pendingAmount: 0,
        status: 'closed'
      });
    }
  };

  const filteredRefunds = refunds.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Reembolsos</h2>
          <p className="text-slate-500 font-medium">Controla quién te debe dinero. Los cobros restan de tus gastos totales.</p>
        </div>
        <div className="flex gap-2">
          {refunds.length >= 2 && (
            <button 
              onClick={() => setIsMerging(!isMerging)}
              className={`flex items-center gap-2 px-6 py-3 font-bold rounded-2xl transition-all shadow-sm ${isMerging ? 'bg-amber-600 text-white shadow-lg shadow-amber-100' : 'bg-white border border-slate-200 text-slate-700 hover:bg-slate-50'}`}
            >
              <Merge size={18} />
              {isMerging ? 'Cancelar Unión' : 'Unificar Deudas'}
            </button>
          )}
          <button 
            onClick={() => setIsAdding(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
          >
            <Plus size={18} />
            Nuevo Reembolso
          </button>
        </div>
      </div>

      {/* Filtros */}
      <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-2xl w-fit border border-slate-200 shadow-inner">
        <button onClick={() => setFilter('open')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'open' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>PENDIENTES</button>
        <button onClick={() => setFilter('closed')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'closed' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>COMPLETADOS</button>
        <button onClick={() => setFilter('all')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>TODOS</button>
      </div>

      {isMerging && (
        <div className="bg-amber-50 border border-amber-200 p-6 rounded-[2rem] flex flex-col md:flex-row items-center justify-between gap-4 animate-in slide-in-from-top-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-amber-200 text-amber-700 rounded-full flex items-center justify-center"><Merge size={20} /></div>
            <div>
              <p className="text-amber-800 font-bold">Unificación de Deudas</p>
              <p className="text-amber-600 text-sm">Combina dos deudas de la misma persona para un cobro único.</p>
            </div>
          </div>
          <button onClick={confirmMerge} disabled={mergeSelection.length !== 2} className="bg-amber-600 text-white px-6 py-2 rounded-xl font-bold text-sm shadow-md disabled:opacity-50 active:scale-95">Confirmar Unión ({mergeSelection.length}/2)</button>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredRefunds.map(r => (
          <div 
            key={r.id} 
            onClick={() => isMerging && handleMergeToggle(r.id)}
            className={`bg-white rounded-[2.5rem] p-8 border transition-all relative overflow-hidden group ${
              isMerging && mergeSelection.includes(r.id) ? 'border-amber-500 ring-4 ring-amber-100 scale-[1.02] shadow-xl' : 
              r.status === 'closed' ? 'border-slate-100 opacity-75' : 'border-slate-100 shadow-sm hover:shadow-md'
            } ${isMerging ? 'cursor-pointer' : ''}`}
          >
            {r.status === 'closed' && (
              <div className="absolute top-4 right-4 z-10">
                <div className="bg-emerald-100 text-emerald-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-1 shadow-sm"><CheckCircle2 size={12} /> Liquidado</div>
              </div>
            )}

            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${r.status === 'closed' ? 'bg-slate-100 text-slate-400' : 'bg-blue-50 text-blue-600'}`}>
                  <Users size={22} />
                </div>
                <div>
                  <h4 className="font-bold text-slate-800 line-clamp-1">{r.name}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{new Date(r.date).toLocaleDateString()}</p>
                </div>
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); if(confirm('¿Eliminar definitivamente?')) deleteRefund(r.id); }}
                className="p-2.5 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
              >
                <Trash2 size={18} />
              </button>
            </div>

            <div className="mb-6 bg-slate-50 p-4 rounded-2xl border border-slate-100">
              <div className="flex items-center justify-between mb-2">
                <p className="text-[10px] text-slate-400 font-bold uppercase flex items-center gap-2"><MessageSquare size={12} /> Notas</p>
                {editingNotesId !== r.id ? (
                  <button onClick={(e) => { e.stopPropagation(); startEditingNotes(r); }} className="p-1.5 text-slate-400 hover:text-blue-600 bg-white rounded-lg shadow-sm"><Edit3 size={14} /></button>
                ) : (
                  <button onClick={(e) => { e.stopPropagation(); saveNotes(); }} className="p-1.5 text-white bg-emerald-500 rounded-lg shadow-sm"><Save size={14} /></button>
                )}
              </div>
              {editingNotesId === r.id ? (
                <textarea value={tempNotes} onChange={e => setTempNotes(e.target.value)} onClick={e => e.stopPropagation()} className="w-full text-xs bg-white border border-blue-200 rounded-xl p-3 outline-none h-20 resize-none font-medium" />
              ) : (
                <p className="text-xs text-slate-500 italic line-clamp-2">{r.notes || 'Sin notas.'}</p>
              )}
            </div>

            <div className={`rounded-3xl p-6 border transition-all space-y-4 ${r.status === 'closed' ? 'bg-slate-50 border-slate-200' : 'bg-blue-50/50 border-blue-100 shadow-sm'}`}>
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Pendiente de cobro</p>
                  <p className={`text-3xl font-black ${r.status === 'closed' ? 'text-slate-400 line-through' : 'text-blue-600'}`}>{r.pendingAmount.toLocaleString()}€</p>
                </div>
                <div className="text-right">
                  <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Total</p>
                  <p className="text-lg font-bold text-slate-700">{r.totalAmount}€</p>
                </div>
              </div>
              <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-lg bg-emerald-100 text-emerald-600 flex items-center justify-center"><Check size={14} /></div>
                  <div>
                    <p className="text-[10px] text-slate-400 font-bold uppercase">Mi parte (Gasto real)</p>
                    <p className="text-sm font-black text-emerald-600">{r.paidByMe}€</p>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-lg bg-blue-100 text-blue-600 flex items-center justify-center"><TrendingUp size={14} /></div>
                  <div>
                    <p className="text-[10px] text-slate-400 font-bold uppercase">Recuperado</p>
                    <p className="text-sm font-black text-blue-600">{r.totalAmount - r.paidByMe - r.pendingAmount}€</p>
                  </div>
                </div>
              </div>
            </div>

            {r.status === 'open' && !isMerging && (
              <button 
                onClick={(e) => { e.stopPropagation(); handleManualComplete(r); }}
                className="w-full mt-4 flex items-center justify-center gap-2 p-3 bg-white border border-slate-200 text-slate-700 rounded-2xl text-xs font-bold hover:bg-emerald-50 hover:text-emerald-600 transition-all active:scale-95 group/btn"
              >
                <CheckCircle2 size={16} className="text-slate-300 group-hover/btn:text-emerald-500" />
                Marcar como cobrado
              </button>
            )}
          </div>
        ))}
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
               <h3 className="text-2xl font-black text-slate-800 tracking-tight">Nuevo Reembolso</h3>
               <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Concepto</label>
                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none font-medium" placeholder="Ej: Cena amigos..." required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
