          </div>
          <div className="flex items-center gap-1 bg-white p-1.5 rounded-2xl border border-slate-100 shadow-sm">
            <button onClick={() => setFilter('all')} className={`px-6 py-2 text-xs font-bold rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-500'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`px-6 py-2 text-xs font-bold rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white' : 'text-slate-500'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`px-6 py-2 text-xs font-bold rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white' : 'text-slate-500'}`}>Gastos</button>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] uppercase tracking-widest text-slate-400 font-black border-b border-slate-100">
                <th className="px-8 py-5">Fecha</th>
                <th className="px-8 py-5">Movimiento</th>
                <th className="px-8 py-5">Categoría</th>
                <th className="px-8 py-5 text-right">Monto</th>
                <th className="px-8 py-5"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr key={tx.id} className="hover:bg-slate-50/80 transition-colors group">
                  <td className="px-8 py-5 text-sm font-semibold text-slate-400 whitespace-nowrap">{new Date(tx.date).toLocaleDateString()}</td>
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={18} /> : <ArrowDownRight size={18} />}
                      </div>
                      <div>
                        <span className="font-bold text-slate-800 text-sm block">{tx.description}</span>
                        {tx.refundId && <span className="text-[10px] bg-blue-50 text-blue-600 px-2 py-0.5 rounded-lg font-bold flex items-center gap-1 w-fit mt-1"><Receipt size={10} /> {tx.type === 'income' ? 'COBRO REEMBOLSO' : 'GASTO REEMBOLSABLE'}</span>}
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-5"><span className="px-4 py-1.5 bg-slate-100 text-slate-600 rounded-full text-[10px] font-black uppercase tracking-widest">{tx.category}</span></td>
                  <td className={`px-8 py-5 text-right font-black text-lg ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>{tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€</td>
                  <td className="px-8 py-5 text-right"><button onClick={() => { if(confirm('¿Eliminar transacción?')) deleteTransaction(tx.id); }} className="p-2.5 text-slate-300 hover:text-rose-500 rounded-xl opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={18} /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
                <div className="flex justify-between items-center mb-8">
                  <h3 className="text-2xl font-black text-slate-800 tracking-tight">Nueva Transacción</h3>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-2 hover:bg-slate-100 rounded-full"><X size={20} className="text-slate-400" /></button>
                </div>
                <form onSubmit={handleManualSubmit} className="space-y-6">
                  <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-3 text-xs font-black rounded-xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-500' : 'text-slate-400'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 text-xs font-black rounded-xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-500' : 'text-slate-400'}`}>INGRESO</button>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Descripción</label>
                    <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none font-medium" required />
