import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2,
  ChevronRight,
  Sparkles,
  Loader2,
  ShoppingBag
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { generateAIChallenges } from '../services/geminiService';

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    budgets,
    currentDate,
    dashboardLayout,
    updateLayout,
    setChallenges
  } = useFinance();

  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');
  const [isGeneratingChallenges, setIsGeneratingChallenges] = useState(false);

  // Lógica Financiera Corregida: Reembolsos restan de gastos
  const metrics = useMemo(() => {
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));

    // Ingresos reales (que no son cobros de deudas)
    const income = monthTx
      .filter(t => t.type === 'income' && !t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    // Recuperaciones de dinero (cobros de reembolsos)
    const refundRecoveries = monthTx
      .filter(t => t.type === 'income' && t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    // Gasto Bruto
    const grossExpense = monthTx
      .filter(t => t.type === 'expense')
      .reduce((sum, t) => sum + t.amount, 0);

    // Gasto Neto (Gasto real tras recuperar reembolsos)
    const expense = Math.max(0, grossExpense - refundRecoveries);

    const monthSavings = monthTx
      .filter(t => t.category === 'Ahorro' || t.category === 'Ahorros')
      .reduce((sum, t) => sum + t.amount, 0);

    const totalLiquid = accounts.reduce((sum, acc) => sum + acc.currentBalance, 0);
    const totalSavings = savings.reduce((sum, s) => sum + s.currentAmount, 0);
    const netWorth = totalLiquid + totalSavings;

    const monthResult = income - expense; 
    const pastBalance = netWorth - monthResult;

    return {
      income,
      expense,
      refundRecoveries,
      monthSavings,
      monthResult,
      netWorth,
      totalSavings,
      pastBalance
    };
  }, [transactions, currentDate, accounts, savings]);

  // AI Challenges Auto-Evaluator
  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;

      if (ch.type === 'spending_limit') {
        const spent = monthTx
          .filter(t => t.type === 'expense' && t.category === ch.category)
          .reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavings >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.income >= ch.target;
      }

      return { ...ch, completed: isCompleted || ch.completed };
    });
  }, [challenges, transactions, currentDate, metrics]);

  // Chart Data
  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;
    return Array.from({ length: limit }, (_, i) => {
      const valBase = metrics.netWorth;
      const factor = 1 - ( (limit - 1 - i) * 0.05 ); 
      return {
        name: monthNames[i % 12],
        patrimonio: Math.round(valBase * factor)
      };
    });
  }, [metrics.netWorth, chartFilter]);

  const handleGenerateChallenges = async () => {
    setIsGeneratingChallenges(true);
    try {
      const context = `Presupuestos: ${budgets.map(b => b.category + ": " + b.spent + "/" + b.limit).join(", ")}. Patrimonio: ${metrics.netWorth}€. Ahorros: ${metrics.totalSavings}€.`;
      const newChallenges = await generateAIChallenges(context);
      setChallenges(newChallenges);
    } catch (error) {
      console.error("Error generating challenges:", error);
    } finally {
      setIsGeneratingChallenges(false);
    }
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newLayout = [...dashboardLayout];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLayout.length) return;
    [newLayout[index], newLayout[targetIndex]] = [newLayout[targetIndex], newLayout[index]];
    updateLayout(newLayout);
  };

  const renderBlock = (key: string, index: number) => {
    const moveControls = isEditMode && (
      <div className="absolute top-4 right-4 flex gap-1 z-20">
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'up'); }} className="p-2 bg-white border border-slate-200 rounded-xl shadow-sm hover:bg-slate-50 transition-all active:scale-95" disabled={index === 0}>
          <ChevronUp size={16} className="text-slate-600" />
        </button>
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'down'); }} className="p-2 bg-white border border-slate-200 rounded-xl shadow-sm hover:bg-slate-50 transition-all active:scale-95" disabled={index === dashboardLayout.length - 1}>
          <ChevronDown size={16} className="text-slate-600" />
        </button>
      </div>
    );

    switch (key) {
      case 'balance':
        return (
          <div key={key} className="relative bg-[#2563eb] rounded-[2.5rem] p-10 text-white shadow-2xl shadow-blue-200/50 overflow-hidden">
            {moveControls}
            <div className="relative z-10 flex flex-col gap-10">
              {/* Top Row: Net Worth and Month Delta */}
              <div className="flex justify-between items-start">
                <div>
                  <p className="text-blue-100 text-xs font-bold uppercase tracking-widest mb-1">Patrimonio Neto Total</p>
                  <h2 className="text-6xl font-black">{metrics.netWorth.toLocaleString()}€</h2>
                </div>
                <div className={`px-4 py-2.5 rounded-2xl flex items-center gap-2 text-sm font-black transition-all shadow-lg bg-white/20 backdrop-blur-md`}>
                  {metrics.monthResult >= 0 ? <TrendingUp size={18} /> : <TrendingDown size={18} />}
                  {metrics.monthResult >= 0 ? '+' : ''}{metrics.monthResult.toLocaleString()}€ este mes
                  <ChevronDown size={14} className="ml-1 opacity-60" />
                </div>
              </div>

              {/* Middle Row: The Three Main Cards */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {/* Ingresos Card */}
                <div className="p-6 bg-blue-500/40 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between h-32">
                  <p className="text-[10px] font-black uppercase text-blue-100 tracking-wider">Ingresos</p>
                  <p className="text-4xl font-black">{metrics.income.toLocaleString()}€</p>
                </div>

                {/* Gastos Card */}
                <div className="p-6 bg-indigo-600/40 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between h-32 relative overflow-hidden">
                  <div>
                    <p className="text-[10px] font-black uppercase text-indigo-100 tracking-wider mb-1">Gastos</p>
                    <p className="text-4xl font-black">{metrics.expense.toLocaleString()}€</p>
                  </div>
                  {metrics.refundRecoveries > 0 && (
                    <div className="flex items-center gap-1.5 mt-2 bg-white/10 w-fit px-2 py-0.5 rounded-lg border border-white/5">
                      <TrendingDown size={12} className="text-indigo-200" />
                      <span className="text-[9px] font-bold text-indigo-100">Recuperado: {metrics.refundRecoveries}€</span>
                    </div>
                  )}
                </div>

                {/* Ahorrado Card */}
                <div className="p-6 bg-slate-400/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between h-32">
                  <p className="text-[10px] font-black uppercase text-slate-100 tracking-wider">Ahorrado</p>
                  <p className="text-4xl font-black">{metrics.monthSavings.toLocaleString()}€</p>
                </div>
              </div>

              {/* Separator Line */}
              <div className="h-px bg-white/10 w-full"></div>

              {/* Bottom Row: Detailed Metrics */}
              <div className="grid grid-cols-3 gap-8">
                <div>
                  <p className="text-[10px] text-blue-200 font-black uppercase tracking-widest mb-2">Saldo Pasado</p>
                  <p className="text-2xl font-black">{metrics.pastBalance.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[10px] text-blue-200 font-black uppercase tracking-widest mb-2">Resultado Mes</p>
                  <p className="text-2xl font-black">{metrics.monthResult.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[10px] text-blue-200 font-black uppercase tracking-widest mb-2">Total Huchas</p>
                  <p className="text-2xl font-black">{metrics.totalSavings.toLocaleString()}€</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
