import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2,
  ChevronRight,
  Sparkles,
  Loader2,
  ShoppingBag
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { generateAIChallenges } from '../services/geminiService';

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    budgets,
    currentDate,
    dashboardLayout,
    updateLayout,
    setChallenges
  } = useFinance();

  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');
  const [showBreakdown, setShowBreakdown] = useState(false);
  const [isGeneratingChallenges, setIsGeneratingChallenges] = useState(false);

  // Lógica Financiera: Reembolsos restan de gastos
  const metrics = useMemo(() => {
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));

    // Ingresos reales (que no son cobros de deudas)
    const income = monthTx
      .filter(t => t.type === 'income' && !t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    // Recuperaciones de dinero (cobros de reembolsos)
    const refundRecoveries = monthTx
      .filter(t => t.type === 'income' && t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    // Gasto Bruto
    const grossExpense = monthTx
      .filter(t => t.type === 'expense')
      .reduce((sum, t) => sum + t.amount, 0);

    // Gasto Neto (Gasto real tras recuperar reembolsos)
    const expense = Math.max(0, grossExpense - refundRecoveries);

    const monthSavings = monthTx
      .filter(t => t.category === 'Ahorro' || t.category === 'Ahorros')
      .reduce((sum, t) => sum + t.amount, 0);

    const totalLiquid = accounts.reduce((sum, acc) => sum + acc.currentBalance, 0);
    const totalSavings = savings.reduce((sum, s) => sum + s.currentAmount, 0);
    const netWorth = totalLiquid + totalSavings;

    const monthResult = income - expense; 
    const pastBalance = netWorth - monthResult;

    return {
      income,
      expense,
      refundRecoveries,
      monthSavings,
      monthResult,
      netWorth,
      totalSavings,
      pastBalance
    };
  }, [transactions, currentDate, accounts, savings]);

  // AI Challenges Auto-Evaluator
  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;

      if (ch.type === 'spending_limit') {
        const spent = monthTx
          .filter(t => t.type === 'expense' && t.category === ch.category)
          .reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavings >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.income >= ch.target;
      }

      return { ...ch, completed: isCompleted || ch.completed };
    });
  }, [challenges, transactions, currentDate, metrics]);

  // Chart Data
  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;
    return Array.from({ length: limit }, (_, i) => {
      const valBase = metrics.netWorth;
      const factor = 1 - ( (limit - 1 - i) * 0.05 ); 
      return {
        name: monthNames[i % 12],
        patrimonio: Math.round(valBase * factor)
      };
    });
