                    <p className="text-2xl font-black">{metrics.monthSavings.toLocaleString()}€</p>
                  </div>
                </div>
              )}

              {/* Separator Line */}
              <div className="h-px bg-white/10 w-full mb-6"></div>

              {/* Bottom Metrics Row */}
              <div className="grid grid-cols-3 gap-6">
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-widest mb-2">Saldo Pasado</p>
                  <p className="text-xl font-black">{metrics.pastBalance.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-widest mb-2">Resultado Mes</p>
                  <p className="text-xl font-black">{metrics.monthResult.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-widest mb-2">Total Huchas</p>
                  <p className="text-xl font-black">{metrics.totalSavings.toLocaleString()}€</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm h-full hover:shadow-md transition-shadow">
            {moveControls}
            <div className="flex items-center justify-between mb-6">
