            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Concepto</label>
                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none font-medium" placeholder="Ej: Cena con amigos..." required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Importe Total</label>
                  <input type="number" value={total} onChange={e => setTotal(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none text-lg" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Tu parte (Gasto real)</label>
                  <input type="number" value={myPart} onChange={e => setMyPart(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none text-lg" required />
