                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl active:scale-95">Crear Reembolso</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Refunds;

