            <button onClick={() => setFilter('all')} className={`px-4 py-1.5 text-[10px] font-bold rounded-xl transition-all whitespace-nowrap ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-500'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`px-4 py-1.5 text-[10px] font-bold rounded-xl transition-all whitespace-nowrap ${filter === 'income' ? 'bg-emerald-500 text-white' : 'text-slate-500'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`px-4 py-1.5 text-[10px] font-bold rounded-xl transition-all whitespace-nowrap ${filter === 'expense' ? 'bg-rose-500 text-white' : 'text-slate-500'}`}>Gastos</button>
