                <th className="px-4 md:px-8 py-4">Movimiento</th>
                <th className="px-4 md:px-8 py-4 hidden sm:table-cell">Categoría</th>
                <th className="px-4 md:px-8 py-4 text-right">Monto</th>
                <th className="px-4 md:px-8 py-4"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr key={tx.id} className="hover:bg-slate-50/80 transition-colors group">
                  <td className="px-4 md:px-8 py-4 text-[11px] font-semibold text-slate-400 whitespace-nowrap">{new Date(tx.date).toLocaleDateString()}</td>
                  <td className="px-4 md:px-8 py-4">
                    <div className="flex items-center gap-2 md:gap-4">
                      <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={16} /> : <ArrowDownRight size={16} />}
