                      <div className="min-w-0">
                        <span className="font-bold text-slate-800 text-[13px] block truncate">{tx.description}</span>
                        <div className="flex items-center gap-2">
                          {tx.refundId && <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded-md font-bold flex items-center gap-1 w-fit"><Receipt size={8} /> REEMBOLSO</span>}
                          <span className="sm:hidden px-2 py-0.5 bg-slate-100 text-slate-600 rounded-md text-[9px] font-bold uppercase">{tx.category}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 md:px-8 py-4 hidden sm:table-cell"><span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-[9px] font-black uppercase tracking-widest whitespace-nowrap">{tx.category}</span></td>
                  <td className={`px-4 md:px-8 py-4 text-right font-black text-sm md:text-base whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>{tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€</td>
                  <td className="px-4 md:px-8 py-4 text-right"><button onClick={() => { if(confirm('¿Eliminar transacción?')) deleteTransaction(tx.id); }} className="p-2 text-slate-300 hover:text-rose-500 rounded-lg opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[2.5rem] w-full max-w-md p-8 md:p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
