                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-2 hover:bg-slate-100 rounded-full"><X size={20} className="text-slate-400" /></button>
                </div>
                <form onSubmit={handleManualSubmit} className="space-y-4 md:space-y-6">
                  <div className="flex bg-slate-100 p-1 rounded-2xl">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-2.5 text-[10px] font-black rounded-xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-500' : 'text-slate-400'}`}>GASTO</button>
