                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Descripción</label>
                    <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-xl p-3 md:p-4 focus:ring-2 focus:ring-blue-500 outline-none font-medium text-sm" required />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Importe (€)</label>
                      <input type="number" value={amount} onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-xl p-3 md:p-4 font-black text-lg outline-none" required />
                    </div>
                    <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Categoría</label>
                      <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-xl p-3 md:p-4 font-bold outline-none text-sm">
                        {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="p-4 md:p-5 bg-blue-50/50 border border-blue-100 rounded-2xl space-y-4">
                    <label className="flex items-center gap-3 cursor-pointer">
                      <input type="checkbox" checked={isRefundLink} onChange={e => setIsRefundLink(e.target.checked)} className="w-4 h-4 rounded border-blue-200 text-blue-600" />
                      <span className="text-xs font-bold text-blue-800">{type === 'expense' ? '¿Crear un reembolso?' : '¿Vinculado a un reembolso?'}</span>
                    </label>
                    {isRefundLink && type === 'expense' && (
                       <div className="animate-in slide-in-from-top-2 space-y-4">
                          <label className="block">
                            <span className="text-[9px] font-bold text-blue-500 uppercase tracking-widest mb-1 block">Tu parte (Gasto real)</span>
                            <div className="relative">
                              <input type="number" value={myPart} onChange={e => setMyPart(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-white border border-blue-200 rounded-xl p-3 md:p-4 font-black outline-none focus:ring-2 focus:ring-blue-500 text-sm" placeholder="Ej: 5.00" />
                              <UserCheck className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-400" size={18} />
                            </div>
                            <p className="text-[9px] text-blue-400 mt-1">El resto se marcará como dinero que te deben.</p>
                          </label>
                       </div>
                    )}
                    {isRefundLink && type === 'income' && (
                      <select value={selectedRefundId} onChange={e => setSelectedRefundId(e.target.value)} className="w-full bg-white border border-blue-200 rounded-xl p-3 font-bold text-xs outline-none" required>
                        <option value="">-- Selecciona Reembolso --</option>
                        {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} (Pend: {r.pendingAmount}€)</option>)}
                      </select>
                    )}
                  </div>

                  <div className="flex gap-3 pt-2">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-3 md:py-4 bg-slate-100 text-slate-600 font-bold rounded-xl text-sm transition-all hover:bg-slate-200">Cancelar</button>
                    <button type="submit" className="flex-1 py-3 md:py-4 bg-blue-600 text-white font-bold rounded-xl text-sm active:scale-95 shadow-lg shadow-blue-100 transition-all hover:bg-blue-700">Confirmar</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';

const Transactions: React.FC = () => {
  const { transactions, accounts, refunds, budgets, addTransaction, deleteTransaction } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Categorías basadas en el presupuesto
  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  // Form state
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPart, setMyPart] = useState<number | ''>('');

  // Efecto para abrir modal o escáner desde QuickAdd
  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  // Actualizar categoría por defecto cuando cambien las disponibles
  useEffect(() => {
    if (availableCategories.length > 0 && !availableCategories.includes(category)) {
      setCategory(availableCategories[0]);
    }
  }, [availableCategories]);

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPart('');
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    addTransaction({
      date: date,
      amount: Number(amount),
      description: desc,
      category: category,
      type: type,
      accountId: accountId,
      isRefund: type === 'expense' && isRefundLink,
      refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
    }, type === 'expense' && isRefundLink ? (myPart === '' ? Number(amount) / 2 : Number(myPart)) : undefined);

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);
        if (results.length > 0) {
            const first = results[0];
            setDesc(first.description || '');
            setAmount(first.amount || 0);
            setDate(first.date || new Date().toISOString().split('T')[0]);
            setType(first.type === 'income' ? 'income' : 'expense');
            const matchedCat = availableCategories.find(c => c.toLowerCase() === (first.category || '').toLowerCase());
            setCategory(matchedCat || availableCategories[0]);
            setIsAdding(true);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar el ticket");
    } finally {
      setIsScanning(false);
    }
  };

  return (
