          <p className="text-slate-500 font-medium">Controla cada movimiento con precisión quirúrgica.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            {isScanning ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Camera size={18} className="text-blue-600" />}
            <span className="hidden sm:inline">Escanear Ticket</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => setIsAdding(true)} className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
