          <div className="flex items-center gap-3 bg-white px-4 py-2.5 rounded-2xl border border-slate-100 w-full md:w-[350px] shadow-sm transition-focus-within focus-within:ring-2 focus-within:ring-blue-500">
            <Search size={18} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="¿Qué buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-medium placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-100 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-400 hover:text-slate-600'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'text-slate-400 hover:text-slate-600'}`}>Gastos</button>
