    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);
        if (results.length > 0) {
            const first = results[0];
            setDesc(first.description || '');
            setAmount(first.amount || 0);
            setDate(first.date || new Date().toISOString().split('T')[0]);
            setType(first.type === 'income' ? 'income' : 'expense');
            const matchedCat = availableCategories.find(c => c.toLowerCase() === (first.category || '').toLowerCase());
            setCategory(matchedCat || availableCategories[0]);
            setIsAdding(true);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar el ticket");
    } finally {
      setIsScanning(false);
    }
  };

