import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

const Transactions: React.FC = () => {
  const { transactions, accounts, refunds, budgets, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Categorías basadas en el presupuesto
  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  // Form state
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPart, setMyPart] = useState<number | ''>('');

  // Efecto para abrir modal o escáner desde QuickAdd
  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  // Actualizar categoría por defecto cuando cambien las disponibles
  useEffect(() => {
    if (availableCategories.length > 0 && !availableCategories.includes(category)) {
      setCategory(availableCategories[0]);
    }
  }, [availableCategories]);

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPart('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(!!tx.refundId || tx.isRefund);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPart === '' ? Number(amount) / 2 : Number(myPart)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);
        if (results.length > 0) {
            const first = results[0];
            setDesc(first.description || '');
            setAmount(first.amount || 0);
            setDate(first.date || new Date().toISOString().split('T')[0]);
            setType(first.type === 'income' ? 'income' : 'expense');
            const matchedCat = availableCategories.find(c => c.toLowerCase() === (first.category || '').toLowerCase());
            setCategory(matchedCat || availableCategories[0]);
            setIsAdding(true);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar el ticket");
    } finally {
      setIsScanning(false);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setConfirmDeleteId(id);
  };

  const confirmDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    deleteTransaction(id);
    setConfirmDeleteId(null);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-2 md:px-0">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial de Transacciones</h2>
          <p className="text-slate-500 font-medium">Controla cada movimiento con precisión quirúrgica.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            {isScanning ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Camera size={18} className="text-blue-600" />}
            <span className="hidden sm:inline">Escanear Ticket</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-4 py-2.5 rounded-2xl border border-slate-100 w-full md:w-[350px] shadow-sm transition-focus-within focus-within:ring-2 focus-within:ring-blue-500">
            <Search size={18} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="¿Qué buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-medium placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-100 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-400 hover:text-slate-600'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'text-slate-400 hover:text-slate-600'}`}>Gastos</button>
          </div>
        </div>

        {/* Listado optimizado para no requerir scroll horizontal y con diseño centrado */}
        <div className="w-full">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] uppercase tracking-[0.2em] text-slate-400 font-black border-b border-slate-100">
                <th className="px-4 py-5 text-center">Fecha</th>
                <th className="px-4 py-5 text-center">Movimiento</th>
                <th className="px-4 py-5 text-center hidden sm:table-cell">Categoría</th>
                <th className="px-4 py-5 text-center">Monto</th>
                <th className="px-4 py-5 text-center w-24">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr key={tx.id} className="hover:bg-blue-50/30 transition-colors group">
                  <td className="px-4 py-5 text-[11px] font-bold text-slate-400 text-center whitespace-nowrap">
                    {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                  </td>
                  <td className="px-4 py-5">
                    <div className="flex items-center justify-center gap-3">
                      <div className={`w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0 transition-transform group-hover:scale-110 ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={18} /> : <ArrowDownRight size={18} />}
                      </div>
                      <div className="min-w-0 flex flex-col items-start">
                        <span className="font-bold text-slate-700 text-sm truncate">{tx.description}</span>
                        <div className="flex items-center gap-2 mt-0.5">
                          {tx.refundId && <span className="text-[9px] bg-blue-100 text-blue-700 px-2 py-0.5 rounded-md font-black flex items-center gap-1 w-fit shadow-sm"><Receipt size={10} /> REEMBOLSO</span>}
                          <span className="sm:hidden px-2 py-0.5 bg-slate-100 text-slate-500 rounded-md text-[9px] font-black uppercase">{tx.category}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-5 text-center hidden sm:table-cell">
                    <span className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-full text-[10px] font-black uppercase tracking-wider">
                      {tx.category}
                    </span>
                  </td>
                  <td className={`px-4 py-5 text-center font-black text-sm md:text-base whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€
                  </td>
                  <td className="px-4 py-5 text-center">
                    <div className="flex items-center justify-center gap-1">
                      {confirmDeleteId === tx.id ? (
                        <div className="flex items-center gap-1 animate-in zoom-in duration-200">
                           <button 
                             onClick={(e) => confirmDelete(e, tx.id)}
                             className="p-2 bg-rose-500 text-white rounded-lg shadow-sm hover:bg-rose-600"
                           >
                             <Check size={14} />
                           </button>
                           <button 
                             onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(null); }}
                             className="p-2 bg-slate-100 text-slate-400 rounded-lg hover:bg-slate-200"
                           >
                             <X size={14} />
                           </button>
                        </div>
                      ) : (
                        <>
                          <button 
                            onClick={(e) => { e.stopPropagation(); startEdit(tx); }}
                            className="p-2.5 text-slate-300 hover:text-blue-500 hover:bg-blue-50 rounded-xl transition-all opacity-0 group-hover:opacity-100"
                          >
                            <Edit2 size={16} />
                          </button>
                          <button 
                            onClick={(e) => handleDeleteClick(e, tx.id)} 
                            className="p-2.5 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all opacity-0 group-hover:opacity-100"
                          >
                            <Trash2 size={16} />
                          </button>
                        </>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filteredTx.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-24 text-center">
                    <div className="flex flex-col items-center opacity-30">
                      <AlertCircle size={48} className="text-slate-400 mb-4" />
                      <p className="text-slate-500 font-bold text-lg">No hay movimientos registrados</p>
                      <p className="text-slate-400 text-sm">Empieza añadiendo una nueva transacción</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 border border-slate-100">
                <div className="flex justify-between items-center mb-8">
                  <div>
                    <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingTx ? 'Editar Movimiento' : 'Registro'}</h3>
                    <p className="text-slate-400 text-sm font-medium">{editingTx ? 'Actualiza los detalles de este movimiento' : 'Añade un nuevo movimiento a tu balance'}</p>
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-3 hover:bg-slate-100 rounded-full text-slate-400 transition-colors">
                    <X size={24} />
                  </button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-6">
                  <div className="flex bg-slate-100 p-1.5 rounded-[1.5rem] shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-500' : 'text-slate-400 hover:text-slate-600'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}>INGRESO</button>
                  </div>

                  <div className="space-y-4">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Descripción del movimiento</label>
                      <input 
                        type="text" 
                        value={desc} 
                        onChange={e => setDesc(e.target.value)} 
                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-700" 
                        placeholder="Ej: Cena Vips, Nómina..." 
                        required 
                      />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Importe (€)</label>
                        <input 
                          type="number" 
                          step="0.01"
                          value={amount} 
                          onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-black text-2xl text-center outline-none focus:ring-2 focus:ring-blue-500" 
                          placeholder="0.00" 
                          required 
                        />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Fecha del movimiento</label>
                        <div className="relative">
                          <input 
                            type="date" 
                            value={date} 
                            onChange={e => setDate(e.target.value)} 
                            className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 text-center appearance-none" 
                            required 
                          />
                          <Calendar className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" size={18} />
                        </div>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Categoría</label>
                        <select 
                          value={category} 
                          onChange={e => setCategory(e.target.value)} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 appearance-none"
                        >
                          {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Cuenta / Origen</label>
                        <select 
                          value={accountId} 
                          onChange={e => setAccountId(e.target.value)} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 appearance-none"
                        >
                          {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                        </select>
                      </div>
                    </div>
                  </div>

                  {!editingTx && (
                    <div className="p-5 bg-blue-50/50 border border-blue-100 rounded-[1.5rem] space-y-4 shadow-sm">
                      <label className="flex items-center gap-3 cursor-pointer group">
                        <div className="relative flex items-center">
                          <input 
                            type="checkbox" 
                            checked={isRefundLink} 
                            onChange={e => setIsRefundLink(e.target.checked)} 
                            className="w-5 h-5 rounded-lg border-blue-200 text-blue-600 focus:ring-blue-500 transition-all cursor-pointer" 
                          />
                        </div>
                        <span className="text-xs font-black text-blue-800 uppercase tracking-wider">{type === 'expense' ? '¿Generar un reembolso?' : '¿Asociar a un reembolso?'}</span>
                      </label>

                      {isRefundLink && type === 'expense' && (
                         <div className="animate-in slide-in-from-top-2 space-y-4">
                            <label className="block">
                              <span className="text-[9px] font-black text-blue-500 uppercase tracking-[0.2em] mb-2 block">Tu parte del gasto (Gasto real)</span>
                              <div className="relative">
                                <input 
                                  type="number" 
                                  step="0.01"
                                  value={myPart} 
                                  onChange={e => setMyPart(e.target.value === '' ? '' : Number(e.target.value))} 
                                  className="w-full bg-white border border-blue-200 rounded-2xl p-4 font-black outline-none focus:ring-2 focus:ring-blue-500 text-center text-lg" 
                                  placeholder="Indica cuánto pagas tú" 
                                />
                                <UserCheck className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-300" size={18} />
                              </div>
                              <p className="text-[9px] text-blue-400 mt-2 font-bold italic text-center">Aura calculará automáticamente cuánto deben devolverte.</p>
                            </label>
                         </div>
                      )}
                      {isRefundLink && type === 'income' && (
                        <select 
                          value={selectedRefundId} 
                          onChange={e => setSelectedRefundId(e.target.value)} 
                          className="w-full bg-white border border-blue-200 rounded-2xl p-4 font-black text-xs outline-none focus:ring-2 focus:ring-blue-500" 
                          required
                        >
                          <option value="">-- Selecciona de quién cobras --</option>
                          {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} (Pend: {r.pendingAmount}€)</option>)}
                        </select>
                      )}
                    </div>
                  )}

                  <div className="flex gap-4 pt-4">
                    <button 
                      type="button" 
                      onClick={() => { setIsAdding(false); resetForm(); }} 
                      className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl text-xs uppercase tracking-widest hover:bg-slate-200 transition-all"
                    >
                      Cancelar
                    </button>
                    <button 
                      type="submit" 
                      className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl text-xs uppercase tracking-widest active:scale-95 shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all"
                    >
                      {editingTx ? 'Guardar Cambios' : 'Confirmar Movimiento'}
                    </button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

const Transactions: React.FC = () => {
  const { transactions, accounts, refunds, budgets, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Categorías basadas en el presupuesto
  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  // Form state
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPart, setMyPart] = useState<number | ''>('');

  // Efecto para abrir modal o escáner desde QuickAdd
  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  // Actualizar categoría por defecto cuando cambien las disponibles
  useEffect(() => {
    if (availableCategories.length > 0 && !availableCategories.includes(category)) {
      setCategory(availableCategories[0]);
    }
  }, [availableCategories]);

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPart('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(!!tx.refundId || tx.isRefund);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPart === '' ? Number(amount) / 2 : Number(myPart)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);
        if (results.length > 0) {
            const first = results[0];
            setDesc(first.description || '');
            setAmount(first.amount || 0);
            setDate(first.date || new Date().toISOString().split('T')[0]);
            setType(first.type === 'income' ? 'income' : 'expense');
            const matchedCat = availableCategories.find(c => c.toLowerCase() === (first.category || '').toLowerCase());
            setCategory(matchedCat || availableCategories[0]);
            setIsAdding(true);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar el ticket");
    } finally {
      setIsScanning(false);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setConfirmDeleteId(id);
  };

  const confirmDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    deleteTransaction(id);
    setConfirmDeleteId(null);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial de Transacciones</h2>
          <p className="text-slate-500 font-medium">Controla cada movimiento con precisión quirúrgica.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            {isScanning ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Camera size={18} className="text-blue-600" />}
            <span className="hidden sm:inline">Escanear Ticket</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-4 py-2.5 rounded-2xl border border-slate-100 w-full md:w-[350px] shadow-sm transition-focus-within focus-within:ring-2 focus-within:ring-blue-500">
            <Search size={18} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="¿Qué buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-medium placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-100 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-400 hover:text-slate-600'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'text-slate-400 hover:text-slate-600'}`}>Gastos</button>
          </div>
        </div>

        {/* Listado con alineación central armónica y sin texto en la columna de acciones */}
        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] uppercase tracking-[0.25em] text-slate-400 font-black border-b border-slate-100">
                <th className="px-6 py-5 text-center w-[15%]">Fecha</th>
                <th className="px-6 py-5 text-center w-[40%]">Movimiento</th>
                <th className="px-6 py-5 text-center w-[15%] hidden sm:table-cell">Categoría</th>
                <th className="px-6 py-5 text-center w-[20%]">Monto</th>
                <th className="px-6 py-5 text-center w-[10%]"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr key={tx.id} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-6 py-6 text-[11px] font-bold text-slate-400 text-center whitespace-nowrap">
                    {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' }).toUpperCase()}
                  </td>
                  <td className="px-6 py-6">
                    <div className="flex items-center justify-center gap-4">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 transition-transform group-hover:scale-110 shadow-sm ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={18} /> : <ArrowDownRight size={18} />}
                      </div>
                      <div className="min-w-0 flex flex-col items-start text-left max-w-[200px]">
                        <span className="font-bold text-slate-700 text-sm truncate w-full">{tx.description}</span>
                        <div className="flex items-center gap-2 mt-1">
                          {tx.refundId && <span className="text-[9px] bg-blue-100 text-blue-700 px-2 py-0.5 rounded-md font-black flex items-center gap-1 shadow-sm"><Receipt size={10} /> REEMBOLSO</span>}
                          <span className="sm:hidden px-2 py-0.5 bg-slate-100 text-slate-500 rounded-md text-[9px] font-black uppercase">{tx.category}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-6 text-center hidden sm:table-cell">
                    <span className="px-3 py-1.5 bg-slate-50 text-slate-500 border border-slate-100 rounded-full text-[10px] font-black uppercase tracking-wider">
                      {tx.category}
                    </span>
                  </td>
                  <td className={`px-6 py-6 text-center font-black text-sm md:text-lg whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€
                  </td>
                  <td className="px-6 py-6 text-center">
                    <div className="flex items-center justify-center gap-1">
                      {confirmDeleteId === tx.id ? (
                        <div className="flex items-center gap-1 animate-in zoom-in duration-200">
                           <button 
                             onClick={(e) => confirmDelete(e, tx.id)}
                             className="p-2 bg-rose-500 text-white rounded-lg shadow-sm hover:bg-rose-600"
                           >
                             <Check size={14} />
                           </button>
                           <button 
                             onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(null); }}
                             className="p-2 bg-slate-100 text-slate-400 rounded-lg hover:bg-slate-200"
                           >
                             <X size={14} />
                           </button>
                        </div>
                      ) : (
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={(e) => { e.stopPropagation(); startEdit(tx); }}
                            className="p-2 text-slate-300 hover:text-blue-500 hover:bg-blue-50 rounded-xl transition-all"
                          >
                            <Edit2 size={16} />
                          </button>
                          <button 
                            onClick={(e) => handleDeleteClick(e, tx.id)} 
                            className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filteredTx.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-24 text-center">
                    <div className="flex flex-col items-center opacity-30">
                      <AlertCircle size={48} className="text-slate-400 mb-4" />
                      <p className="text-slate-500 font-bold text-lg">No hay movimientos registrados</p>
                      <p className="text-slate-400 text-sm">Empieza añadiendo una nueva transacción</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 border border-slate-100">
                <div className="flex justify-between items-center mb-8">
                  <div>
                    <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingTx ? 'Editar Movimiento' : 'Registro'}</h3>
                    <p className="text-slate-400 text-sm font-medium">{editingTx ? 'Actualiza los detalles de este movimiento' : 'Añade un nuevo movimiento a tu balance'}</p>
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-3 hover:bg-slate-100 rounded-full text-slate-400 transition-colors">
                    <X size={24} />
                  </button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-6">
                  <div className="flex bg-slate-100 p-1.5 rounded-[1.5rem] shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-500' : 'text-slate-400 hover:text-slate-600'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}>INGRESO</button>
                  </div>

                  <div className="space-y-4">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Descripción del movimiento</label>
                      <input 
                        type="text" 
                        value={desc} 
                        onChange={e => setDesc(e.target.value)} 
                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-700" 
                        placeholder="Ej: Cena Vips, Nómina..." 
                        required 
                      />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Importe (€)</label>
                        <input 
                          type="number" 
                          step="0.01"
                          value={amount} 
                          onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-black text-2xl text-center outline-none focus:ring-2 focus:ring-blue-500" 
                          placeholder="0.00" 
                          required 
                        />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Fecha del movimiento</label>
                        <div className="relative">
                          <input 
                            type="date" 
                            value={date} 
                            onChange={e => setDate(e.target.value)} 
                            className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 text-center appearance-none" 
                            required 
                          />
                          <Calendar className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" size={18} />
                        </div>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Categoría</label>
                        <select 
                          value={category} 
                          onChange={e => setCategory(e.target.value)} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 appearance-none"
                        >
                          {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Cuenta / Origen</label>
                        <select 
                          value={accountId} 
                          onChange={e => setAccountId(e.target.value)} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 appearance-none"
                        >
                          {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                        </select>
                      </div>
                    </div>
                  </div>

                  {!editingTx && (
                    <div className="p-5 bg-blue-50/50 border border-blue-100 rounded-[1.5rem] space-y-4 shadow-sm">
                      <label className="flex items-center gap-3 cursor-pointer group">
                        <div className="relative flex items-center">
                          <input 
                            type="checkbox" 
                            checked={isRefundLink} 
                            onChange={e => setIsRefundLink(e.target.checked)} 
                            className="w-5 h-5 rounded-lg border-blue-200 text-blue-600 focus:ring-blue-500 transition-all cursor-pointer" 
                          />
                        </div>
                        <span className="text-xs font-black text-blue-800 uppercase tracking-wider">{type === 'expense' ? '¿Generar un reembolso?' : '¿Asociar a un reembolso?'}</span>
                      </label>

                      {isRefundLink && type === 'expense' && (
                         <div className="animate-in slide-in-from-top-2 space-y-4">
                            <label className="block">
                              <span className="text-[9px] font-black text-blue-500 uppercase tracking-[0.2em] mb-2 block">Tu parte del gasto (Gasto real)</span>
                              <div className="relative">
                                <input 
                                  type="number" 
                                  step="0.01"
                                  value={myPart} 
                                  onChange={e => setMyPart(e.target.value === '' ? '' : Number(e.target.value))} 
                                  className="w-full bg-white border border-blue-200 rounded-2xl p-4 font-black outline-none focus:ring-2 focus:ring-blue-500 text-center text-lg" 
                                  placeholder="Indica cuánto pagas tú" 
                                />
                                <UserCheck className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-300" size={18} />
                              </div>
                              <p className="text-[9px] text-blue-400 mt-2 font-bold italic text-center">Aura calculará automáticamente cuánto deben devolverte.</p>
                            </label>
                         </div>
                      )}
                      {isRefundLink && type === 'income' && (
                        <select 
                          value={selectedRefundId} 
                          onChange={e => setSelectedRefundId(e.target.value)} 
                          className="w-full bg-white border border-blue-200 rounded-2xl p-4 font-black text-xs outline-none focus:ring-2 focus:ring-blue-500" 
                          required
                        >
                          <option value="">-- Selecciona de quién cobras --</option>
                          {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} (Pend: {r.pendingAmount}€)</option>)}
                        </select>
                      )}
                    </div>
                  )}

                  <div className="flex gap-4 pt-4">
                    <button 
                      type="button" 
                      onClick={() => { setIsAdding(false); resetForm(); }} 
                      className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl text-xs uppercase tracking-widest hover:bg-slate-200 transition-all"
                    >
                      Cancelar
                    </button>
                    <button 
                      type="submit" 
                      className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl text-xs uppercase tracking-widest active:scale-95 shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all"
                    >
                      {editingTx ? 'Guardar Cambios' : 'Confirmar Movimiento'}
                    </button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

const Transactions: React.FC = () => {
  const { transactions, accounts, refunds, budgets, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Categorías basadas en el presupuesto
  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  // Form state
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPart, setMyPart] = useState<number | ''>('');

  // Efecto para abrir modal o escáner desde QuickAdd
  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  // Actualizar categoría por defecto cuando cambien las disponibles
  useEffect(() => {
    if (availableCategories.length > 0 && !availableCategories.includes(category)) {
      setCategory(availableCategories[0]);
    }
  }, [availableCategories]);

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPart('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(!!tx.refundId || tx.isRefund);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPart === '' ? Number(amount) / 2 : Number(myPart)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);
        if (results.length > 0) {
            const first = results[0];
            setDesc(first.description || '');
            setAmount(first.amount || 0);
            setDate(first.date || new Date().toISOString().split('T')[0]);
            setType(first.type === 'income' ? 'income' : 'expense');
            const matchedCat = availableCategories.find(c => c.toLowerCase() === (first.category || '').toLowerCase());
            setCategory(matchedCat || availableCategories[0]);
            setIsAdding(true);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar el ticket");
    } finally {
      setIsScanning(false);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setConfirmDeleteId(id);
  };

  const confirmDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    deleteTransaction(id);
    setConfirmDeleteId(null);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial de Transacciones</h2>
          <p className="text-slate-500 font-medium">Controla cada movimiento con precisión quirúrgica.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            {isScanning ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Camera size={18} className="text-blue-600" />}
            <span className="hidden sm:inline">Escanear Ticket</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-4 py-2.5 rounded-2xl border border-slate-100 w-full md:w-[350px] shadow-sm transition-focus-within focus-within:ring-2 focus-within:ring-blue-500">
            <Search size={18} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="¿Qué buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-medium placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-100 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-400 hover:text-slate-600'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'text-slate-400 hover:text-slate-600'}`}>Gastos</button>
          </div>
        </div>

        {/* Listado con tamaños reducidos para mejor encaje visual */}
        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-slate-50/50 text-[8px] sm:text-[9px] uppercase tracking-wider text-slate-400 font-black border-b border-slate-100">
                <th className="px-2 py-4 text-center w-[15%]">Fecha</th>
                <th className="px-2 py-4 text-center w-[35%]">Movimiento</th>
                <th className="px-2 py-4 text-center w-[15%] hidden sm:table-cell">Categoría</th>
                <th className="px-2 py-4 text-center w-[20%]">Monto</th>
                <th className="px-2 py-4 text-center w-[15%]">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr key={tx.id} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-2 py-4 text-[9px] sm:text-[10px] font-bold text-slate-400 text-center whitespace-nowrap">
                    {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' }).toUpperCase()}
                  </td>
                  <td className="px-2 py-4">
                    <div className="flex items-center justify-center gap-2 sm:gap-3">
                      <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-lg sm:rounded-xl flex items-center justify-center flex-shrink-0 transition-transform group-hover:scale-110 shadow-sm ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={14} className="sm:w-[18px]" /> : <ArrowDownRight size={14} className="sm:w-[18px]" />}
                      </div>
                      <div className="min-w-0 flex flex-col items-start text-left max-w-[150px] sm:max-w-[200px]">
                        <span className="font-bold text-slate-700 text-[11px] sm:text-sm truncate w-full">{tx.description}</span>
                        <div className="flex items-center gap-1 mt-0.5">
                          {tx.refundId && <span className="text-[7px] sm:text-[9px] bg-blue-100 text-blue-700 px-1 py-0.5 rounded font-black flex items-center gap-1 shadow-sm"><Receipt size={8} /> REEMBOLSO</span>}
                          <span className="sm:hidden px-1 py-0.5 bg-slate-100 text-slate-500 rounded text-[7px] font-black uppercase">{tx.category}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-2 py-4 text-center hidden sm:table-cell">
                    <span className="px-2 py-1 bg-slate-50 text-slate-500 border border-slate-100 rounded-full text-[8px] sm:text-[10px] font-black uppercase tracking-wider">
                      {tx.category}
                    </span>
                  </td>
                  <td className={`px-2 py-4 text-center font-black text-[11px] sm:text-base whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€
                  </td>
                  <td className="px-2 py-4 text-center">
                    <div className="flex items-center justify-center gap-0.5 sm:gap-1">
                      {confirmDeleteId === tx.id ? (
                        <div className="flex items-center gap-1 animate-in zoom-in duration-200">
                           <button 
                             onClick={(e) => confirmDelete(e, tx.id)}
                             className="p-1.5 bg-rose-500 text-white rounded-md shadow-sm hover:bg-rose-600"
                           >
                             <Check size={12} />
                           </button>
                           <button 
                             onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(null); }}
                             className="p-1.5 bg-slate-100 text-slate-400 rounded-md hover:bg-slate-200"
                           >
                             <X size={12} />
                           </button>
                        </div>
                      ) : (
                        <div className="flex items-center gap-0.5 sm:gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={(e) => { e.stopPropagation(); startEdit(tx); }}
                            className="p-2 text-slate-300 hover:text-blue-500 hover:bg-blue-50 rounded-lg transition-all"
                          >
                            <Edit2 size={14} />
                          </button>
                          <button 
                            onClick={(e) => handleDeleteClick(e, tx.id)} 
                            className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-all"
                          >
                            <Trash2 size={14} />
                          </button>
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filteredTx.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-24 text-center">
                    <div className="flex flex-col items-center opacity-30">
                      <AlertCircle size={48} className="text-slate-400 mb-4" />
                      <p className="text-slate-500 font-bold text-lg">No hay movimientos registrados</p>
                      <p className="text-slate-400 text-sm">Empieza añadiendo una nueva transacción</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 border border-slate-100">
                <div className="flex justify-between items-center mb-8">
                  <div>
                    <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingTx ? 'Editar Movimiento' : 'Registro'}</h3>
                    <p className="text-slate-400 text-sm font-medium">{editingTx ? 'Actualiza los detalles de este movimiento' : 'Añade un nuevo movimiento a tu balance'}</p>
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-3 hover:bg-slate-100 rounded-full text-slate-400 transition-colors">
                    <X size={24} />
                  </button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-6">
                  <div className="flex bg-slate-100 p-1.5 rounded-[1.5rem] shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-500' : 'text-slate-400 hover:text-slate-600'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}>INGRESO</button>
                  </div>

                  <div className="space-y-4">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Descripción del movimiento</label>
                      <input 
                        type="text" 
                        value={desc} 
                        onChange={e => setDesc(e.target.value)} 
                        className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-700" 
                        placeholder="Ej: Cena Vips, Nómina..." 
                        required 
                      />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Importe (€)</label>
                        <input 
                          type="number" 
                          step="0.01"
                          value={amount} 
                          onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-black text-2xl text-center outline-none focus:ring-2 focus:ring-blue-500" 
                          placeholder="0.00" 
                          required 
                        />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Fecha del movimiento</label>
                        <div className="relative">
                          <input 
                            type="date" 
                            value={date} 
                            onChange={e => setDate(e.target.value)} 
                            className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 text-center appearance-none" 
                            required 
                          />
                          <Calendar className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" size={18} />
                        </div>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Categoría</label>
                        <select 
                          value={category} 
                          onChange={e => setCategory(e.target.value)} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 appearance-none"
                        >
                          {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] mb-2">Cuenta / Origen</label>
                        <select 
                          value={accountId} 
                          onChange={e => setAccountId(e.target.value)} 
                          className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none focus:ring-2 focus:ring-blue-500 appearance-none"
                        >
                          {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                        </select>
                      </div>
                    </div>
                  </div>

                  {!editingTx && (
                    <div className="p-5 bg-blue-50/50 border border-blue-100 rounded-[1.5rem] space-y-4 shadow-sm">
                      <label className="flex items-center gap-3 cursor-pointer group">
                        <div className="relative flex items-center">
                          <input 
                            type="checkbox" 
                            checked={isRefundLink} 
                            onChange={e => setIsRefundLink(e.target.checked)} 
                            className="w-5 h-5 rounded-lg border-blue-200 text-blue-600 focus:ring-blue-500 transition-all cursor-pointer" 
                          />
                        </div>
                        <span className="text-xs font-black text-blue-800 uppercase tracking-wider">{type === 'expense' ? '¿Generar un reembolso?' : '¿Asociar a un reembolso?'}</span>
                      </label>

                      {isRefundLink && type === 'expense' && (
                         <div className="animate-in slide-in-from-top-2 space-y-4">
                            <label className="block">
                              <span className="text-[9px] font-black text-blue-500 uppercase tracking-[0.2em] mb-2 block">Tu parte del gasto (Gasto real)</span>
                              <div className="relative">
                                <input 
                                  type="number" 
                                  step="0.01"
                                  value={myPart} 
                                  onChange={e => setMyPart(e.target.value === '' ? '' : Number(e.target.value))} 
                                  className="w-full bg-white border border-blue-200 rounded-2xl p-4 font-black outline-none focus:ring-2 focus:ring-blue-500 text-center text-lg" 
                                  placeholder="Indica cuánto pagas tú" 
                                />
                                <UserCheck className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-300" size={18} />
                              </div>
                              <p className="text-[9px] text-blue-400 mt-2 font-bold italic text-center">Aura calculará automáticamente cuánto deben devolverte.</p>
                            </label>
                         </div>
                      )}
                      {isRefundLink && type === 'income' && (
                        <select 
                          value={selectedRefundId} 
                          onChange={e => setSelectedRefundId(e.target.value)} 
                          className="w-full bg-white border border-blue-200 rounded-2xl p-4 font-black text-xs outline-none focus:ring-2 focus:ring-blue-500" 
                          required
                        >
                          <option value="">-- Selecciona de quién cobras --</option>
                          {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} (Pend: {r.pendingAmount}€)</option>)}
                        </select>
                      )}
                    </div>
                  )}

                  <div className="flex gap-4 pt-4">
                    <button 
                      type="button" 
                      onClick={() => { setIsAdding(false); resetForm(); }} 
                      className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl text-xs uppercase tracking-widest hover:bg-slate-200 transition-all"
                    >
                      Cancelar
                    </button>
                    <button 
                      type="submit" 
                      className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl text-xs uppercase tracking-widest active:scale-95 shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all"
                    >
                      {editingTx ? 'Guardar Cambios' : 'Confirmar Movimiento'}
                    </button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import { GoogleGenAI, Type, FunctionDeclaration, GenerateContentResponse } from "@google/genai";
import { Transaction, Budget, AIChallenge } from "../types";

export const analyzeReceipt = async (base64Image: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: `Analiza esta captura de pantalla de movimientos financieros. Extrae CADA línea de transacción visible.
        Para cada línea, determina con precisión:
        1. Descripción, Monto, Fecha (YYYY-MM-DD), Categoría.
        2. Intención (intent): 
           - 'standard': Gasto o ingreso normal.
           - 'transfer': Movimiento entre dos cuentas bancarias del usuario.
           - 'savings': Dinero enviado a una hucha de ahorro.
           - 'refund': Movimiento vinculado a un préstamo o dinero que te deben/debes.
        3. Tipo (type): 'income' o 'expense'.

        Devuelve un JSON puro con un array de objetos.` }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            type: { type: Type.STRING, description: 'income or expense' },
            intent: { type: Type.STRING, description: 'standard, transfer, savings, or refund' },
            suggestedTarget: { type: Type.STRING, description: 'Nombre sugerido de la cuenta destino o hucha si aplica' }
          },
          required: ['description', 'amount', 'date', 'category', 'type', 'intent']
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

