import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check, ArrowRightLeft, PiggyBank, Sparkles } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; // Para transferencias (otra cuenta) o ahorros (hucha)
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, updateSaving } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // New Scan Review State
  const [pendingImports, setPendingImports] = useState<ScannedItem[]>([]);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  // Manual Form state
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPart, setMyPart] = useState<number | ''>('');

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPart('');
    setEditingTx(null);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPart === '' ? Number(amount) / 2 : Number(myPart)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);

        const mappedResults: ScannedItem[] = results.map((r: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          description: r.description || 'Sin descripción',
          amount: r.amount || 0,
          date: r.date || new Date().toISOString().split('T')[0],
          category: r.category || 'Varios',
          type: r.type === 'income' ? 'income' : 'expense',
          intent: r.intent || 'standard',
          accountId: accounts[0]?.id || '',
          targetId: ''
        }));

        setPendingImports(mappedResults);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar la captura");
    } finally {
      setIsScanning(false);
    }
  };

  const updatePendingItem = (id: string, updates: Partial<ScannedItem>) => {
    setPendingImports(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const confirmImports = () => {
    pendingImports.forEach(item => {
      if (item.intent === 'transfer' && item.targetId) {
        // Lógica de transferencia: dos transacciones
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia a: ${item.description}`,
          category: 'Transferencia',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia desde: ${item.description}`,
          category: 'Transferencia',
          type: 'income',
          accountId: item.targetId,
          isRefund: false
        });
      } else if (item.intent === 'savings' && item.targetId) {
        // Lógica de ahorro: gasto en cuenta, suma en hucha
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Ahorro: ${item.description}`,
          category: 'Ahorro',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        const saving = savings.find(s => s.id === item.targetId);
        if (saving) {
          updateSaving({ ...saving, currentAmount: saving.currentAmount + item.amount });
        }
      } else {
        // Standard o Refund
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: item.description,
          category: item.category,
          type: item.type,
          accountId: item.accountId,
          isRefund: item.intent === 'refund',
          refundId: item.intent === 'refund' ? item.targetId : undefined
        });
      }
    });
    setPendingImports([]);
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial de Transacciones</h2>
          <p className="text-slate-500 font-medium">Gestiona tus movimientos con inteligencia artificial.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            {isScanning ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Camera size={18} className="text-blue-600" />}
            <span className="hidden sm:inline">Escanear Captura</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      {/* Main Table */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-4 py-2.5 rounded-2xl border border-slate-100 w-full md:w-[350px] shadow-sm transition-focus-within focus-within:ring-2 focus-within:ring-blue-500">
            <Search size={18} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="¿Qué buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-medium placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-100 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-400 hover:text-slate-600'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'text-slate-400 hover:text-slate-600'}`}>Gastos</button>
          </div>
        </div>

        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-slate-50/50 text-[8px] sm:text-[9px] uppercase tracking-wider text-slate-400 font-black border-b border-slate-100">
                <th className="px-2 py-4 text-center w-[15%]">Fecha</th>
                <th className="px-2 py-4 text-center w-[35%]">Movimiento</th>
                <th className="px-2 py-4 text-center w-[15%] hidden sm:table-cell">Categoría</th>
                <th className="px-2 py-4 text-center w-[20%]">Monto</th>
                <th className="px-2 py-4 text-center w-[15%]">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr key={tx.id} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-2 py-4 text-[9px] sm:text-[10px] font-bold text-slate-400 text-center whitespace-nowrap">
                    {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' }).toUpperCase()}
                  </td>
                  <td className="px-2 py-4">
                    <div className="flex items-center justify-center gap-2 sm:gap-3">
                      <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-lg sm:rounded-xl flex items-center justify-center flex-shrink-0 transition-transform group-hover:scale-110 shadow-sm ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={14} className="sm:w-[18px]" /> : <ArrowDownRight size={14} className="sm:w-[18px]" />}
                      </div>
                      <div className="min-w-0 flex flex-col items-start text-left max-w-[150px] sm:max-w-[200px]">
                        <span className="font-bold text-slate-700 text-[11px] sm:text-sm truncate w-full">{tx.description}</span>
                        <div className="flex items-center gap-1 mt-0.5">
                          {tx.refundId && <span className="text-[7px] sm:text-[9px] bg-blue-100 text-blue-700 px-1 py-0.5 rounded font-black flex items-center gap-1 shadow-sm"><Receipt size={8} /> REEMBOLSO</span>}
                          <span className="sm:hidden px-1 py-0.5 bg-slate-100 text-slate-500 rounded text-[7px] font-black uppercase">{tx.category}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-2 py-4 text-center hidden sm:table-cell">
                    <span className="px-2 py-1 bg-slate-50 text-slate-500 border border-slate-100 rounded-full text-[8px] sm:text-[10px] font-black uppercase tracking-wider">
                      {tx.category}
                    </span>
                  </td>
                  <td className={`px-2 py-4 text-center font-black text-[11px] sm:text-base whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€
                  </td>
                  <td className="px-2 py-4 text-center">
                    <div className="flex items-center justify-center gap-0.5 sm:gap-1">
                      {confirmDeleteId === tx.id ? (
                        <div className="flex items-center gap-1 animate-in zoom-in duration-200">
                           <button onClick={(e) => { e.stopPropagation(); deleteTransaction(tx.id); setConfirmDeleteId(null); }} className="p-1.5 bg-rose-500 text-white rounded-md shadow-sm"><Check size={12} /></button>
                           <button onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(null); }} className="p-1.5 bg-slate-100 text-slate-400 rounded-md"><X size={12} /></button>
                        </div>
                      ) : (
                        <div className="flex items-center gap-0.5 sm:gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={(e) => { e.stopPropagation(); startEdit(tx); }} className="p-2 text-slate-300 hover:text-blue-500 rounded-lg"><Edit2 size={14} /></button>
                          <button onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(tx.id); }} className="p-2 text-slate-300 hover:text-rose-500 rounded-lg"><Trash2 size={14} /></button>
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* SCAN REVIEW BATCH MODAL */}
      {pendingImports.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] w-full max-w-5xl h-[85vh] flex flex-col shadow-2xl animate-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-slate-800 flex items-center gap-3">
                  <Sparkles className="text-blue-600" /> Revisión Inteligente de Aura
                </h3>
                <p className="text-slate-400 font-medium">Clasifica los movimientos detectados en tu captura.</p>
              </div>
              <button onClick={() => setPendingImports([])} className="p-4 hover:bg-slate-100 rounded-full"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-4 custom-scrollbar bg-slate-50/50">
              {pendingImports.map(item => (
                <div key={item.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row gap-6 items-center">
                  <div className="flex-1 min-w-0">
                    <input 
                      type="text" 
                      value={item.description} 
                      onChange={e => updatePendingItem(item.id, { description: e.target.value })}
                      className="text-lg font-black text-slate-800 bg-transparent border-none p-0 focus:ring-0 w-full"
                    />
                    <div className="flex gap-4 mt-2">
                       <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{item.date}</span>
                       <span className={`text-xs font-black uppercase ${item.type === 'income' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.amount}€</span>
                    </div>
                  </div>

                  <div className="flex flex-wrap items-center gap-3">
                    <div className="flex bg-slate-100 p-1 rounded-2xl">
                       <button onClick={() => updatePendingItem(item.id, { intent: 'standard' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'standard' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><Receipt size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'transfer' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'transfer' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><ArrowRightLeft size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'savings' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'savings' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><PiggyBank size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'refund' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'refund' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><UserCheck size={18}/></button>
                    </div>

                    <div className="flex flex-col gap-2 min-w-[180px]">
                       <select 
                         value={item.accountId} 
                         onChange={e => updatePendingItem(item.id, { accountId: e.target.value })}
                         className="bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5"
                       >
                         {accounts.map(acc => <option key={acc.id} value={acc.id}>Desde: {acc.name}</option>)}
                       </select>

                       {item.intent === 'transfer' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-blue-50 border-none rounded-xl text-xs font-bold p-2.5 text-blue-700 animate-in fade-in"
                          >
                            <option value="">A qué cuenta...</option>
                            {accounts.filter(acc => acc.id !== item.accountId).map(acc => <option key={acc.id} value={acc.id}>Hacia: {acc.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'savings' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-amber-50 border-none rounded-xl text-xs font-bold p-2.5 text-amber-700 animate-in fade-in"
                          >
                            <option value="">A qué hucha...</option>
                            {savings.map(s => <option key={s.id} value={s.id}>Meta: {s.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'refund' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-emerald-50 border-none rounded-xl text-xs font-bold p-2.5 text-emerald-700 animate-in fade-in"
                          >
                            <option value="">Vincular a deuda...</option>
                            {refunds.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'standard' && (
                          <select 
                            value={item.category} 
                            onChange={e => updatePendingItem(item.id, { category: e.target.value })}
                            className="bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5"
                          >
                            {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                          </select>
                       )}
                    </div>
                  </div>

                  <button 
                    onClick={() => setPendingImports(prev => prev.filter(p => p.id !== item.id))}
                    className="p-3 text-rose-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl"
                  >
                    <Trash2 size={20} />
                  </button>
                </div>
              ))}
            </div>

            <div className="p-8 border-t border-slate-100 flex justify-end gap-4">
               <button onClick={() => setPendingImports([])} className="px-8 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl">DESCARTAR</button>
               <button onClick={confirmImports} className="px-12 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-200">IMPORTAR MOVIMIENTOS</button>
            </div>
          </div>
        </div>
      )}

      {/* Manual Add Modal */}
      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 border border-slate-100">
                <div className="flex justify-between items-center mb-8">
                  <div>
                    <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingTx ? 'Editar Movimiento' : 'Registro'}</h3>
                    <p className="text-slate-400 text-sm font-medium">{editingTx ? 'Actualiza los detalles' : 'Nuevo movimiento manual'}</p>
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-3 hover:bg-slate-100 rounded-full text-slate-400"><X size={24} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-6">
                  <div className="flex bg-slate-100 p-1.5 rounded-[1.5rem] shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-500' : 'text-slate-400 hover:text-slate-600'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}>INGRESO</button>
                  </div>

                  <div className="space-y-4">
                    <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold" placeholder="Descripción..." required />
                    <div className="grid grid-cols-2 gap-4">
                      <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-black text-2xl" placeholder="0.00" required />
                      <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold" required />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold">
                        {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                      <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold">
                        {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="flex gap-4 pt-4">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl">CANCELAR</button>
                    <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl">CONFIRMAR</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check, ArrowRightLeft, PiggyBank, Sparkles } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; // Para transferencias (otra cuenta) o ahorros (hucha)
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, updateSaving } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // New Scan Review State
  const [pendingImports, setPendingImports] = useState<ScannedItem[]>([]);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  // Manual Form state
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPart, setMyPart] = useState<number | ''>('');

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPart('');
    setEditingTx(null);
  };

  // Fix: Added startEdit function to handle editing an existing transaction
  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPart === '' ? Number(amount) / 2 : Number(myPart)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);

        const mappedResults: ScannedItem[] = results.map((r: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          description: r.description || 'Sin descripción',
          amount: r.amount || 0,
          date: r.date || new Date().toISOString().split('T')[0],
          category: r.category || 'Varios',
          type: r.type === 'income' ? 'income' : 'expense',
          intent: r.intent || 'standard',
          accountId: accounts[0]?.id || '',
          targetId: ''
        }));

        setPendingImports(mappedResults);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar la captura");
    } finally {
      setIsScanning(false);
    }
  };

  const updatePendingItem = (id: string, updates: Partial<ScannedItem>) => {
    setPendingImports(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const confirmImports = () => {
    pendingImports.forEach(item => {
      if (item.intent === 'transfer' && item.targetId) {
        // Lógica de transferencia: dos transacciones
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia a: ${item.description}`,
          category: 'Transferencia',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia desde: ${item.description}`,
          category: 'Transferencia',
          type: 'income',
          accountId: item.targetId,
          isRefund: false
        });
      } else if (item.intent === 'savings' && item.targetId) {
        // Lógica de ahorro: gasto en cuenta, suma en hucha
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Ahorro: ${item.description}`,
          category: 'Ahorro',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        const saving = savings.find(s => s.id === item.targetId);
        if (saving) {
          updateSaving({ ...saving, currentAmount: saving.currentAmount + item.amount });
        }
      } else {
        // Standard o Refund
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: item.description,
          category: item.category,
          type: item.type,
          accountId: item.accountId,
          isRefund: item.intent === 'refund',
          refundId: item.intent === 'refund' ? item.targetId : undefined
        });
      }
    });
    setPendingImports([]);
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial de Transacciones</h2>
          <p className="text-slate-500 font-medium">Gestiona tus movimientos con inteligencia artificial.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            {isScanning ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Camera size={18} className="text-blue-600" />}
            <span className="hidden sm:inline">Escanear Captura</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      {/* Main Table */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-4 py-2.5 rounded-2xl border border-slate-100 w-full md:w-[350px] shadow-sm transition-focus-within focus-within:ring-2 focus-within:ring-blue-500">
            <Search size={18} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="¿Qué buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-medium placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-100 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-400 hover:text-slate-600'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'text-slate-400 hover:text-slate-600'}`}>Gastos</button>
          </div>
        </div>

        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-slate-50/50 text-[8px] sm:text-[9px] uppercase tracking-wider text-slate-400 font-black border-b border-slate-100">
                <th className="px-2 py-4 text-center w-[15%]">Fecha</th>
                <th className="px-2 py-4 text-center w-[35%]">Movimiento</th>
                <th className="px-2 py-4 text-center w-[15%] hidden sm:table-cell">Categoría</th>
                <th className="px-2 py-4 text-center w-[20%]">Monto</th>
                <th className="px-2 py-4 text-center w-[15%]">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr key={tx.id} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-2 py-4 text-[9px] sm:text-[10px] font-bold text-slate-400 text-center whitespace-nowrap">
                    {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' }).toUpperCase()}
                  </td>
                  <td className="px-2 py-4">
                    <div className="flex items-center justify-center gap-2 sm:gap-3">
                      <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-lg sm:rounded-xl flex items-center justify-center flex-shrink-0 transition-transform group-hover:scale-110 shadow-sm ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={14} className="sm:w-[18px]" /> : <ArrowDownRight size={14} className="sm:w-[18px]" />}
                      </div>
                      <div className="min-w-0 flex flex-col items-start text-left max-w-[150px] sm:max-w-[200px]">
                        <span className="font-bold text-slate-700 text-[11px] sm:text-sm truncate w-full">{tx.description}</span>
                        <div className="flex items-center gap-1 mt-0.5">
                          {tx.refundId && <span className="text-[7px] sm:text-[9px] bg-blue-100 text-blue-700 px-1 py-0.5 rounded font-black flex items-center gap-1 shadow-sm"><Receipt size={8} /> REEMBOLSO</span>}
                          <span className="sm:hidden px-1 py-0.5 bg-slate-100 text-slate-500 rounded text-[7px] font-black uppercase">{tx.category}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-2 py-4 text-center hidden sm:table-cell">
                    <span className="px-2 py-1 bg-slate-50 text-slate-500 border border-slate-100 rounded-full text-[8px] sm:text-[10px] font-black uppercase tracking-wider">
                      {tx.category}
                    </span>
                  </td>
                  <td className={`px-2 py-4 text-center font-black text-[11px] sm:text-base whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€
                  </td>
                  <td className="px-2 py-4 text-center">
                    <div className="flex items-center justify-center gap-0.5 sm:gap-1">
                      {confirmDeleteId === tx.id ? (
                        <div className="flex items-center gap-1 animate-in zoom-in duration-200">
                           <button onClick={(e) => { e.stopPropagation(); deleteTransaction(tx.id); setConfirmDeleteId(null); }} className="p-1.5 bg-rose-500 text-white rounded-md shadow-sm"><Check size={12} /></button>
                           <button onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(null); }} className="p-1.5 bg-slate-100 text-slate-400 rounded-md"><X size={12} /></button>
                        </div>
                      ) : (
                        <div className="flex items-center gap-0.5 sm:gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={(e) => { e.stopPropagation(); startEdit(tx); }} className="p-2 text-slate-300 hover:text-blue-500 rounded-lg"><Edit2 size={14} /></button>
                          <button onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(tx.id); }} className="p-2 text-slate-300 hover:text-rose-500 rounded-lg"><Trash2 size={14} /></button>
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* SCAN REVIEW BATCH MODAL */}
      {pendingImports.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] w-full max-w-5xl h-[85vh] flex flex-col shadow-2xl animate-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-slate-800 flex items-center gap-3">
                  <Sparkles className="text-blue-600" /> Revisión Inteligente de Aura
                </h3>
                <p className="text-slate-400 font-medium">Clasifica los movimientos detectados en tu captura.</p>
              </div>
              <button onClick={() => setPendingImports([])} className="p-4 hover:bg-slate-100 rounded-full"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-4 custom-scrollbar bg-slate-50/50">
              {pendingImports.map(item => (
                <div key={item.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row gap-6 items-center">
                  <div className="flex-1 min-w-0">
                    <input 
                      type="text" 
                      value={item.description} 
                      onChange={e => updatePendingItem(item.id, { description: e.target.value })}
                      className="text-lg font-black text-slate-800 bg-transparent border-none p-0 focus:ring-0 w-full"
                    />
                    <div className="flex gap-4 mt-2">
                       <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{item.date}</span>
                       <span className={`text-xs font-black uppercase ${item.type === 'income' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.amount}€</span>
                    </div>
                  </div>

                  <div className="flex flex-wrap items-center gap-3">
                    <div className="flex bg-slate-100 p-1 rounded-2xl">
                       <button onClick={() => updatePendingItem(item.id, { intent: 'standard' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'standard' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><Receipt size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'transfer' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'transfer' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><ArrowRightLeft size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'savings' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'savings' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><PiggyBank size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'refund' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'refund' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><UserCheck size={18}/></button>
                    </div>

                    <div className="flex flex-col gap-2 min-w-[180px]">
                       <select 
                         value={item.accountId} 
                         onChange={e => updatePendingItem(item.id, { accountId: e.target.value })}
                         className="bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5"
                       >
                         {accounts.map(acc => <option key={acc.id} value={acc.id}>Desde: {acc.name}</option>)}
                       </select>

                       {item.intent === 'transfer' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-blue-50 border-none rounded-xl text-xs font-bold p-2.5 text-blue-700 animate-in fade-in"
                          >
                            <option value="">A qué cuenta...</option>
                            {accounts.filter(acc => acc.id !== item.accountId).map(acc => <option key={acc.id} value={acc.id}>Hacia: {acc.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'savings' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-amber-50 border-none rounded-xl text-xs font-bold p-2.5 text-amber-700 animate-in fade-in"
                          >
                            <option value="">A qué hucha...</option>
                            {savings.map(s => <option key={s.id} value={s.id}>Meta: {s.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'refund' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-emerald-50 border-none rounded-xl text-xs font-bold p-2.5 text-emerald-700 animate-in fade-in"
                          >
                            <option value="">Vincular a deuda...</option>
                            {refunds.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'standard' && (
                          <select 
                            value={item.category} 
                            onChange={e => updatePendingItem(item.id, { category: e.target.value })}
                            className="bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5"
                          >
                            {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                          </select>
                       )}
                    </div>
                  </div>

                  <button 
                    onClick={() => setPendingImports(prev => prev.filter(p => p.id !== item.id))}
                    className="p-3 text-rose-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl"
                  >
                    <Trash2 size={20} />
                  </button>
                </div>
              ))}
            </div>

            <div className="p-8 border-t border-slate-100 flex justify-end gap-4">
               <button onClick={() => setPendingImports([])} className="px-8 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl">DESCARTAR</button>
               <button onClick={confirmImports} className="px-12 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-200">IMPORTAR MOVIMIENTOS</button>
            </div>
          </div>
        </div>
      )}

      {/* Manual Add Modal */}
      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 border border-slate-100">
                <div className="flex justify-between items-center mb-8">
                  <div>
                    <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingTx ? 'Editar Movimiento' : 'Registro'}</h3>
                    <p className="text-slate-400 text-sm font-medium">{editingTx ? 'Actualiza los detalles' : 'Nuevo movimiento manual'}</p>
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-3 hover:bg-slate-100 rounded-full text-slate-400"><X size={24} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-6">
                  <div className="flex bg-slate-100 p-1.5 rounded-[1.5rem] shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-500' : 'text-slate-400 hover:text-slate-600'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}>INGRESO</button>
                  </div>

                  <div className="space-y-4">
                    <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold" placeholder="Descripción..." required />
                    <div className="grid grid-cols-2 gap-4">
                      <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-black text-2xl" placeholder="0.00" required />
                      <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold" required />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold">
                        {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                      <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold">
                        {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="flex gap-4 pt-4">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl">CANCELAR</button>
                    <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl">CONFIRMAR</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check, ArrowRightLeft, PiggyBank, Sparkles } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; // Para transferencias (otra cuenta) o ahorros (hucha)
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, updateSaving } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // New Scan Review State
  const [pendingImports, setPendingImports] = useState<ScannedItem[]>([]);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  // Manual Form state
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPart, setMyPart] = useState<number | ''>('');

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPart('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPart === '' ? Number(amount) / 2 : Number(myPart)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);

        const mappedResults: ScannedItem[] = results.map((r: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          description: r.description || 'Sin descripción',
          amount: r.amount || 0,
          date: r.date || new Date().toISOString().split('T')[0],
          category: r.category || 'Varios',
          type: r.type === 'income' ? 'income' : 'expense',
          intent: r.intent || 'standard',
          accountId: accounts[0]?.id || '',
          targetId: ''
        }));

        setPendingImports(mappedResults);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar la captura");
      setIsScanning(false);
    }
  };

  const updatePendingItem = (id: string, updates: Partial<ScannedItem>) => {
    setPendingImports(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const confirmImports = () => {
    pendingImports.forEach(item => {
      if (item.intent === 'transfer' && item.targetId) {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia a: ${item.description}`,
          category: 'Transferencia',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia desde: ${item.description}`,
          category: 'Transferencia',
          type: 'income',
          accountId: item.targetId,
          isRefund: false
        });
      } else if (item.intent === 'savings' && item.targetId) {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Ahorro: ${item.description}`,
          category: 'Ahorro',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        const saving = savings.find(s => s.id === item.targetId);
        if (saving) {
          updateSaving({ ...saving, currentAmount: saving.currentAmount + item.amount });
        }
      } else {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: item.description,
          category: item.category,
          type: item.type,
          accountId: item.accountId,
          isRefund: item.intent === 'refund',
          refundId: item.intent === 'refund' ? item.targetId : undefined
        });
      }
    });
    setPendingImports([]);
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Global Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[70] flex flex-col items-center justify-center">
          <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in duration-300 border border-slate-100 max-w-sm w-full mx-4">
            <div className="w-20 h-20 bg-blue-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-blue-200 animate-pulse">
              <Sparkles size={40} />
            </div>
            <div className="text-center">
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Aura está analizando...</h3>
              <p className="text-slate-500 text-sm font-medium mt-2 leading-relaxed">Extrayendo cada detalle de tu captura para tu gestión financiera.</p>
            </div>
            <div className="flex items-center gap-2 text-blue-600 font-bold uppercase tracking-[0.2em] text-[10px]">
              <Loader2 size={16} className="animate-spin" />
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial de Transacciones</h2>
          <p className="text-slate-500 font-medium">Gestiona tus movimientos con inteligencia artificial.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            <Camera size={18} className="text-blue-600" />
            <span className="hidden sm:inline">Escanear Captura</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-5 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      {/* Main Table */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-4 py-2.5 rounded-2xl border border-slate-100 w-full md:w-[350px] shadow-sm transition-focus-within focus-within:ring-2 focus-within:ring-blue-500">
            <Search size={18} className="text-slate-400" />
            <input 
              type="text" 
              placeholder="¿Qué buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-medium placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-100 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-400 hover:text-slate-600'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 md:flex-none px-5 py-2 text-xs font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'text-slate-400 hover:text-slate-600'}`}>Gastos</button>
          </div>
        </div>

        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-slate-50/50 text-[8px] sm:text-[9px] uppercase tracking-wider text-slate-400 font-black border-b border-slate-100">
                <th className="px-2 py-4 text-center w-[15%]">Fecha</th>
                <th className="px-2 py-4 text-center w-[35%]">Movimiento</th>
                <th className="px-2 py-4 text-center w-[15%] hidden sm:table-cell">Categoría</th>
                <th className="px-2 py-4 text-center w-[20%]">Monto</th>
                <th className="px-2 py-4 text-center w-[15%]">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr key={tx.id} className="hover:bg-blue-50/20 transition-colors group">
                  <td className="px-2 py-4 text-[9px] sm:text-[10px] font-bold text-slate-400 text-center whitespace-nowrap">
                    {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' }).toUpperCase()}
                  </td>
                  <td className="px-2 py-4">
                    <div className="flex items-center justify-center gap-2 sm:gap-3">
                      <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-lg sm:rounded-xl flex items-center justify-center flex-shrink-0 transition-transform group-hover:scale-110 shadow-sm ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={14} className="sm:w-[18px]" /> : <ArrowDownRight size={14} className="sm:w-[18px]" />}
                      </div>
                      <div className="min-w-0 flex flex-col items-start text-left max-w-[150px] sm:max-w-[200px]">
                        <span className="font-bold text-slate-700 text-[11px] sm:text-sm truncate w-full">{tx.description}</span>
                        <div className="flex items-center gap-1 mt-0.5">
                          {tx.refundId && <span className="text-[7px] sm:text-[9px] bg-blue-100 text-blue-700 px-1 py-0.5 rounded font-black flex items-center gap-1 shadow-sm"><Receipt size={8} /> REEMBOLSO</span>}
                          <span className="sm:hidden px-1 py-0.5 bg-slate-100 text-slate-500 rounded text-[7px] font-black uppercase">{tx.category}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-2 py-4 text-center hidden sm:table-cell">
                    <span className="px-2 py-1 bg-slate-50 text-slate-500 border border-slate-100 rounded-full text-[8px] sm:text-[10px] font-black uppercase tracking-wider">
                      {tx.category}
                    </span>
                  </td>
                  <td className={`px-2 py-4 text-center font-black text-[14px] sm:text-xl whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€
                  </td>
                  <td className="px-2 py-4 text-center">
                    <div className="flex items-center justify-center gap-0.5 sm:gap-1">
                      {confirmDeleteId === tx.id ? (
                        <div className="flex items-center gap-1 animate-in zoom-in duration-200">
                           <button onClick={(e) => { e.stopPropagation(); deleteTransaction(tx.id); setConfirmDeleteId(null); }} className="p-1.5 bg-rose-500 text-white rounded-md shadow-sm"><Check size={12} /></button>
                           <button onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(null); }} className="p-1.5 bg-slate-100 text-slate-400 rounded-md"><X size={12} /></button>
                        </div>
                      ) : (
                        <div className="flex items-center gap-0.5 sm:gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={(e) => { e.stopPropagation(); startEdit(tx); }} className="p-2 text-slate-300 hover:text-blue-500 rounded-lg"><Edit2 size={14} /></button>
                          <button onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(tx.id); }} className="p-2 text-slate-300 hover:text-rose-500 rounded-lg"><Trash2 size={14} /></button>
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* SCAN REVIEW BATCH MODAL */}
      {pendingImports.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] w-full max-w-5xl h-[85vh] flex flex-col shadow-2xl animate-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-slate-800 flex items-center gap-3">
                  <Sparkles className="text-blue-600" /> Revisión Inteligente de Aura
                </h3>
                <p className="text-slate-400 font-medium">Clasifica los movimientos detectados en tu captura.</p>
              </div>
              <button onClick={() => setPendingImports([])} className="p-4 hover:bg-slate-100 rounded-full"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-4 custom-scrollbar bg-slate-50/50">
              {pendingImports.map(item => (
                <div key={item.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row gap-6 items-center">
                  <div className="flex-1 min-w-0">
                    <input 
                      type="text" 
                      value={item.description} 
                      onChange={e => updatePendingItem(item.id, { description: e.target.value })}
                      className="text-lg font-black text-slate-800 bg-transparent border-none p-0 focus:ring-0 w-full"
                    />
                    <div className="flex gap-4 mt-2">
                       <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{item.date}</span>
                       <span className={`text-lg font-black uppercase ${item.type === 'income' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.amount}€</span>
                    </div>
                  </div>

                  <div className="flex flex-wrap items-center gap-3">
                    <div className="flex bg-slate-100 p-1 rounded-2xl">
                       <button onClick={() => updatePendingItem(item.id, { intent: 'standard' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'standard' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><Receipt size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'transfer' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'transfer' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><ArrowRightLeft size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'savings' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'savings' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><PiggyBank size={18}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'refund' })} className={`p-2.5 rounded-xl transition-all ${item.intent === 'refund' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}><UserCheck size={18}/></button>
                    </div>

                    <div className="flex flex-col gap-2 min-w-[200px]">
                       <select 
                         value={item.accountId} 
                         onChange={e => updatePendingItem(item.id, { accountId: e.target.value })}
                         className="bg-slate-100/50 border border-slate-200 rounded-xl text-xs font-black p-2.5 text-slate-700 focus:bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                       >
                         {accounts.map(acc => <option key={acc.id} value={acc.id}>Desde: {acc.name}</option>)}
                       </select>

                       {item.intent === 'transfer' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-blue-50 border border-blue-200 rounded-xl text-xs font-black p-2.5 text-blue-700 animate-in fade-in focus:bg-white outline-none"
                          >
                            <option value="">A qué cuenta...</option>
                            {accounts.filter(acc => acc.id !== item.accountId).map(acc => <option key={acc.id} value={acc.id}>Hacia: {acc.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'savings' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-amber-50 border border-amber-200 rounded-xl text-xs font-black p-2.5 text-amber-700 animate-in fade-in focus:bg-white outline-none"
                          >
                            <option value="">A qué hucha...</option>
                            {savings.map(s => <option key={s.id} value={s.id}>Meta: {s.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'refund' && (
                          <select 
                            value={item.targetId} 
                            onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                            className="bg-emerald-50 border border-emerald-200 rounded-xl text-xs font-black p-2.5 text-emerald-700 animate-in fade-in focus:bg-white outline-none"
                          >
                            <option value="">Vincular a deuda...</option>
                            {refunds.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                          </select>
                       )}

                       {item.intent === 'standard' && (
                          <select 
                            value={item.category} 
                            onChange={e => updatePendingItem(item.id, { category: e.target.value })}
                            className="bg-slate-100/50 border border-slate-200 rounded-xl text-xs font-black p-2.5 text-slate-700 focus:bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                          >
                            {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                          </select>
                       )}
                    </div>
                  </div>

                  <button 
                    onClick={() => setPendingImports(prev => prev.filter(p => p.id !== item.id))}
                    className="p-3 text-rose-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-colors"
                  >
                    <Trash2 size={20} />
                  </button>
                </div>
              ))}
            </div>

            <div className="p-8 border-t border-slate-100 flex justify-end gap-4">
               <button onClick={() => setPendingImports([])} className="px-8 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl active:scale-95 transition-all">DESCARTAR</button>
               <button onClick={confirmImports} className="px-12 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-200 active:scale-95 transition-all">IMPORTAR MOVIMIENTOS</button>
            </div>
          </div>
        </div>
      )}

      {/* Manual Add Modal */}
      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 border border-slate-100">
                <div className="flex justify-between items-center mb-8">
                  <div>
                    <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingTx ? 'Editar Movimiento' : 'Registro'}</h3>
                    <p className="text-slate-400 text-sm font-medium">{editingTx ? 'Actualiza los detalles' : 'Nuevo movimiento manual'}</p>
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-3 hover:bg-slate-100 rounded-full text-slate-400"><X size={24} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-6">
                  <div className="flex bg-slate-100 p-1.5 rounded-[1.5rem] shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-500' : 'text-slate-400 hover:text-slate-600'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 text-[11px] font-black rounded-xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-500' : 'text-slate-400 hover:text-slate-600'}`}>INGRESO</button>
                  </div>

                  <div className="space-y-4">
                    <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold" placeholder="Descripción..." required />
                    <div className="grid grid-cols-2 gap-4">
                      <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-black text-2xl" placeholder="0.00" required />
                      <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold" required />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold">
                        {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                      <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold">
                        {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                      </select>
                    </div>
                  </div>

                  <div className="flex gap-4 pt-4">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl">CANCELAR</button>
                    <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl">CONFIRMAR</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check, ArrowRightLeft, PiggyBank, Sparkles, ChevronDown } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; 
  myPart?: number; // Para cuando el gasto es un reembolso
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, updateSaving } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const [pendingImports, setPendingImports] = useState<ScannedItem[]>([]);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  // Form states con mejor visibilidad
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPartManual('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);

        const mappedResults: ScannedItem[] = results.map((r: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          description: r.description || 'Sin descripción',
          amount: r.amount || 0,
          date: r.date || new Date().toISOString().split('T')[0],
          category: r.category || 'Varios',
          type: r.type === 'income' ? 'income' : 'expense',
          intent: r.intent || 'standard',
          accountId: accounts[0]?.id || '',
          targetId: '',
          myPart: (r.amount || 0) / 2
        }));

        setPendingImports(mappedResults);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar la captura");
      setIsScanning(false);
    }
  };

  const updatePendingItem = (id: string, updates: Partial<ScannedItem>) => {
    setPendingImports(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const confirmImports = () => {
    pendingImports.forEach(item => {
      if (item.intent === 'transfer' && item.targetId) {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia a: ${item.description}`,
          category: 'Transferencia',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia desde: ${item.description}`,
          category: 'Transferencia',
          type: 'income',
          accountId: item.targetId,
          isRefund: false
        });
      } else if (item.intent === 'savings' && item.targetId) {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Ahorro: ${item.description}`,
          category: 'Ahorro',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        const saving = savings.find(s => s.id === item.targetId);
        if (saving) {
          updateSaving({ ...saving, currentAmount: saving.currentAmount + item.amount });
        }
      } else {
        // Handle normal and REFUND logic for Scanned Items
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: item.description,
          category: item.category,
          type: item.type,
          accountId: item.accountId,
          isRefund: item.type === 'expense' && item.intent === 'refund',
          refundId: item.type === 'income' && item.intent === 'refund' ? item.targetId : undefined
        }, item.type === 'expense' && item.intent === 'refund' ? item.myPart : undefined);
      }
    });
    setPendingImports([]);
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Global Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[70] flex flex-col items-center justify-center">
          <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in duration-300 border border-slate-100 max-w-sm w-full mx-4">
            <div className="w-20 h-20 bg-blue-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-blue-200 animate-pulse">
