                  )}

                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-700 font-black rounded-2xl active:scale-95 transition-all">CANCELAR</button>
                    <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100 active:scale-95 transition-all">{editingTx ? 'GUARDAR' : 'CONFIRMAR'}</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check, ArrowRightLeft, PiggyBank, Sparkles, ChevronDown, Info, Wallet } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; 
  myPart?: number; 
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, updateSaving } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const [pendingImports, setPendingImports] = useState<ScannedItem[]>([]);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPartManual('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
    setViewingTx(null);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);

        const mappedResults: ScannedItem[] = results.map((r: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          description: r.description || 'Sin descripción',
          amount: r.amount || 0,
          date: r.date || new Date().toISOString().split('T')[0],
          category: r.category || 'Varios',
          type: r.type === 'income' ? 'income' : 'expense',
          intent: r.intent || 'standard',
          accountId: accounts[0]?.id || '',
          targetId: '',
          myPart: (r.amount || 0) / 2
        }));

        setPendingImports(mappedResults);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar la captura");
      setIsScanning(false);
    }
  };

  const updatePendingItem = (id: string, updates: Partial<ScannedItem>) => {
    setPendingImports(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const confirmImports = () => {
    pendingImports.forEach(item => {
      if (item.intent === 'transfer' && item.targetId) {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia a: ${item.description}`,
          category: 'Transferencia',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia desde: ${item.description}`,
          category: 'Transferencia',
          type: 'income',
          accountId: item.targetId,
          isRefund: false
        });
      } else if (item.intent === 'savings' && item.targetId) {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Ahorro: ${item.description}`,
          category: 'Ahorro',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        const saving = savings.find(s => s.id === item.targetId);
        if (saving) {
          updateSaving({ ...saving, currentAmount: saving.currentAmount + item.amount });
        }
      } else {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: item.description,
          category: item.category,
          type: item.type,
          accountId: item.accountId,
          isRefund: item.type === 'expense' && item.intent === 'refund',
          refundId: item.type === 'income' && item.intent === 'refund' ? item.targetId : undefined
        }, item.type === 'expense' && item.intent === 'refund' ? item.myPart : undefined);
      }
    });
    setPendingImports([]);
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  // Helper to shorten long standard names
  const shortenDescription = (desc: string) => {
    return desc
      .replace(/Ahorro en hucha/gi, 'Ahorro Hucha')
      .replace(/Transferencia de/gi, 'Trf. De')
      .replace(/Transferencia a/gi, 'Trf. A');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Global Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[70] flex flex-col items-center justify-center">
          <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in duration-300 border border-slate-100 max-w-sm w-full mx-4">
            <div className="w-20 h-20 bg-blue-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-blue-200 animate-pulse">
              <Sparkles size={40} />
            </div>
            <div className="text-center">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Aura está analizando...</h3>
              <p className="text-slate-600 text-sm font-medium mt-2 leading-relaxed">Extrayendo detalles financieros con IA avanzada.</p>
            </div>
            <div className="flex items-center gap-2 text-blue-600 font-black uppercase tracking-[0.2em] text-[10px]">
              <Loader2 size={16} className="animate-spin" />
              <span>Procesando imagen</span>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial de Transacciones</h2>
          <p className="text-slate-600 font-medium font-bold">Cada movimiento bajo el radar de Aura.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-6 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            <Camera size={18} className="text-blue-600" />
            <span className="hidden sm:inline">Escanear Captura</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      {/* Main Table - Rediseñada para alineación vertical perfecta */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-5 py-3 rounded-2xl border border-slate-200 w-full md:w-[350px] shadow-sm focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <Search size={18} className="text-slate-500" />
            <input 
              type="text" 
              placeholder="¿Qué transacción buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-200 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-6 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-6 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-600 hover:text-slate-800'}`}>Ingresos</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 md:flex-none px-6 py-2 text-xs font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'text-slate-600 hover:text-slate-800'}`}>Gastos</button>
          </div>
        </div>

        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-slate-50/50 text-[9px] sm:text-[10px] uppercase tracking-[0.15em] text-slate-500 font-black border-b border-slate-100">
                <th className="px-4 py-5 text-left w-[15%]">Fecha</th>
                <th className="px-4 py-5 text-left w-[45%]">Movimiento</th>
                <th className="px-4 py-5 text-center w-[20%]">Monto</th>
                <th className="px-4 py-5 text-right w-[20%]"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => (
                <tr 
                  key={tx.id} 
                  onClick={() => setViewingTx(tx)}
                  className="hover:bg-blue-50/20 transition-all group cursor-pointer"
                >
                  <td className="px-4 py-5 text-[10px] sm:text-[11px] font-black text-slate-500 text-left whitespace-nowrap">
                    {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' }).toUpperCase()}
                  </td>
                  <td className="px-4 py-5">
                    <div className="flex items-center gap-3 sm:gap-4">
                      <div className={`w-9 h-9 sm:w-11 sm:h-11 rounded-xl flex items-center justify-center flex-shrink-0 shadow-sm ${tx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {tx.type === 'income' ? <ArrowUpRight size={18} /> : <ArrowDownRight size={18} />}
                      </div>
                      <div className="min-w-0 flex flex-col">
                        <span className="font-black text-slate-800 text-[12px] sm:text-sm truncate max-w-[120px] sm:max-w-[250px] leading-tight">
                          {shortenDescription(tx.description)}
                        </span>
                        <span className="text-[9px] font-black text-slate-500 uppercase tracking-wider mt-0.5">{tx.category}</span>
                      </div>
                    </div>
                  </td>
                  <td className={`px-4 py-5 text-center font-black text-[14px] sm:text-xl whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString()}€
                  </td>
                  <td className="px-4 py-5 text-right">
                    <div className="flex items-center justify-end gap-1">
                      {confirmDeleteId === tx.id ? (
                        <div className="flex items-center gap-1 animate-in zoom-in duration-200">
                           <button onClick={(e) => { e.stopPropagation(); deleteTransaction(tx.id); setConfirmDeleteId(null); }} className="p-2 bg-rose-500 text-white rounded-lg shadow-lg shadow-rose-100"><Check size={14} /></button>
                           <button onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(null); }} className="p-2 bg-slate-200 text-slate-700 rounded-lg"><X size={14} /></button>
                        </div>
                      ) : (
                        <div className="flex items-center gap-1 sm:opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={(e) => { e.stopPropagation(); startEdit(tx); }} className="p-2.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"><Edit2 size={16} /></button>
                          <button onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(tx.id); }} className="p-2.5 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all"><Trash2 size={16} /></button>
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredTx.length === 0 && (
            <div className="py-20 text-center flex flex-col items-center gap-4">
               <div className="w-16 h-16 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center"><AlertCircle size={32} /></div>
               <p className="text-slate-400 font-bold italic uppercase tracking-widest text-[10px]">No hay movimientos que coincidan</p>
            </div>
          )}
        </div>
      </div>

      {/* MODAL DE DETALLES COMPLETOS (Para textos largos) */}
      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[80] flex items-center justify-center p-4" onClick={() => setViewingTx(null)}>
          <div className="bg-white rounded-[3rem] w-full max-w-md p-8 shadow-2xl animate-in zoom-in duration-300 border border-slate-100" onClick={e => e.stopPropagation()}>
            <div className="flex flex-col items-center text-center gap-6">
              <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-lg ${viewingTx.type === 'income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                {viewingTx.type === 'income' ? <ArrowUpRight size={40} /> : <ArrowDownRight size={40} />}
              </div>

              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{viewingTx.category}</p>
                <h3 className="text-2xl font-black text-slate-900 leading-tight">{viewingTx.description}</h3>
              </div>

              <div className="w-full bg-slate-50 rounded-[2rem] p-6 space-y-4">
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Importe</span>
                  <span className={`text-3xl font-black ${viewingTx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {viewingTx.type === 'income' ? '+' : '-'}{Math.abs(viewingTx.amount).toLocaleString()}€
                  </span>
                </div>
                <div className="h-px bg-slate-200 w-full"></div>
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Fecha</span>
                  <span className="font-black text-slate-800 flex items-center gap-2"><Calendar size={14} /> {new Date(viewingTx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'long', year: 'numeric' })}</span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Cuenta</span>
                  <span className="font-black text-slate-800 flex items-center gap-2">
                    <Wallet size={14} /> {accounts.find(a => a.id === viewingTx.accountId)?.name || 'Cuenta Desconocida'}
                  </span>
                </div>
                {viewingTx.refundId && (
                  <div className="flex justify-between items-center pt-2">
                    <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 px-3 py-1 rounded-full border border-blue-100">Vínculo Reembolso</span>
                    <span className="font-bold text-blue-800 text-xs">#{viewingTx.refundId.substring(0, 8)}</span>
                  </div>
                )}
              </div>

              <div className="flex gap-4 w-full">
                <button onClick={() => setViewingTx(null)} className="flex-1 py-5 bg-slate-100 text-slate-600 font-black rounded-2xl active:scale-95 transition-all">CERRAR</button>
                <button onClick={() => startEdit(viewingTx)} className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100 active:scale-95 transition-all flex items-center justify-center gap-2">
                  <Edit2 size={18} /> EDITAR
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* SCAN REVIEW BATCH MODAL */}
      {pendingImports.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/85 backdrop-blur-2xl z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3.5rem] w-full max-w-6xl h-[88vh] flex flex-col shadow-2xl animate-in zoom-in duration-300">
            <div className="p-8 md:p-10 border-b border-slate-100 flex justify-between items-center bg-slate-50/50 rounded-t-[3.5rem]">
              <div>
                <h3 className="text-3xl font-black text-slate-900 flex items-center gap-4 tracking-tight">
                  <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-100">
                    <Sparkles size={24} />
                  </div>
                  Aura: Confirmación de Lote
                </h3>
                <p className="text-slate-600 font-bold mt-1 text-sm">Asegúrate de que cada línea sea correcta antes de importar.</p>
              </div>
              <button onClick={() => setPendingImports([])} className="p-4 hover:bg-slate-200 rounded-full text-slate-500 transition-colors"><X size={28} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 md:p-10 space-y-6 custom-scrollbar bg-white">
              {pendingImports.map(item => (
                <div key={item.id} className="bg-white p-6 md:p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-sm flex flex-col xl:flex-row gap-8 items-center transition-all hover:border-blue-100 hover:shadow-xl">
                  <div className="flex-1 min-w-0 w-full">
                    <input 
                      type="text" 
                      value={item.description} 
                      onChange={e => updatePendingItem(item.id, { description: e.target.value })}
                      className="text-xl font-black text-slate-900 bg-transparent border-none p-0 focus:ring-0 w-full tracking-tight"
                    />
                    <div className="flex gap-4 mt-3">
                       <span className="text-xs font-black text-slate-500 uppercase tracking-widest bg-slate-100 px-3 py-1 rounded-lg">{item.date}</span>
                       <span className={`text-2xl font-black uppercase ${item.type === 'income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                         {item.type === 'income' ? '+' : '-'}{Math.abs(item.amount).toLocaleString()}€
                       </span>
                    </div>
                  </div>

                  <div className="flex flex-wrap items-center gap-4 w-full xl:w-auto">
                    <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
                       <button onClick={() => updatePendingItem(item.id, { intent: 'standard' })} className={`p-3 rounded-xl transition-all flex items-center gap-2 ${item.intent === 'standard' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`} title="Gasto Normal"><Receipt size={20}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'transfer' })} className={`p-3 rounded-xl transition-all flex items-center gap-2 ${item.intent === 'transfer' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`} title="Transferencia"><ArrowRightLeft size={20}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'savings' })} className={`p-3 rounded-xl transition-all flex items-center gap-2 ${item.intent === 'savings' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`} title="Ahorro/Inversión"><PiggyBank size={20}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'refund' })} className={`p-3 rounded-xl transition-all flex items-center gap-2 ${item.intent === 'refund' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`} title="Reembolso/Deuda"><UserCheck size={20}/></button>
                    </div>

                    <div className="flex flex-col gap-3 min-w-[220px] flex-1">
                       <div className="space-y-1">
                         <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest pl-2">Origen/Cuenta</label>
                         <select 
                           value={item.accountId} 
                           onChange={e => updatePendingItem(item.id, { accountId: e.target.value })}
                           className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl text-[11px] font-black p-3 text-slate-900 focus:bg-white focus:border-blue-300 outline-none transition-all appearance-none cursor-pointer"
                         >
                           {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.currentBalance}€)</option>)}
                         </select>
                       </div>

                       {item.intent === 'transfer' && (
                          <div className="animate-in slide-in-from-top-2 space-y-1">
                             <label className="text-[9px] font-black text-blue-600 uppercase tracking-widest pl-2">Destino</label>
                             <select 
                               value={item.targetId} 
                               onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                               className="w-full bg-blue-50 border-2 border-blue-200 rounded-xl text-[11px] font-black p-3 text-blue-800 focus:bg-white focus:border-blue-400 outline-none transition-all"
                             >
                               <option value="">¿A qué cuenta va?</option>
                               {accounts.filter(acc => acc.id !== item.accountId).map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                             </select>
                          </div>
                       )}

                       {item.intent === 'savings' && (
                          <div className="animate-in slide-in-from-top-2 space-y-1">
                             <label className="text-[9px] font-black text-amber-600 uppercase tracking-widest pl-2">Meta de Ahorro</label>
                             <select 
                               value={item.targetId} 
                               onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                               className="w-full bg-amber-50 border-2 border-amber-200 rounded-xl text-[11px] font-black p-3 text-amber-900 focus:bg-white focus:border-amber-400 outline-none transition-all"
                             >
                               <option value="">¿A qué hucha?</option>
                               {savings.map(s => <option key={s.id} value={s.id}>{s.name} ({s.currentAmount}€)</option>)}
                             </select>
                          </div>
                       )}

                       {item.intent === 'refund' && (
                          <div className="animate-in slide-in-from-top-2 space-y-2">
                            {item.type === 'expense' ? (
                              <>
                                <label className="text-[9px] font-black text-blue-600 uppercase tracking-widest pl-2 block">Opciones Reembolso</label>
                                <div className="bg-blue-50/50 p-4 rounded-xl border-2 border-blue-100">
                                   <label className="text-[8px] font-black text-blue-400 uppercase tracking-widest block mb-2">Tu parte (Gasto real)</label>
                                   <input 
                                     type="number" 
                                     value={item.myPart}
                                     onChange={e => updatePendingItem(item.id, { myPart: Number(e.target.value) })}
                                     className="w-full bg-white border border-blue-200 rounded-lg p-2 font-black text-center text-blue-700 focus:ring-2 focus:ring-blue-400 outline-none"
                                   />
                                </div>
                              </>
                            ) : (
                              <>
                                <label className="text-[9px] font-black text-emerald-600 uppercase tracking-widest pl-2 block">Vincular a deuda</label>
                                <select 
                                  value={item.targetId} 
                                  onChange={e => updatePendingItem(item.id, { targetId: e.target.value })}
                                  className="w-full bg-emerald-50 border-2 border-emerald-200 rounded-xl text-[11px] font-black p-3 text-emerald-900 focus:bg-white focus:border-emerald-400 outline-none"
                                >
                                  <option value="">¿Quién te ha pagado?</option>
                                  {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} (Pend: {r.pendingAmount}€)</option>)}
                                </select>
                              </>
                            )}
                          </div>
                       )}

                       {item.intent === 'standard' && (
                          <div className="animate-in slide-in-from-top-2 space-y-1">
                             <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest pl-2">Categoría Presupuesto</label>
                             <select 
                               value={item.category} 
                               onChange={e => updatePendingItem(item.id, { category: e.target.value })}
                               className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl text-[11px] font-black p-3 text-slate-900 focus:bg-white focus:border-blue-200 outline-none appearance-none"
                             >
                               {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                             </select>
                          </div>
                       )}
                    </div>
                  </div>

                  <button 
                    onClick={() => setPendingImports(prev => prev.filter(p => p.id !== item.id))}
                    className="p-4 text-rose-300 hover:text-rose-600 hover:bg-rose-50 rounded-2xl transition-all"
                  >
                    <Trash2 size={24} />
                  </button>
                </div>
              ))}
            </div>

            <div className="p-8 md:p-10 border-t border-slate-100 flex justify-end gap-4 bg-slate-50/50 rounded-b-[3.5rem]">
               <button onClick={() => setPendingImports([])} className="px-10 py-5 bg-white border border-slate-200 text-slate-700 font-black rounded-2xl shadow-sm">DESCARTAR TODO</button>
               <button onClick={confirmImports} className="px-16 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl active:scale-95 transition-all flex items-center gap-3">
                 <Check size={24} /> IMPORTAR {pendingImports.length} MOVIMIENTOS
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Manual Add Modal con contraste mejorado */}
      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/75 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-10 md:p-14 shadow-2xl animate-in zoom-in duration-300 border border-slate-200">
                <div className="flex justify-between items-center mb-10">
                  <div>
                    <h3 className="text-3xl font-black text-slate-900 tracking-tight">{editingTx ? 'Editar Movimiento' : 'Nuevo Registro'}</h3>
                    <p className="text-slate-600 text-sm font-bold mt-1">Ingresa los detalles manualmente.</p>
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-4 hover:bg-slate-100 rounded-full text-slate-400 transition-colors"><X size={28} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 p-2 rounded-[1.8rem] shadow-inner border border-slate-200">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-600' : 'text-slate-500 hover:text-slate-700'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500 hover:text-slate-700'}`}>INGRESO</button>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3 pl-1">Descripción</label>
                      <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold text-slate-900 placeholder:text-slate-300 focus:bg-white focus:border-blue-400 transition-all outline-none" placeholder="¿En qué has gastado?" required />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3 pl-1">Importe (€)</label>
                        <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-black text-2xl text-slate-900 placeholder:text-slate-300 focus:bg-white focus:border-blue-400 transition-all outline-none" placeholder="0.00" required />
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3 pl-1">Fecha</label>
                        <div className="relative">
                          <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold text-slate-900 focus:bg-white focus:border-blue-400 transition-all outline-none appearance-none" required />
                          <Calendar size={18} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                        </div>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3 pl-1">Categoría</label>
                        <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold text-slate-900 focus:bg-white focus:border-blue-400 transition-all outline-none cursor-pointer appearance-none">
                          {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3 pl-1">Cuenta</label>
                        <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold text-slate-900 focus:bg-white focus:border-blue-400 transition-all outline-none cursor-pointer appearance-none">
                          {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                        </select>
                      </div>
                    </div>
                  </div>

                  {!editingTx && (
                    <div className="p-6 bg-blue-50/50 border-2 border-blue-100 rounded-[2rem] space-y-5">
                      <label className="flex items-center gap-3 cursor-pointer group">
                        <input 
                          type="checkbox" 
                          checked={isRefundLink} 
                          onChange={e => setIsRefundLink(e.target.checked)} 
                          className="w-6 h-6 rounded-lg border-blue-300 text-blue-600 focus:ring-blue-500 transition-all" 
                        />
                        <span className="text-xs font-black text-blue-900 uppercase tracking-widest">{type === 'expense' ? 'Generar Reembolso' : 'Vincular a Reembolso'}</span>
                      </label>

                      {isRefundLink && (
                        <div className="animate-in slide-in-from-top-2">
                          {type === 'expense' ? (
                            <div className="space-y-3">
                              <label className="block text-[10px] font-black text-blue-700 uppercase tracking-widest pl-1">Tu parte del gasto (€)</label>
                              <input 
                                type="number" 
                                value={myPartManual} 
                                onChange={e => setMyPartManual(Number(e.target.value))}
                                className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-black text-blue-800 outline-none text-center" 
                                placeholder="Indica cuánto pagas tú"
                              />
                            </div>
                          ) : (
                            <select 
                              value={selectedRefundId} 
                              onChange={e => setSelectedRefundId(e.target.value)} 
                              className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-black text-blue-800 outline-none"
                            >
                              <option value="">Selecciona quién te pagó</option>
                              {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} (Pendiente: {r.pendingAmount}€)</option>)}
                            </select>
                          )}
                        </div>
                      )}
                    </div>
                  )}

                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-700 font-black rounded-2xl active:scale-95 transition-all">CANCELAR</button>
                    <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100 active:scale-95 transition-all">{editingTx ? 'GUARDAR' : 'CONFIRMAR'}</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { Plus, Search, Camera, ArrowUpRight, ArrowDownRight, Trash2, Edit2, Loader2, X, Receipt, UserCheck, Calendar, AlertCircle, Check, ArrowRightLeft, PiggyBank, Sparkles, ChevronDown, Info, Wallet } from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { CATEGORIES } from '../constants';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; 
  myPart?: number; 
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, updateSaving } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const [pendingImports, setPendingImports] = useState<ScannedItem[]>([]);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const availableCategories = useMemo(() => {
    const budgetCats = budgets.map(b => b.category);
    return budgetCats.length > 0 ? budgetCats : CATEGORIES.map(c => c.name);
  }, [budgets]);

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState(availableCategories[0] || '');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPartManual('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleDeleteFromModal = (id: string) => {
    deleteTransaction(id);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: type === 'expense' && isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);

        const mappedResults: ScannedItem[] = results.map((r: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          description: r.description || 'Sin descripción',
          amount: r.amount || 0,
          date: r.date || new Date().toISOString().split('T')[0],
          category: r.category || 'Varios',
          type: r.type === 'income' ? 'income' : 'expense',
          intent: r.intent || 'standard',
          accountId: accounts[0]?.id || '',
          targetId: '',
          myPart: (r.amount || 0) / 2
        }));

        setPendingImports(mappedResults);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar la captura");
      setIsScanning(false);
    }
  };

  const updatePendingItem = (id: string, updates: Partial<ScannedItem>) => {
    setPendingImports(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const confirmImports = () => {
    pendingImports.forEach(item => {
      if (item.intent === 'transfer' && item.targetId) {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia a: ${item.description}`,
          category: 'Transferencia',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Transferencia desde: ${item.description}`,
          category: 'Transferencia',
          type: 'income',
          accountId: item.targetId,
          isRefund: false
        });
      } else if (item.intent === 'savings' && item.targetId) {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: `Ahorro: ${item.description}`,
          category: 'Ahorro',
          type: 'expense',
          accountId: item.accountId,
          isRefund: false
        });
        const saving = savings.find(s => s.id === item.targetId);
        if (saving) {
          updateSaving({ ...saving, currentAmount: saving.currentAmount + item.amount });
        }
      } else {
        addTransaction({
          date: item.date,
          amount: item.amount,
          description: item.description,
          category: item.category,
          type: item.type,
          accountId: item.accountId,
          isRefund: item.type === 'expense' && item.intent === 'refund',
          refundId: item.type === 'income' && item.intent === 'refund' ? item.targetId : undefined
        }, item.type === 'expense' && item.intent === 'refund' ? item.myPart : undefined);
      }
    });
    setPendingImports([]);
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filter === 'all' || t.type === filter;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const shortenDescription = (desc: string) => {
    return desc
      .replace(/Ahorro en hucha/gi, 'Ahorro Hucha')
      .replace(/Transferencia de/gi, 'Trf. De')
      .replace(/Transferencia a/gi, 'Trf. A');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Global Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[70] flex flex-col items-center justify-center">
          <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in duration-300 border border-slate-100 max-w-sm w-full mx-4">
            <div className="w-20 h-20 bg-blue-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-blue-200 animate-pulse">
              <Sparkles size={40} />
            </div>
            <div className="text-center">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Aura está analizando...</h3>
              <p className="text-slate-600 text-sm font-medium mt-2 leading-relaxed">Extrayendo detalles financieros con IA avanzada.</p>
            </div>
            <div className="flex items-center gap-2 text-blue-600 font-black uppercase tracking-[0.2em] text-[10px]">
              <Loader2 size={16} className="animate-spin" />
              <span>Procesando imagen</span>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Historial de Transacciones</h2>
          <p className="text-slate-600 font-bold">Pulsa en cualquier transacción para ver el detalle completo.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-6 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            <Camera size={18} className="text-blue-600" />
            <span className="hidden sm:inline">Escanear Captura</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nueva Transacción</span>
          </button>
        </div>
      </div>

      {/* Main Table - Lista Nativa */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3 bg-white px-5 py-3 rounded-2xl border border-slate-200 w-full md:w-[350px] shadow-sm focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <Search size={18} className="text-slate-500" />
            <input 
              type="text" 
              placeholder="¿Qué transacción buscas?" 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-200 shadow-sm w-full md:w-auto">
            <button onClick={() => setFilter('all')} className={`flex-1 md:flex-none px-6 py-2 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>Todos</button>
            <button onClick={() => setFilter('income')} className={`flex-1 md:flex-none px-6 py-2 text-xs font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'text-slate-600 hover:text-slate-800'}`}>Ingresos</button>
