                <form onSubmit={handleManualSubmit} className="space-y-8 overflow-y-auto max-h-[70vh] pr-2 custom-scrollbar">
                  <div className="flex bg-slate-100 p-2 rounded-[1.8rem] shadow-inner border border-slate-200">
