                    {/* Selector de Intención */}
                    <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
                       <button onClick={() => updatePendingItem(item.id, { intent: 'standard' })} className={`p-3 rounded-xl transition-all flex items-center gap-2 ${item.intent === 'standard' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`} title="Gasto/Ingreso Estándar"><Receipt size={20}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'transfer' })} className={`p-3 rounded-xl transition-all flex items-center gap-2 ${item.intent === 'transfer' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`} title="Traspaso entre cuentas"><ArrowRightLeft size={20}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'savings' })} className={`p-3 rounded-xl transition-all flex items-center gap-2 ${item.intent === 'savings' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`} title="Ahorro en hucha"><PiggyBank size={20}/></button>
                       <button onClick={() => updatePendingItem(item.id, { intent: 'refund' })} className={`p-3 rounded-xl transition-all flex items-center gap-2 ${item.intent === 'refund' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`} title="Reembolso/Deuda"><UserCheck size={20}/></button>
