                    className="p-2.5 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>

              <div className="space-y-5">
                <div className="flex justify-between items-end">
                   <div>
                      <p className={`text-4xl font-black tracking-tight ${activeTab === 'expense' && progress > 100 ? 'text-rose-500' : 'text-slate-900'}`}>
                        {b.spent.toLocaleString('es-ES')}€
                      </p>
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">de {b.limit.toLocaleString()}€ {activeTab === 'expense' ? 'permitidos' : 'objetivo'}</p>
                   </div>
                   <div className="text-right">
                      <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider ${
                        activeTab === 'expense' 
                        ? (progress > 100 ? 'bg-rose-50 text-rose-500' : progress > 80 ? 'bg-amber-50 text-amber-500' : 'bg-emerald-50 text-emerald-500')
                        : (progress >= 100 ? 'bg-emerald-50 text-emerald-500' : 'bg-blue-50 text-blue-500')
                      }`}>
                        {activeTab === 'expense' 
                          ? (progress > 100 ? 'Excedido' : progress > 80 ? 'Cerca del límite' : 'Bajo control') 
                          : (progress >= 100 ? 'Objetivo logrado' : 'En progreso')}
                      </span>
                   </div>
                </div>

                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                  <div 
                    className={`h-full rounded-full transition-all duration-1000 ease-out ${
                      activeTab === 'expense'
                      ? (progress >= 100 ? 'bg-rose-500' : progress > 80 ? 'bg-amber-400' : 'bg-blue-500')
                      : (progress >= 100 ? 'bg-emerald-500' : 'bg-blue-500')
                    }`} 
                    style={{ width: `${progress}%` }}
                  ></div>
                </div>

                <div className="flex items-center justify-between">
                   <p className="text-xs text-slate-400 font-bold flex items-center gap-1">
                     <ChevronRight size={14} className="text-blue-500" /> Ver movimientos
                   </p>
                   {activeTab === 'expense' && (
                     <p className="text-xs font-black text-slate-700">
                        {b.limit - b.spent > 0 ? `Restan ${(b.limit - b.spent).toLocaleString()}€` : 'Límite superado'}
                     </p>
                   )}
                </div>
              </div>
            </div>
          );
        })}
        {filteredBudgets.length === 0 && (
          <div className="col-span-full py-20 bg-white rounded-[3rem] border border-dashed border-slate-200 flex flex-col items-center justify-center gap-4">
             <div className="w-16 h-16 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center"><AlertCircle size={32} /></div>
             <p className="text-slate-400 font-bold italic uppercase tracking-widest text-xs">No hay presupuestos de {activeTab === 'expense' ? 'gastos' : 'ingresos'} para este mes.</p>
             <button onClick={openCreate} className="text-blue-600 font-black text-sm hover:underline">Crear el primero</button>
          </div>
        )}
      </div>

      {/* Detail Transactions Modal */}
      {selectedBudget && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4" onClick={() => setSelectedBudget(null)}>
          <div className="bg-white rounded-[3.5rem] w-full max-w-2xl p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-8">
               <div className="flex items-center gap-4">
                 <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${selectedBudget.type === 'expense' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                    <ShoppingBag size={24} />
                 </div>
                 <div>
                   <h3 className="text-2xl font-black text-slate-800 tracking-tight">{selectedBudget.category}</h3>
                   <p className="text-xs text-slate-500 font-bold uppercase tracking-widest flex items-center gap-2">
                     <Calendar size={14} /> Movimientos de {currentDate}
                   </p>
                 </div>
               </div>
               <button onClick={() => setSelectedBudget(null)} className="p-3 hover:bg-slate-100 rounded-full text-slate-400">
                 <X size={24} />
               </button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-3">
              {budgetTransactions.length > 0 ? (
                budgetTransactions.map(t => (
                  <div key={t.id} className="flex items-center justify-between p-5 bg-slate-50 rounded-[1.8rem] border border-slate-100 hover:bg-white hover:shadow-md transition-all border-l-4 border-l-blue-500">
                    <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${t.type === 'income' ? 'bg-emerald-50 text-emerald-500' : 'bg-rose-50 text-rose-500'}`}>
                        {t.type === 'income' ? <ArrowDownLeft size={18} /> : <ArrowUpRight size={18} />}
                      </div>
                      <div>
                        <p className="text-sm font-black text-slate-800 line-clamp-1">{t.description}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(t.date).toLocaleDateString()}</p>
                      </div>
                    </div>
                    <p className={`text-lg font-black ${t.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                      {t.type === 'income' ? '+' : '-'}{t.amount.toLocaleString()}€
                    </p>
                  </div>
                ))
              ) : (
                <div className="py-12 text-center text-slate-400">
                   <p className="font-bold italic">No se han registrado movimientos en esta categoría para {currentDate}.</p>
                </div>
              )}
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 flex justify-between items-center">
               <div className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Resumen Categoría</div>
               <div className="text-right">
                 <p className="text-xs font-bold text-slate-500">Total {selectedBudget.type === 'expense' ? 'Gastado' : 'Ingresado'}</p>
                 <p className="text-2xl font-black text-blue-600">{selectedBudget.spent.toLocaleString()}€</p>
               </div>
            </div>
          </div>
        </div>
      )}

      {/* Create / Edit Modal */}
      {(isCreating || isEditing) && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">{isEditing ? 'Editar Presupuesto' : 'Nuevo Límite'}</h3>
              <button onClick={() => { setIsCreating(false); setIsEditing(null); }} className="p-2 hover:bg-slate-100 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <form onSubmit={handleSave} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">Categoría de {activeTab === 'expense' ? 'Gasto' : 'Ingreso'}</label>
                <select 
                  value={category} 
                  onChange={e => setCategory(e.target.value)}
                  className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 font-bold text-slate-800 focus:bg-white focus:border-blue-400 outline-none transition-all appearance-none cursor-pointer"
                  required
                >
                  {(activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES).map(c => (
                    <option key={c.name} value={c.name}>{c.name}</option>
                  ))}
                  <option value="Otra">Otra...</option>
                </select>
                {category === 'Otra' && (
                  <input 
                    type="text" 
                    placeholder="Escribe el nombre de la categoría..." 
                    className="mt-3 w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 font-bold outline-none" 
                    onChange={e => setCategory(e.target.value)}
                    required
                  />
                )}
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">Límite Mensual (€)</label>
                <input 
                  type="number" 
                  value={limit} 
                  onChange={e => setLimit(e.target.value === '' ? '' : Number(e.target.value))}
                  className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 text-center text-4xl font-black text-slate-900 placeholder:text-slate-300 focus:bg-white focus:border-blue-400 transition-all outline-none" 
                  placeholder="0"
                  required 
                  autoFocus
                />
                <p className="mt-3 text-[10px] text-slate-400 font-bold text-center uppercase tracking-widest">Presupuesto para {currentDate}</p>
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  type="button" 
                  onClick={() => { setIsCreating(false); setIsEditing(null); }} 
                  className="flex-1 py-5 bg-slate-100 text-slate-600 font-black rounded-2xl hover:bg-slate-200 transition-all active:scale-95"
                >
                  CANCELAR
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  {isEditing ? 'GUARDAR' : 'CREAR'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetManager;

import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Wallet, 
  PiggyBank, 
  Receipt, 
  BarChart3, 
  MessageSquare,
  ChevronLeft,
  ChevronRight,
  Menu,
  X,
  Plus,
  Camera
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';

interface FinanceContextType extends FinanceState {
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon'>) => void;
  updateBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  changeMonth: (offset: number) => void;
  setMonth: (date: string) => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<FinanceState>(() => {
    const saved = localStorage.getItem('finance_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('finance_data', JSON.stringify(state));
  }, [state]);

  const contextValue: FinanceContextType = {
    ...state,
    addTransaction: (t, myPart) => {
      const id = Math.random().toString(36).substr(2, 9);
      const newTransaction = { ...t, id };

      setState(prev => {
        let updatedRefunds = [...prev.refunds];

        if (t.type === 'expense' && t.isRefund) {
          const refundId = 'ref_' + Date.now();
          const partToPay = myPart !== undefined ? myPart : t.amount / 2;
          updatedRefunds.push({
            id: refundId,
            name: t.description,
            totalAmount: t.amount,
            paidByMe: partToPay, 
            pendingAmount: t.amount - partToPay, 
            status: (t.amount - partToPay) <= 0 ? 'closed' : 'open',
            notes: 'Creado desde gasto: ' + t.description,
            date: t.date,
            originTransactionId: id
          });
          newTransaction.refundId = refundId;
        }

        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = Math.max(0, r.pendingAmount - t.amount);
              return { ...r, pendingAmount: newPending, status: newPending <= 0 ? 'closed' : 'open' };
            }
            return r;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? t.amount : -t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        const budgets = prev.budgets.map(b => {
          if (t.type === b.type && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: b.spent + t.amount };
          }
          return b;
        });

        return {
          ...prev,
          transactions: [newTransaction, ...prev.transactions],
          accounts,
          budgets,
          refunds: updatedRefunds
        };
      });
    },
    updateTransaction: (updatedTx) => {
      setState(prev => {
        const oldTx = prev.transactions.find(t => t.id === updatedTx.id);
        if (!oldTx) return prev;

        const accounts = prev.accounts.map(acc => {
          let balance = acc.currentBalance;
          if (acc.id === oldTx.accountId) {
            balance -= (oldTx.type === 'income' ? oldTx.amount : -oldTx.amount);
          }
          if (acc.id === updatedTx.accountId) {
            balance += (updatedTx.type === 'income' ? updatedTx.amount : -updatedTx.amount);
          }
          return { ...acc, currentBalance: balance };
        });

        const budgets = prev.budgets.map(b => {
          let spent = b.spent;
          if (oldTx.type === b.type && b.category === oldTx.category && oldTx.date.startsWith(prev.currentDate)) {
            spent -= oldTx.amount;
          }
          if (updatedTx.type === b.type && b.category === updatedTx.category && updatedTx.date.startsWith(prev.currentDate)) {
            spent += updatedTx.amount;
          }
          return { ...b, spent: Math.max(0, spent) };
        });

        return {
          ...prev,
          transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t),
          accounts,
          budgets
        };
      });
    },
    deleteTransaction: (id) => {
      setState(prev => {
        const t = prev.transactions.find(tx => tx.id === id);
        if (!t) return prev;

        let updatedRefunds = [...prev.refunds];
        updatedRefunds = updatedRefunds.filter(r => r.originTransactionId !== id);

        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = r.pendingAmount + t.amount;
              return { ...r, pendingAmount: newPending, status: 'open' };
            }
            return r;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? -t.amount : t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        const budgets = prev.budgets.map(b => {
          if (t.type === b.type && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: Math.max(0, b.spent - t.amount) };
          }
          return b;
        });

        return {
          ...prev,
          transactions: prev.transactions.filter(tx => tx.id !== id),
          accounts,
          refunds: updatedRefunds,
          budgets
        };
      });
    },
    addAccount: (a) => {
      const id = 'acc_' + Date.now();
      setState(prev => ({
        ...prev,
        accounts: [...prev.accounts, { ...a, id, currentBalance: a.initialBalance }]
      }));
    },
    updateAccount: (a) => {
      setState(prev => ({
        ...prev,
        accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc)
      }));
    },
    deleteAccount: (id) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) }));
    },
    addSaving: (s) => {
      const id = 'sav_' + Date.now();
      setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id }] }));
    },
    updateSaving: (s) => {
      setState(prev => ({
        ...prev,
        savings: prev.savings.map(sv => sv.id === s.id ? s : sv)
      }));
    },
    deleteSaving: (id) => {
      setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) }));
    },
    addRefund: (r) => {
      const id = 'ref_' + Date.now();
      setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id }] }));
    },
    updateRefund: (r) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf)
      }));
    },
    deleteRefund: (id) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.filter(r => r.id !== id),
        transactions: prev.transactions.map(t => t.refundId === id ? { ...t, refundId: undefined, isRefund: false } : t)
      }));
    },
    mergeRefunds: (id1, id2) => {
      setState(prev => {
        const r1 = prev.refunds.find(r => r.id === id1);
        const r2 = prev.refunds.find(r => r.id === id2);
        if (!r1 || !r2) return prev;

        const newId = 'ref_merged_' + Date.now();
        const mergedRefund: Refund = {
          id: newId,
          name: `${r1.name} + ${r2.name}`,
          totalAmount: r1.totalAmount + r2.totalAmount,
          paidByMe: r1.paidByMe + r2.paidByMe,
          pendingAmount: r1.pendingAmount + r2.pendingAmount,
          status: (r1.pendingAmount + r2.pendingAmount) > 0 ? 'open' : 'closed',
          notes: `Unificado desde "${r1.name}" y "${r2.name}".\nNotas R1: ${r1.notes}\nNotas R2: ${r2.notes}`,
          date: new Date().toISOString().split('T')[0]
        };

        return {
          ...prev,
          refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), mergedRefund],
          transactions: prev.transactions.map(t => 
            (t.refundId === id1 || t.refundId === id2) ? { ...t, refundId: newId } : t
          )
        };
      });
    },
    addBudget: (b) => {
      const id = 'budget_' + Date.now();
      const monthTx = state.transactions.filter(t => t.date.startsWith(state.currentDate) && t.type === b.type && t.category === b.category);
      const spent = monthTx.reduce((sum, t) => sum + t.amount, 0);

      setState(prev => ({
        ...prev,
        budgets: [...prev.budgets, { ...b, id, spent, icon: 'ShoppingBag' }]
      }));
    },
    updateBudget: (updatedBudget) => {
      setState(prev => {
        // Recalcular spent/income al actualizar para que refleje la realidad de la categoría (en caso de que cambie el nombre)
        const monthTx = prev.transactions.filter(t => t.date.startsWith(prev.currentDate) && t.type === updatedBudget.type && t.category === updatedBudget.category);
        const spent = monthTx.reduce((sum, t) => sum + t.amount, 0);

        return {
          ...prev,
          budgets: prev.budgets.map(bg => bg.id === updatedBudget.id ? { ...updatedBudget, spent } : bg)
        };
      });
    },
    deleteBudget: (id) => {
      setState(prev => ({
        ...prev,
        budgets: prev.budgets.filter(b => b.id !== id)
      }));
    },
    changeMonth: (offset) => {
      setState(prev => {
        const [year, month] = prev.currentDate.split('-').map(Number);
        const date = new Date(year, month - 1 + offset, 1);
        const newMonthStr = date.toISOString().substring(0, 7);

        const updatedBudgets = prev.budgets.map(b => {
          const monthTx = prev.transactions.filter(t => t.date.startsWith(newMonthStr) && t.type === b.type && t.category === b.category);
          return { ...b, spent: monthTx.reduce((sum, t) => sum + t.amount, 0) };
        });

        return { ...prev, currentDate: newMonthStr, budgets: updatedBudgets };
      });
    },
    setMonth: (dateStr) => {
      setState(prev => {
        const updatedBudgets = prev.budgets.map(b => {
          const monthTx = prev.transactions.filter(t => t.date.startsWith(dateStr) && t.type === b.type && t.category === b.category);
          return { ...b, spent: monthTx.reduce((sum, t) => sum + t.amount, 0) };
        });
        return { ...prev, currentDate: dateStr, budgets: updatedBudgets };
      });
    },
    updateLayout: (newLayout) => {
      setState(prev => ({ ...prev, dashboardLayout: newLayout }));
    },
    setChallenges: (challenges) => {
      setState(prev => ({ ...prev, challenges }));
    }
  };

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);
  const closeMenu = () => setIsMenuOpen(false);

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 overflow-hidden">
          <Sidebar isOpen={isMenuOpen} onClose={closeMenu} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={toggleMenu} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

