export default App;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  Edit2, 
  Trash2, 
  ShoppingBag, 
  ChevronRight, 
  X, 
  ArrowUpRight, 
  ArrowDownRight, 
  ArrowLeftRight,
  TrendingDown,
  TrendingUp,
  AlertCircle,
  Calendar,
  Wallet,
  Tag
} from 'lucide-react';
import { Budget, Transaction } from '../types';
import { CATEGORIES, INCOME_CATEGORIES } from '../constants';

const BudgetManager: React.FC = () => {
  const { budgets, transactions, currentDate, updateBudget, addBudget, deleteBudget, accounts } = useFinance();

  // UI States
  const [activeTab, setActiveTab] = useState<'expense' | 'income'>('expense');
  const [selectedBudget, setSelectedBudget] = useState<Budget | null>(null);
  const [isEditing, setIsEditing] = useState<Budget | null>(null);
  const [isCreating, setIsCreating] = useState(false);

  // Form States
  const [category, setCategory] = useState('');
  const [limit, setLimit] = useState<number | ''>('');
  const [customCategory, setCustomCategory] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);

  const filteredBudgets = useMemo(() => {
    return budgets.filter(b => b.type === activeTab);
  }, [budgets, activeTab]);

  const budgetTransactions = useMemo(() => {
    if (!selectedBudget) return [];
    return transactions.filter(t => 
      t.category === selectedBudget.category && 
      t.type === selectedBudget.type &&
      t.date.startsWith(currentDate)
    );
  }, [selectedBudget, transactions, currentDate]);

  const totals = useMemo(() => {
    const b = budgets.filter(x => x.type === activeTab);
    return {
      limit: b.reduce((s, x) => s + x.limit, 0),
      actual: b.reduce((s, x) => s + x.spent, 0)
    };
  }, [budgets, activeTab]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const finalCategory = isCustomMode ? customCategory : category;
    if (!finalCategory || limit === '') return;

    if (isEditing) {
      updateBudget({ ...isEditing, category: finalCategory, limit: Number(limit) });
      setIsEditing(null);
    } else {
      addBudget({ 
        category: finalCategory, 
        limit: Number(limit), 
        type: activeTab,
        spent: 0,
        icon: 'ShoppingBag'
      });
      setIsCreating(false);
    }
    resetForm();
  };

  const resetForm = () => {
    setCategory('');
    setLimit('');
    setCustomCategory('');
    setIsCustomMode(false);
  };

  const openCreate = () => {
    resetForm();
    const defaultCats = activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    setCategory(defaultCats[0].name);
    setIsCreating(true);
  };

  const openEdit = (b: Budget) => {
    const defaultCats = b.type === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    const isStandard = defaultCats.some(c => c.name === b.category);

    setCategory(isStandard ? b.category : 'Otra');
    setCustomCategory(isStandard ? '' : b.category);
    setIsCustomMode(!isStandard);
    setLimit(b.limit);
    setIsEditing(b);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Presupuestos</h2>
          <p className="text-slate-500 font-medium">Controla tus finanzas de {currentDate} con precisión.</p>
        </div>
        <button 
          onClick={openCreate}
          className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
        >
          <Plus size={20} />
          Nuevo Límite
        </button>
      </div>

      {/* Selector de tipo (Ingreso/Gasto) */}
      <div className="flex items-center gap-1 bg-slate-100 p-1.5 rounded-3xl w-full md:w-fit border border-slate-200 shadow-inner">
        <button 
          onClick={() => setActiveTab('expense')} 
          className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'expense' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <TrendingDown size={16} /> GASTOS
        </button>
        <button 
          onClick={() => setActiveTab('income')} 
          className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'income' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <TrendingUp size={16} /> INGRESOS
        </button>
      </div>

      {/* Resumen de totales */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className={`p-6 rounded-[2.5rem] border shadow-sm flex items-center gap-4 bg-white border-slate-100`}>
          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${activeTab === 'expense' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
            <ShoppingBag size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total {activeTab === 'expense' ? 'Presupuestado' : 'Objetivo'}</p>
            <p className="text-2xl font-black text-slate-800">{totals.limit.toLocaleString()}€</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-4">
          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center bg-blue-50 text-blue-600`}>
            <ArrowLeftRight size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{activeTab === 'expense' ? 'Consumo Real' : 'Ingreso Real'}</p>
            <p className="text-2xl font-black text-blue-600">{totals.actual.toLocaleString()}€</p>
          </div>
        </div>
      </div>

      {/* Cuadrícula de presupuestos */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {filteredBudgets.map(b => {
          const progress = b.limit > 0 ? Math.min((b.spent / b.limit) * 100, 100) : 0;
          const isOver = activeTab === 'expense' ? b.spent > b.limit : false;

          return (
            <div 
              key={b.id} 
              onClick={() => setSelectedBudget(b)}
              className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm hover:shadow-md transition-all group cursor-pointer active:scale-[0.99]"
            >
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner ${activeTab === 'expense' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                    <Tag size={24} />
                  </div>
                  <div>
                    <h4 className="text-lg font-black text-slate-800 tracking-tight">{b.category}</h4>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{activeTab === 'expense' ? 'Gasto' : 'Ingreso'}</p>
                  </div>
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                  <button 
                    onClick={(e) => { e.stopPropagation(); openEdit(b); }}
                    className="p-2.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl"
                  >
                    <Edit2 size={18} />
                  </button>
                  <button 
                    onClick={(e) => { e.stopPropagation(); if(confirm('¿Seguro que quieres eliminar este presupuesto?')) deleteBudget(b.id); }}
                    className="p-2.5 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>

              <div className="space-y-5">
                <div className="flex justify-between items-end">
                   <div>
                      <p className={`text-4xl font-black tracking-tight ${activeTab === 'expense' && b.spent > b.limit ? 'text-rose-500' : 'text-slate-900'}`}>
                        {b.spent.toLocaleString('es-ES')}€
                      </p>
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">de {b.limit.toLocaleString()}€ {activeTab === 'expense' ? 'definidos' : 'objetivo'}</p>
                   </div>
                   <div className="text-right">
                      <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider ${
                        activeTab === 'expense' 
                        ? (b.spent > b.limit ? 'bg-rose-50 text-rose-500' : progress > 85 ? 'bg-amber-50 text-amber-500' : 'bg-emerald-50 text-emerald-500')
                        : (b.spent >= b.limit ? 'bg-emerald-50 text-emerald-500' : 'bg-blue-50 text-blue-500')
                      }`}>
                        {activeTab === 'expense' 
                          ? (b.spent > b.limit ? 'Excedido' : progress > 85 ? 'Cuidado' : 'Correcto') 
                          : (b.spent >= b.limit ? 'Logrado' : 'En progreso')}
                      </span>
                   </div>
                </div>

                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                  <div 
                    className={`h-full rounded-full transition-all duration-1000 ease-out ${
                      activeTab === 'expense'
                      ? (b.spent > b.limit ? 'bg-rose-500' : progress > 85 ? 'bg-amber-400' : 'bg-blue-500')
                      : (b.spent >= b.limit ? 'bg-emerald-500' : 'bg-blue-500')
                    }`} 
                    style={{ width: `${progress}%` }}
                  ></div>
                </div>

                <div className="flex items-center justify-between">
                   <p className="text-xs text-slate-400 font-bold flex items-center gap-1">
                     <ChevronRight size={14} className="text-blue-500" /> Ver detalles
                   </p>
                   {activeTab === 'expense' && b.limit > b.spent && (
                     <p className="text-xs font-black text-slate-700">
                        Dispones de {(b.limit - b.spent).toLocaleString()}€ más
                     </p>
                   )}
                </div>
              </div>
            </div>
          );
        })}
        {filteredBudgets.length === 0 && (
          <div className="col-span-full py-20 bg-white rounded-[3rem] border border-dashed border-slate-200 flex flex-col items-center justify-center gap-4 text-center">
             <div className="w-16 h-16 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center"><AlertCircle size={32} /></div>
             <div>
               <p className="text-slate-400 font-bold italic uppercase tracking-widest text-xs">No hay categorías configuradas para {activeTab === 'expense' ? 'gastos' : 'ingresos'}.</p>
               <button onClick={openCreate} className="mt-4 text-blue-600 font-black text-sm hover:underline flex items-center justify-center gap-2 mx-auto">
                 <Plus size={16} /> Crear presupuesto inicial
               </button>
             </div>
          </div>
        )}
      </div>

      {/* Modal de transacciones por categoría */}
      {selectedBudget && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-50 flex items-center justify-center p-4" onClick={() => setSelectedBudget(null)}>
          <div className="bg-white rounded-[3.5rem] w-full max-w-2xl p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 max-h-[85vh] flex flex-col border border-slate-100" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-10">
               <div className="flex items-center gap-5">
                 <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-lg ${selectedBudget.type === 'expense' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                    <Tag size={32} />
                 </div>
                 <div>
                   <h3 className="text-3xl font-black text-slate-800 tracking-tight">{selectedBudget.category}</h3>
                   <div className="flex items-center gap-2 mt-1">
                     <span className="text-[10px] bg-slate-100 text-slate-500 px-3 py-1 rounded-full font-black uppercase tracking-wider">{selectedBudget.type === 'expense' ? 'Gasto' : 'Ingreso'}</span>
                     <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest flex items-center gap-1">
                       <Calendar size={12} /> {currentDate}
                     </p>
                   </div>
                 </div>
               </div>
               <button onClick={() => setSelectedBudget(null)} className="p-4 hover:bg-slate-100 rounded-full text-slate-400 transition-colors">
                 <X size={28} />
               </button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar pr-3 space-y-4">
              {budgetTransactions.length > 0 ? (
                budgetTransactions.map(t => (
                  <div key={t.id} className="flex items-center justify-between p-6 bg-slate-50/50 rounded-[2rem] border border-slate-100 hover:bg-white hover:shadow-xl hover:scale-[1.01] transition-all group">
                    <div className="flex items-center gap-5">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center shadow-sm ${t.type === 'income' ? 'bg-emerald-50 text-emerald-500' : 'bg-rose-50 text-rose-500'}`}>
                        {t.type === 'income' ? <ArrowDownLeft size={20} /> : <ArrowUpRight size={20} />}
                      </div>
                      <div>
                        <p className="text-base font-black text-slate-800 line-clamp-1 group-hover:text-blue-600 transition-colors">{t.description}</p>
                        <div className="flex items-center gap-3 mt-1">
                           <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1"><Calendar size={12} /> {new Date(t.date).toLocaleDateString()}</span>
                           <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1"><Wallet size={12} /> {accounts.find(a => a.id === t.accountId)?.name}</span>
                        </div>
                      </div>
                    </div>
                    <p className={`text-xl font-black ${t.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                      {t.type === 'income' ? '+' : '-'}{t.amount.toLocaleString()}€
                    </p>
                  </div>
                ))
              ) : (
                <div className="py-20 text-center flex flex-col items-center gap-4 border-2 border-dashed border-slate-100 rounded-[2.5rem]">
                   <AlertCircle size={40} className="text-slate-200" />
                   <p className="font-black text-slate-400 uppercase tracking-widest text-xs">Sin movimientos en {currentDate}</p>
                </div>
              )}
            </div>

            <div className="mt-10 pt-8 border-t border-slate-100 flex justify-between items-center">
               <div>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total acumulado</p>
                 <p className="text-3xl font-black text-blue-600">{selectedBudget.spent.toLocaleString()}€</p>
               </div>
               <div className="text-right">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Presupuesto</p>
                 <p className="text-xl font-black text-slate-700">{selectedBudget.limit.toLocaleString()}€</p>
               </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Crear / Editar */}
      {(isCreating || isEditing) && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3.5rem] w-full max-w-md p-10 md:p-14 shadow-2xl animate-in fade-in zoom-in duration-300 border border-slate-100">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-3xl font-black text-slate-900 tracking-tight">{isEditing ? 'Editar Límite' : 'Nueva Categoría'}</h3>
              <button onClick={() => { setIsCreating(false); setIsEditing(null); }} className="p-3 hover:bg-slate-100 rounded-full text-slate-400 transition-colors">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSave} className="space-y-8">
              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest pl-1">Categoría de {activeTab === 'expense' ? 'Gasto' : 'Ingreso'}</label>
                <div className="relative">
                  <select 
                    value={category} 
                    onChange={e => {
                      setCategory(e.target.value);
                      setIsCustomMode(e.target.value === 'Otra');
                      if(e.target.value !== 'Otra') setCustomCategory('');
                    }}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-black text-slate-800 focus:bg-white focus:border-blue-400 outline-none transition-all appearance-none cursor-pointer"
                    required
                  >
                    {(activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES).map(c => (
                      <option key={c.name} value={c.name}>{c.name}</option>
                    ))}
                    <option value="Otra">-- Personalizada --</option>
                  </select>
                  <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={20} />
                </div>

                {isCustomMode && (
                  <div className="animate-in slide-in-from-top-2 duration-300">
                    <input 
