  emoji?: string;
}

export interface Refund {
  id: string;
  name: string;
  totalAmount: number;
  paidByMe: number;
  pendingAmount: number;
  status: 'open' | 'closed';
  notes: string;
  date: string;
  category: string; // Nueva: Para saber qué gasto reducir al cobrar
