import React, { useState } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  CheckCircle2, 
  Users, 
  Trash2, 
  Merge, 
  X, 
  Edit3, 
  Save, 
  MessageSquare,
  Check,
  TrendingUp,
  AlertCircle
} from 'lucide-react';
import { Refund } from '../types';
import { CATEGORIES } from '../constants';

const Refunds: React.FC = () => {
  const { refunds, addRefund, updateRefund, deleteRefund, mergeRefunds } = useFinance();

  // UI States
  const [isAdding, setIsAdding] = useState(false);
  const [isMerging, setIsMerging] = useState(false);
  const [mergeSelection, setMergeSelection] = useState<string[]>([]);
  const [filter, setFilter] = useState<'all' | 'open' | 'closed'>('open');

  // Action Confirmation States
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const [confirmCompleteId, setConfirmCompleteId] = useState<string | null>(null);

  // Editing notes
  const [editingNotesId, setEditingNotesId] = useState<string | null>(null);
  const [tempNotes, setTempNotes] = useState('');

  // Form state
  const [name, setName] = useState('');
  const [total, setTotal] = useState<number | ''>('');
  const [myPart, setMyPart] = useState<number | ''>('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0].name);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (total === '' || myPart === '') return;
    const pending = total - myPart;
    addRefund({
      name,
      totalAmount: total,
      paidByMe: myPart,
      pendingAmount: pending,
      status: pending <= 0 ? 'closed' : 'open',
      notes,
      date: new Date().toISOString(),
      category: category
    });
    setIsAdding(false);
    resetForm();
  };

  const resetForm = () => { setName(''); setTotal(''); setMyPart(''); setNotes(''); setCategory(CATEGORIES[0].name); };

  const handleMergeToggle = (id: string) => {
    if (!isMerging) return;
    setMergeSelection(prev => {
      if (prev.includes(id)) return prev.filter(x => x !== id);
      if (prev.length >= 2) return prev; 
      return [...prev, id];
    });
  };

  const executeMerge = () => {
    if (mergeSelection.length === 2) {
      mergeRefunds(mergeSelection[0], mergeSelection[1]);
      setMergeSelection([]);
      setIsMerging(false);
    }
  };

  const handleActionClick = (e: React.MouseEvent, action: () => void) => {
    e.stopPropagation();
    e.preventDefault();
    action();
  };

  const filteredRefunds = refunds.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Reembolsos</h2>
          <p className="text-slate-500 font-medium">Gestiona deudas pendientes. Los cobros reducen el gasto neto del mes.</p>
        </div>
        <div className="flex gap-2">
          {refunds.length >= 2 && (
            <button 
              type="button"
              onClick={() => {
                setIsMerging(!isMerging);
                setMergeSelection([]);
              }}
              className={`flex items-center gap-2 px-6 py-3 font-bold rounded-2xl transition-all shadow-sm ${isMerging ? 'bg-amber-600 text-white shadow-lg shadow-amber-100' : 'bg-white border border-slate-200 text-slate-700 hover:bg-slate-50'}`}
            >
              <Merge size={18} />
              {isMerging ? 'Cancelar' : 'Unificar Deudas'}
            </button>
          )}
          <button 
            type="button"
            onClick={() => setIsAdding(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
          >
            <Plus size={18} />
            Nuevo Reembolso
          </button>
        </div>
      </div>

      <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-2xl w-fit border border-slate-200 shadow-inner">
        <button type="button" onClick={() => setFilter('open')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'open' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>PENDIENTES</button>
        <button type="button" onClick={() => setFilter('closed')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'closed' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>COMPLETADOS</button>
        <button type="button" onClick={() => setFilter('all')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>TODOS</button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredRefunds.map(r => (
          <div 
            key={r.id} 
            onClick={() => isMerging && handleMergeToggle(r.id)}
            className={`bg-white rounded-[2.5rem] p-8 border transition-all relative overflow-hidden group flex flex-col ${
              isMerging && mergeSelection.includes(r.id) ? 'border-amber-500 ring-4 ring-amber-100 scale-[1.02] shadow-xl' : 
              r.status === 'closed' ? 'border-slate-100 opacity-80 shadow-sm' : 'border-slate-100 shadow-sm hover:shadow-md'
            }`}
          >
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${r.status === 'closed' ? 'bg-slate-100 text-slate-400' : 'bg-blue-50 text-blue-600'}`}>
                  <Users size={22} />
                </div>
                <div>
                  <h4 className="font-bold text-slate-800 line-clamp-1">{r.name}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{r.category} • {new Date(r.date).toLocaleDateString()}</p>
                </div>
              </div>
              <button 
                type="button"
                onClick={(e) => handleActionClick(e, () => deleteRefund(r.id))}
                className="p-2.5 text-slate-300 hover:text-rose-500 transition-all"
              >
                <Trash2 size={18} />
              </button>
            </div>

            <div className={`rounded-3xl p-6 border transition-all space-y-4 ${r.status === 'closed' ? 'bg-slate-50 border-slate-200' : 'bg-blue-50/50 border-blue-100 shadow-sm'}`}>
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Pendiente</p>
                  <p className={`text-3xl font-black ${r.status === 'closed' ? 'text-slate-400 line-through' : 'text-blue-600'}`}>{r.pendingAmount.toLocaleString()}€</p>
                </div>
              </div>
            </div>

            {r.status === 'open' && !isMerging && (
              <div className="mt-4">
                <button 
                  type="button"
                  onClick={(e) => handleActionClick(e, () => updateRefund({ ...r, status: 'closed' }, true))}
                  className="w-full flex items-center justify-center gap-2 p-3 bg-white border border-slate-200 text-slate-700 rounded-2xl text-xs font-bold hover:bg-emerald-50 hover:text-emerald-600 hover:border-emerald-200 transition-all active:scale-95"
                >
                  <CheckCircle2 size={16} className="text-slate-300" />
                  Cobrar deuda ahora
                </button>
              </div>
            )}
          </div>
        ))}
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
               <h3 className="text-2xl font-black text-slate-800 tracking-tight">Nuevo Reembolso</h3>
               <button type="button" onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Concepto</label>
                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none font-medium" placeholder="Cena..." required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Importe Total</label>
                  <input type="number" value={total} onChange={e => setTotal(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Tu parte</label>
                  <input type="number" value={myPart} onChange={e => setMyPart(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" required />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Categoría a la que pertenece</label>
                <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none">
                  {CATEGORIES.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                </select>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl active:scale-95">Crear</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

