import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Wallet, 
  PiggyBank, 
  Receipt, 
  BarChart3, 
  MessageSquare,
  ChevronLeft,
  ChevronRight,
  Menu,
  X,
  Plus,
  Camera
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';

interface FinanceContextType extends FinanceState {
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon' | 'type'> & { type?: 'income' | 'expense'; icon?: string }) => void;
  updateBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  changeMonth: (offset: number) => void;
  setMonth: (date: string) => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<FinanceState>(() => {
    const saved = localStorage.getItem('finance_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('finance_data', JSON.stringify(state));
  }, [state]);

  const contextValue: FinanceContextType = {
    ...state,
    addTransaction: (t, myPart) => {
      const id = Math.random().toString(36).substr(2, 9);
      let finalTransaction = { ...t, id };

      setState(prev => {
        let updatedRefunds = [...prev.refunds];

        if (t.type === 'income' && t.refundId) {
          const linkedRefund = prev.refunds.find(r => r.id === t.refundId);
          if (linkedRefund) {
            finalTransaction.category = linkedRefund.category;
          }
        }

        if (t.type === 'expense' && t.isRefund) {
          const refundId = 'ref_' + Date.now();
          const partToPay = myPart !== undefined ? myPart : t.amount / 2;
          updatedRefunds.push({
            id: refundId,
            name: t.description,
            totalAmount: t.amount,
            paidByMe: partToPay, 
            pendingAmount: t.amount - partToPay, 
            status: (t.amount - partToPay) <= 0 ? 'closed' : 'open',
            notes: 'Creado desde gasto: ' + t.description,
            date: t.date,
            category: t.category,
            originTransactionId: id
          });
          finalTransaction.refundId = refundId;
        }

        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = Math.max(0, r.pendingAmount - t.amount);
              return { ...r, pendingAmount: newPending, status: newPending <= 0 ? 'closed' : 'open' };
            }
            return r;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? t.amount : -t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        const budgets = prev.budgets.map(b => {
          if (finalTransaction.type === 'income' && finalTransaction.refundId) {
            if (b.type === 'expense' && b.category === finalTransaction.category && finalTransaction.date.startsWith(prev.currentDate)) {
              return { ...b, spent: Math.max(0, b.spent - finalTransaction.amount) };
            }
          } else if (finalTransaction.type === b.type && b.category === finalTransaction.category && finalTransaction.date.startsWith(prev.currentDate)) {
            return { ...b, spent: b.spent + finalTransaction.amount };
          }
          return b;
        });

        return {
          ...prev,
          transactions: [finalTransaction, ...prev.transactions],
          accounts,
          budgets,
          refunds: updatedRefunds
        };
      });
    },
    updateTransaction: (updatedTx) => {
      setState(prev => {
        const oldTx = prev.transactions.find(t => t.id === updatedTx.id);
        if (!oldTx) return prev;

        const accounts = prev.accounts.map(acc => {
          let balance = acc.currentBalance;
          if (acc.id === oldTx.accountId) balance -= (oldTx.type === 'income' ? oldTx.amount : -oldTx.amount);
          if (acc.id === updatedTx.accountId) balance += (updatedTx.type === 'income' ? updatedTx.amount : -updatedTx.amount);
          return { ...acc, currentBalance: balance };
        });

        const budgets = prev.budgets.map(b => {
          let spent = b.spent;
          if (oldTx.type === 'income' && oldTx.refundId) {
             if (b.type === 'expense' && b.category === oldTx.category && oldTx.date.startsWith(prev.currentDate)) spent += oldTx.amount;
          } else if (oldTx.type === b.type && b.category === oldTx.category && oldTx.date.startsWith(prev.currentDate)) {
            spent -= oldTx.amount;
          }
          if (updatedTx.type === 'income' && updatedTx.refundId) {
            if (b.type === 'expense' && b.category === updatedTx.category && updatedTx.date.startsWith(prev.currentDate)) spent -= updatedTx.amount;
          } else if (updatedTx.type === b.type && b.category === updatedTx.category && updatedTx.date.startsWith(prev.currentDate)) {
            spent += updatedTx.amount;
          }
          return { ...b, spent: Math.max(0, spent) };
        });

        return {
          ...prev,
          transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t),
          accounts,
          budgets
        };
      });
    },
    deleteTransaction: (id) => {
      setState(prev => {
        const t = prev.transactions.find(tx => tx.id === id);
        if (!t) return prev;
        let updatedRefunds = prev.refunds.filter(r => r.originTransactionId !== id);
        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) return { ...r, pendingAmount: r.pendingAmount + t.amount, status: 'open' };
            return r;
          });
        }
        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) return { ...acc, currentBalance: acc.currentBalance + (t.type === 'income' ? -t.amount : t.amount) };
          return acc;
        });
        const budgets = prev.budgets.map(b => {
          if (t.type === 'income' && t.refundId) {
            if (b.type === 'expense' && b.category === t.category && t.date.startsWith(prev.currentDate)) return { ...b, spent: b.spent + t.amount };
          } else if (t.type === b.type && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: Math.max(0, b.spent - t.amount) };
          }
          return b;
        });
        return { ...prev, transactions: prev.transactions.filter(tx => tx.id !== id), accounts, refunds: updatedRefunds, budgets };
      });
    },
    addAccount: (a) => {
      const id = 'acc_' + Date.now();
      setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id, currentBalance: a.initialBalance }] }));
    },
    updateAccount: (a) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) }));
    },
    deleteAccount: (id) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) }));
    },
    addSaving: (s) => {
      const id = 'sav_' + Date.now();
      setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id }] }));
    },
    updateSaving: (s) => {
      setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) }));
    },
    deleteSaving: (id) => {
      setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) }));
    },
    addRefund: (r) => {
      const id = 'ref_' + Date.now();
      setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id }] }));
    },
    updateRefund: (r) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf)
      }));
    },
    deleteRefund: (id) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.filter(r => r.id !== id),
        transactions: prev.transactions.map(t => t.refundId === id ? { ...t, refundId: undefined, isRefund: false } : t)
      }));
    },
    mergeRefunds: (id1, id2) => {
      setState(prev => {
        const r1 = prev.refunds.find(r => r.id === id1);
        const r2 = prev.refunds.find(r => r.id === id2);
        if (!r1 || !r2) return prev;
        const newId = 'ref_merged_' + Date.now();
        const mergedRefund: Refund = {
          id: newId,
          name: `${r1.name} + ${r2.name}`,
          totalAmount: r1.totalAmount + r2.totalAmount,
          paidByMe: r1.paidByMe + r2.paidByMe,
          pendingAmount: r1.pendingAmount + r2.pendingAmount,
          status: (r1.pendingAmount + r2.pendingAmount) > 0 ? 'open' : 'closed',
          notes: `Unificado.`,
          date: new Date().toISOString().split('T')[0],
          category: r1.category
        };
        return {
          ...prev,
          refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), mergedRefund],
          transactions: prev.transactions.map(t => (t.refundId === id1 || t.refundId === id2) ? { ...t, refundId: newId } : t)
        };
      });
    },
    addBudget: (b) => {
      const budgetType = b.type || 'expense';
      const id = 'budget_' + Date.now();
      const monthTx = state.transactions.filter(t => t.date.startsWith(state.currentDate) && t.category === b.category);
      let spent = 0;
      monthTx.forEach(t => {
        if (t.type === 'expense') {
          if (budgetType === 'expense') spent += t.amount;
        } else if (t.type === 'income') {
          if (t.refundId && budgetType === 'expense') spent -= t.amount;
          else if (!t.refundId && budgetType === 'income') spent += t.amount;
        }
      });
      setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id, spent, type: budgetType, icon: b.icon || 'ShoppingBag' } as Budget] }));
    },
    updateBudget: (updatedBudget) => {
      setState(prev => {
        const monthTx = prev.transactions.filter(t => t.date.startsWith(prev.currentDate) && t.category === updatedBudget.category);
        let spent = 0;
        monthTx.forEach(t => {
          if (t.type === 'expense') {
            if (updatedBudget.type === 'expense') spent += t.amount;
          } else if (t.type === 'income') {
            if (t.refundId && updatedBudget.type === 'expense') spent -= t.amount;
            else if (!t.refundId && updatedBudget.type === 'income') spent += t.amount;
          }
        });
        return { ...prev, budgets: prev.budgets.map(bg => bg.id === updatedBudget.id ? { ...updatedBudget, spent: Math.max(0, spent) } : bg) };
      });
    },
    deleteBudget: (id) => {
      setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) }));
    },
    changeMonth: (offset) => {
      setState(prev => {
        const [year, month] = prev.currentDate.split('-').map(Number);
        const date = new Date(year, month - 1 + offset, 1);
        const newMonthStr = date.toISOString().substring(0, 7);
        const updatedBudgets = prev.budgets.map(b => {
          const monthTx = prev.transactions.filter(t => t.date.startsWith(newMonthStr) && t.category === b.category);
          let spent = 0;
          monthTx.forEach(t => {
            if (t.type === 'expense') { if (b.type === 'expense') spent += t.amount; }
            else if (t.type === 'income') { if (t.refundId && b.type === 'expense') spent -= t.amount; else if (!t.refundId && b.type === 'income') spent += t.amount; }
          });
          return { ...b, spent: Math.max(0, spent) };
        });
        return { ...prev, currentDate: newMonthStr, budgets: updatedBudgets };
      });
    },
    setMonth: (dateStr) => {
      setState(prev => {
        const updatedBudgets = prev.budgets.map(b => {
          const monthTx = prev.transactions.filter(t => t.date.startsWith(dateStr) && t.category === b.category);
          let spent = 0;
          monthTx.forEach(t => {
            if (t.type === 'expense') { if (b.type === 'expense') spent += t.amount; }
            else if (t.type === 'income') { if (t.refundId && b.type === 'expense') spent -= t.amount; else if (!t.refundId && b.type === 'income') spent += t.amount; }
          });
          return { ...b, spent: Math.max(0, spent) };
        });
        return { ...prev, currentDate: dateStr, budgets: updatedBudgets };
      });
    },
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges }))
  };

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);
  const closeMenu = () => setIsMenuOpen(false);

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 overflow-hidden">
          <Sidebar isOpen={isMenuOpen} onClose={closeMenu} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={toggleMenu} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

