import React, { useState } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  CheckCircle2, 
  Users, 
  Trash2, 
  Merge, 
  X, 
  Edit3, 
  Save, 
  MessageSquare,
  Check,
  TrendingUp,
  AlertCircle
} from 'lucide-react';
import { Refund } from '../types';
import { CATEGORIES } from '../constants';

const Refunds: React.FC = () => {
  const { refunds, addRefund, updateRefund, deleteRefund, mergeRefunds } = useFinance();

  // UI States
  const [isAdding, setIsAdding] = useState(false);
  const [isMerging, setIsMerging] = useState(false);
  const [mergeSelection, setMergeSelection] = useState<string[]>([]);
  const [filter, setFilter] = useState<'all' | 'open' | 'closed'>('open');

  // Action Confirmation States
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const [confirmCompleteId, setConfirmCompleteId] = useState<string | null>(null);

  // Editing notes
  const [editingNotesId, setEditingNotesId] = useState<string | null>(null);
  const [tempNotes, setTempNotes] = useState('');

  // Form state
  const [name, setName] = useState('');
  const [total, setTotal] = useState<number | ''>('');
  const [myPart, setMyPart] = useState<number | ''>('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0].name);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (total === '' || myPart === '') return;
    const pending = total - myPart;
    addRefund({
      name,
      totalAmount: total,
      paidByMe: myPart,
      pendingAmount: pending,
      status: pending <= 0 ? 'closed' : 'open',
      notes,
      date: new Date().toISOString(),
      category: category
    });
    setIsAdding(false);
    resetForm();
  };

  const resetForm = () => { setName(''); setTotal(''); setMyPart(''); setNotes(''); setCategory(CATEGORIES[0].name); };

  const handleMergeToggle = (id: string) => {
    if (!isMerging) return;
    setMergeSelection(prev => {
      if (prev.includes(id)) return prev.filter(x => x !== id);
      if (prev.length >= 2) return prev; 
      return [...prev, id];
    });
  };

  const executeMerge = () => {
    if (mergeSelection.length === 2) {
      mergeRefunds(mergeSelection[0], mergeSelection[1]);
      setMergeSelection([]);
      setIsMerging(false);
    }
  };

  const handleActionClick = (e: React.MouseEvent, action: () => void) => {
    e.stopPropagation();
    e.preventDefault();
    action();
  };

  const filteredRefunds = refunds.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Reembolsos</h2>
          <p className="text-slate-500 font-medium">Gestiona deudas pendientes. Los cobros reducen el gasto neto del mes.</p>
        </div>
        <div className="flex gap-2">
          {refunds.length >= 2 && (
            <button 
              type="button"
              onClick={() => {
                setIsMerging(!isMerging);
                setMergeSelection([]);
              }}
              className={`flex items-center gap-2 px-6 py-3 font-bold rounded-2xl transition-all shadow-sm ${isMerging ? 'bg-amber-600 text-white shadow-lg shadow-amber-100' : 'bg-white border border-slate-200 text-slate-700 hover:bg-slate-50'}`}
            >
              <Merge size={18} />
              {isMerging ? 'Cancelar' : 'Unificar Deudas'}
            </button>
          )}
          <button 
            type="button"
            onClick={() => setIsAdding(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
          >
            <Plus size={18} />
            Nuevo Reembolso
          </button>
        </div>
      </div>

      <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-2xl w-fit border border-slate-200 shadow-inner">
        <button type="button" onClick={() => setFilter('open')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'open' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>PENDIENTES</button>
        <button type="button" onClick={() => setFilter('closed')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'closed' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>COMPLETADOS</button>
        <button type="button" onClick={() => setFilter('all')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>TODOS</button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredRefunds.map(r => (
          <div 
            key={r.id} 
            onClick={() => isMerging && handleMergeToggle(r.id)}
            className={`bg-white rounded-[2.5rem] p-8 border transition-all relative overflow-hidden group flex flex-col ${
              isMerging && mergeSelection.includes(r.id) ? 'border-amber-500 ring-4 ring-amber-100 scale-[1.02] shadow-xl' : 
              r.status === 'closed' ? 'border-slate-100 opacity-80 shadow-sm' : 'border-slate-100 shadow-sm hover:shadow-md'
            }`}
          >
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${r.status === 'closed' ? 'bg-slate-100 text-slate-400' : 'bg-blue-50 text-blue-600'}`}>
                  <Users size={22} />
                </div>
                <div>
                  <h4 className="font-bold text-slate-800 line-clamp-1">{r.name}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{r.category} • {new Date(r.date).toLocaleDateString()}</p>
                </div>
              </div>
              <button 
                type="button"
                onClick={(e) => handleActionClick(e, () => deleteRefund(r.id))}
                className="p-2.5 text-slate-300 hover:text-rose-500 transition-all"
              >
                <Trash2 size={18} />
              </button>
            </div>

            <div className={`rounded-3xl p-6 border transition-all space-y-4 ${r.status === 'closed' ? 'bg-slate-50 border-slate-200' : 'bg-blue-50/50 border-blue-100 shadow-sm'}`}>
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Pendiente</p>
                  <p className={`text-3xl font-black ${r.status === 'closed' ? 'text-slate-400 line-through' : 'text-blue-600'}`}>{r.pendingAmount.toLocaleString()}€</p>
                </div>
              </div>
            </div>

            {r.status === 'open' && !isMerging && (
              <div className="mt-4">
                <button 
                  type="button"
                  onClick={(e) => handleActionClick(e, () => updateRefund({ ...r, status: 'closed' }))}
                  className="w-full flex items-center justify-center gap-2 p-3 bg-white border border-slate-200 text-slate-700 rounded-2xl text-xs font-bold hover:bg-emerald-50 hover:text-emerald-600 hover:border-emerald-200 transition-all active:scale-95"
                >
                  <CheckCircle2 size={16} className="text-slate-300" />
                  Marcar como cobrado
                </button>
              </div>
            )}
          </div>
        ))}
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
               <h3 className="text-2xl font-black text-slate-800 tracking-tight">Nuevo Reembolso</h3>
               <button type="button" onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Concepto</label>
                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none font-medium" placeholder="Cena..." required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Importe Total</label>
                  <input type="number" value={total} onChange={e => setTotal(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Tu parte</label>
                  <input type="number" value={myPart} onChange={e => setMyPart(Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none" required />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Categoría a la que pertenece</label>
                <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-bold outline-none">
                  {CATEGORIES.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                </select>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl active:scale-95">Crear</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Refunds;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  Camera, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  Loader2, 
  X, 
  Receipt, 
  UserCheck, 
  Calendar, 
  AlertCircle, 
  Check, 
  ArrowRightLeft, 
  PiggyBank, 
  Sparkles, 
  ChevronDown, 
  Wallet, 
  Split 
} from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; 
  myPart?: number; 
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, updateSaving } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const [pendingImports, setPendingImports] = useState<ScannedItem[]>([]);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  // RESTRICCIÓN: Solo categorías que existen en los presupuestos
  const availableCategories = useMemo(() => {
    const budgetList = budgets
      .filter(b => b.type === type)
      .map(b => b.category);

    return budgetList.length > 0 ? budgetList : ["Sin Presupuesto"];
  }, [type, budgets]);

  useEffect(() => {
    if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setMyPartManual('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    setType(tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setIsAdding(true);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleDeleteFromModal = (id: string) => {
    deleteTransaction(id);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        refundId: selectedRefundId || undefined
      });
    } else {
      addTransaction({
        date: date,
        amount: Number(amount),
        description: desc,
        category: category,
        type: type,
        accountId: accountId,
        isRefund: isRefundLink,
        refundId: type === 'income' && isRefundLink ? selectedRefundId : undefined
      }, type === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const results = await analyzeReceipt(base64);

        const mappedResults: ScannedItem[] = results.map((r: any) => ({
          id: Math.random().toString(36).substr(2, 9),
          description: r.description || 'Sin descripción',
          amount: r.amount || 0,
          date: r.date || new Date().toISOString().split('T')[0],
          category: r.category || 'Varios',
          type: r.type === 'income' ? 'income' : 'expense',
          intent: r.intent || 'standard',
          accountId: accounts[0]?.id || '',
          targetId: '',
          myPart: (r.amount || 0) / 2
        }));

        setPendingImports(mappedResults);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      alert("Error al analizar la captura");
      setIsScanning(false);
    }
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      // Lógica de Filtros Expandida
      let matchesType = true;
      const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros');
      const isRefund = t.type === 'income' && !!t.refundId;

      if (filter === 'income') matchesType = t.type === 'income' && !t.refundId;
      else if (filter === 'expense') matchesType = t.type === 'expense' && !isSaving;
      else if (filter === 'savings') matchesType = isSaving;
      else if (filter === 'refunds') matchesType = isRefund;

      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  // Identificador de estilo visual por transacción
  const getTxStyle = (t: Transaction) => {
    const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros');
    const isRefund = t.type === 'income' && !!t.refundId;

    if (isSaving) return { color: 'text-amber-600', bg: 'bg-amber-50', icon: <PiggyBank size={18} /> };
    if (isRefund) return { color: 'text-blue-600', bg: 'bg-blue-50', icon: <ArrowUpRight size={18} /> };
    if (t.type === 'income') return { color: 'text-emerald-600', bg: 'bg-emerald-50', icon: <ArrowUpRight size={18} /> };
    return { color: 'text-rose-600', bg: 'bg-rose-50', icon: <ArrowDownRight size={18} /> };
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[70] flex flex-col items-center justify-center">
          <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in duration-300 border border-slate-100 max-w-sm w-full mx-4">
            <div className="w-20 h-20 bg-blue-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-blue-200 animate-pulse">
              <Sparkles size={40} />
            </div>
            <h3 className="text-2xl font-black text-slate-900 tracking-tight">Analizando con Aura...</h3>
            <div className="flex items-center gap-2 text-blue-600 font-black uppercase tracking-[0.2em] text-[10px]">
              <Loader2 size={16} className="animate-spin" />
              <span>Procesando imagen</span>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Transacciones</h2>
          <p className="text-slate-700 font-bold">Historial de movimientos categorizados.</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 px-6 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition-all cursor-pointer active:scale-95 shadow-sm">
            <Camera size={18} className="text-blue-600" />
            <span className="hidden sm:inline">Escanear</span>
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} disabled={isScanning} />
          </label>
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={18} /> 
            <span>Nuevo</span>
          </button>
        </div>
      </div>

      {/* Main Container */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        {/* Filtros Expandidos */}
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col gap-6 bg-slate-50/30">
          <div className="flex flex-wrap items-center gap-1 bg-white p-1 rounded-2xl border border-slate-200 shadow-sm w-full">
            <button onClick={() => setFilter('all')} className={`flex-1 px-4 py-2.5 text-[10px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`flex-1 px-4 py-2.5 text-[10px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 px-4 py-2.5 text-[10px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`flex-1 px-4 py-2.5 text-[10px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>AHORROS</button>
            <button onClick={() => setFilter('refunds')} className={`flex-1 px-4 py-2.5 text-[10px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>REEMBOLSOS</button>
          </div>

          <div className="flex items-center gap-3 bg-white px-5 py-3 rounded-2xl border border-slate-200 w-full shadow-sm focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <Search size={18} className="text-slate-500" />
            <input 
              type="text" 
              placeholder="Buscar por descripción o categoría..." 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Tabla con Estilos Diferenciados */}
        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse table-fixed">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] uppercase tracking-[0.15em] text-slate-400 font-black border-b border-slate-100">
                <th className="px-6 py-5 text-left w-[20%]">Fecha</th>
                <th className="px-6 py-5 text-left w-[50%]">Detalle</th>
                <th className="px-6 py-5 text-right w-[30%]">Importe</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => {
                const style = getTxStyle(tx);
                return (
                  <tr 
                    key={tx.id} 
                    onClick={() => { setViewingTx(tx); setConfirmDeleteInModal(false); }}
                    className="hover:bg-slate-50 transition-all group cursor-pointer active:bg-slate-100"
                  >
                    <td className="px-6 py-6 text-[11px] font-black text-slate-500 uppercase">
                      {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex items-center gap-4 overflow-hidden">
                        <div className={`flex w-9 h-9 rounded-xl items-center justify-center flex-shrink-0 shadow-sm ${style.bg} ${style.color}`}>
                          {style.icon}
                        </div>
                        <div className="min-w-0 flex flex-col">
                          <span className="font-black text-slate-800 text-[13px] truncate leading-tight">
                            {tx.description}
                          </span>
                          <span className="text-[9px] font-black text-slate-400 uppercase tracking-wider mt-0.5 truncate">{tx.category}</span>
                        </div>
                      </div>
                    </td>
                    <td className={`px-6 py-6 text-right font-black text-lg ${style.color}`}>
                      {tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTx.length === 0 && (
            <div className="py-24 text-center flex flex-col items-center gap-4">
