                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Importe (€)</label>
                        <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-black text-xl outline-none" required />
