import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  Camera, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  Loader2, 
  X, 
  Receipt, 
  UserCheck, 
  Calendar, 
  AlertCircle, 
  Check, 
  ArrowRightLeft, 
  PiggyBank, 
  Sparkles, 
  ChevronDown, 
  Wallet, 
  Split 
} from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; 
  myPart?: number; 
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  // RESTRICCIÓN: Solo categorías que existen en los presupuestos
  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];
    const budgetList = budgets
      .filter(b => b.type === (type === 'saving' ? 'expense' : type))
      .map(b => b.category);

    return budgetList.length > 0 ? budgetList : ["Sin Presupuesto"];
  }, [type, budgets]);

  useEffect(() => {
    if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setSelectedSavingId('');
    setMyPartManual('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);

    const isSavingType = tx.type === 'expense' && !!tx.savingId;
    setType(isSavingType ? 'saving' : tx.type);

    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setSelectedSavingId(tx.savingId || '');
    setIsAdding(true);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    const finalType = type === 'saving' ? 'expense' : type;
    const finalCategory = type === 'saving' ? 'Ahorro' : category;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date,
        amount: Number(amount),
        description: desc,
        category: finalCategory,
        type: finalType,
        accountId,
        refundId: selectedRefundId || undefined,
        savingId: type === 'saving' ? selectedSavingId : undefined
      });
    } else {
      addTransaction({
        date,
        amount: Number(amount),
        description: desc,
        category: finalCategory,
        type: finalType,
        accountId,
        isRefund: isRefundLink,
        refundId: finalType === 'income' && isRefundLink ? selectedRefundId : undefined,
        savingId: type === 'saving' ? selectedSavingId : undefined
      }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      let matchesType = true;
      const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
      const isRefund = t.type === 'income' && !!t.refundId;

      if (filter === 'income') matchesType = t.type === 'income' && !t.refundId;
      else if (filter === 'expense') matchesType = t.type === 'expense' && !isSaving;
      else if (filter === 'savings') matchesType = isSaving;
      else if (filter === 'refunds') matchesType = isRefund;

      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const getTxStyle = (t: Transaction) => {
    const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
    const isRefund = t.type === 'income' && !!t.refundId;

    if (isSaving) return { color: 'text-amber-600', bg: 'bg-amber-50', icon: <PiggyBank size={18} /> };
    if (isRefund) return { color: 'text-blue-600', bg: 'bg-blue-50', icon: <ArrowUpRight size={18} /> };
    if (t.type === 'income') return { color: 'text-emerald-600', bg: 'bg-emerald-50', icon: <ArrowUpRight size={18} /> };
    return { color: 'text-rose-600', bg: 'bg-rose-50', icon: <ArrowDownRight size={18} /> };
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
