          <p className="text-slate-700 font-bold">Historial de movimientos categorizados.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={20} /> 
            <span>Nuevo Movimiento</span>
          </button>
        </div>
      </div>

      {/* Main Container */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        {/* Filtros Expandidos */}
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col gap-6 bg-slate-50/30">
          <div className="flex flex-wrap items-center gap-1 bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm w-full">
            <button onClick={() => setFilter('all')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>AHORROS</button>
            <button onClick={() => setFilter('refunds')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>REEMBOLSOS</button>
          </div>

          <div className="flex items-center gap-3 bg-white px-5 py-3 rounded-2xl border border-slate-200 w-full shadow-sm focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <Search size={18} className="text-slate-500" />
            <input 
              type="text" 
              placeholder="Buscar por descripción o categoría..." 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Tabla */}
        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse table-fixed">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] uppercase tracking-[0.15em] text-slate-400 font-black border-b border-slate-100">
                <th className="px-6 py-5 text-left w-[20%]">Fecha</th>
                <th className="px-6 py-5 text-left w-[50%]">Detalle</th>
                <th className="px-6 py-5 text-right w-[30%]">Importe</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => {
                const style = getTxStyle(tx);
                return (
                  <tr 
                    key={tx.id} 
                    onClick={() => { setViewingTx(tx); setConfirmDeleteInModal(false); }}
                    className="hover:bg-slate-50 transition-all group cursor-pointer active:bg-slate-100"
                  >
                    <td className="px-6 py-6 text-[11px] font-black text-slate-500 uppercase">
                      {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex items-center gap-4 overflow-hidden">
                        <div className={`flex w-9 h-9 rounded-xl items-center justify-center flex-shrink-0 shadow-sm ${style.bg} ${style.color}`}>
                          {style.icon}
                        </div>
                        <div className="min-w-0 flex flex-col">
                          <span className="font-black text-slate-800 text-[13px] truncate leading-tight">
                            {tx.description}
                          </span>
                          <span className="text-[9px] font-black text-slate-400 uppercase tracking-wider mt-0.5 truncate">{tx.category}</span>
                        </div>
                      </div>
                    </td>
                    <td className={`px-6 py-6 text-right font-black text-lg ${style.color}`}>
                      {tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTx.length === 0 && (
            <div className="py-24 text-center flex flex-col items-center gap-4">
               <div className="w-16 h-16 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center"><AlertCircle size={32} /></div>
               <p className="text-slate-400 font-bold italic uppercase tracking-widest text-[11px]">No se encontraron movimientos</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal Detalles */}
      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[80] flex items-center justify-center p-4" onClick={() => { setViewingTx(null); setConfirmDeleteInModal(false); }}>
          <div className="bg-white rounded-[3.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100" onClick={e => e.stopPropagation()}>
            <div className="flex flex-col items-center text-center gap-8">
              <div className={`w-24 h-24 rounded-[2rem] flex items-center justify-center shadow-lg ${getTxStyle(viewingTx).bg} ${getTxStyle(viewingTx).color}`}>
                {React.cloneElement(getTxStyle(viewingTx).icon as React.ReactElement, { size: 48 })}
              </div>

              <div>
                <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-2">{viewingTx.category}</p>
                <h3 className="text-2xl font-black text-slate-900 leading-tight">
                  {viewingTx.description}
                </h3>
              </div>

              <div className="w-full bg-slate-50 rounded-[2.5rem] p-8 space-y-5 border border-slate-100">
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-slate-500 uppercase">Monto</span>
                  <span className={`text-3xl font-black ${getTxStyle(viewingTx).color}`}>
                    {viewingTx.type === 'income' ? '+' : '-'}{Math.abs(viewingTx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                  </span>
                </div>
                <div className="h-px bg-slate-200 w-full opacity-50"></div>
                <div className="flex justify-between items-center text-sm font-black text-slate-800">
                  <span className="text-xs font-bold text-slate-500 uppercase">Cuenta</span>
                  <span>{accounts.find(a => a.id === viewingTx.accountId)?.name || 'Desconocida'}</span>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 w-full">
                <button onClick={() => startEdit(viewingTx)} className="py-5 bg-white border-2 border-slate-100 text-slate-800 font-black rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-50">
                  <Edit2 size={18} /> EDITAR
                </button>
                {confirmDeleteInModal ? (
                  <button onClick={() => handleDeleteFromModal(viewingTx.id)} className="py-5 bg-rose-600 text-white font-black rounded-2xl animate-in zoom-in">CONFIRMAR</button>
                ) : (
                  <button onClick={() => setConfirmDeleteInModal(true)} className="py-5 bg-rose-50 text-rose-600 border-2 border-rose-100 font-black rounded-2xl flex items-center justify-center gap-2">
                    <Trash2 size={18} /> BORRAR
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Añadir/Editar */}
      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/75 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-200 overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center mb-10">
                  <h3 className="text-3xl font-black text-slate-900">{editingTx ? 'Editar' : 'Nuevo Movimiento'}</h3>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-4 hover:bg-slate-100 rounded-full text-slate-400"><X size={28} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 p-2 rounded-[1.8rem] border border-slate-200 shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-600' : 'text-slate-500'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>INGRESO</button>
                    <button type="button" onClick={() => setType('saving')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'saving' ? 'bg-white shadow-md text-amber-600' : 'text-slate-500'}`}>AHORRO</button>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Descripción</label>
                      <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none focus:border-blue-400 transition-all placeholder:text-slate-300" placeholder="Ej: Ahorro para vacaciones" required />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Importe (€)</label>
                        <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-black text-xl outline-none" required />
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Fecha</label>
                        <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none" required />
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">
                          {type === 'saving' ? 'Hucha Destino' : 'Categoría'}
                        </label>
                        <div className="relative">
                          {type === 'saving' ? (
                            <select value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none" required>
                              <option value="">Selecciona hucha</option>
                              {savings.map(s => <option key={s.id} value={s.id}>{s.emoji} {s.name}</option>)}
                            </select>
                          ) : (
                            <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none">
                              {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                          )}
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Cuenta Origen</label>
                        <div className="relative">
                          <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none">
                            {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                          </select>
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                    </div>

                    {/* Vínculo a Reembolsos (Solo si no es ahorro) */}
                    {type !== 'saving' && (
                      <div className="pt-4">
                         <button 
                           type="button"
                           onClick={() => setIsRefundLink(!isRefundLink)}
                           className={`w-full flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${isRefundLink ? 'bg-blue-50 border-blue-400 text-blue-700' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                         >
                           <div className="flex items-center gap-3">
                             {type === 'expense' ? <Split size={20} /> : <UserCheck size={20} />}
                             <span className="font-bold text-sm">{type === 'expense' ? 'Dividir gasto / Préstamo' : 'Cobro de reembolso'}</span>
                           </div>
                           <Check size={20} className={isRefundLink ? 'text-blue-600 opacity-100' : 'opacity-0'} />
                         </button>

                         {isRefundLink && (
                           <div className="mt-4 p-5 bg-blue-50 rounded-2xl border-2 border-blue-100 space-y-4">
                             {type === 'expense' ? (
                               <>
                                 <label className="block text-[11px] font-black text-blue-700 uppercase">Tu Parte (Gasto Neto)</label>
                                 <input type="number" value={myPartManual} onChange={e => setMyPartManual(Number(e.target.value))} className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-black outline-none text-center" placeholder="Cuanto pagas tú" />
                               </>
                             ) : (
                               <>
                                 <label className="block text-[11px] font-black text-blue-700 uppercase">Vincular a Deuda</label>
                                 <select value={selectedRefundId} onChange={e => setSelectedRefundId(e.target.value)} className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-bold outline-none" required>
                                   <option value="">Selecciona deuda pendiente</option>
                                   {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} ({r.pendingAmount}€)</option>)}
                                 </select>
                               </>
                             )}
                           </div>
                         )}
                      </div>
                    )}
                  </div>

                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-700 font-black rounded-2xl">CANCELAR</button>
                    <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100">{editingTx ? 'GUARDAR' : 'CONFIRMAR'}</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  Camera, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  Loader2, 
  X, 
  Receipt, 
  UserCheck, 
  Calendar, 
  AlertCircle, 
  Check, 
  ArrowRightLeft, 
  PiggyBank, 
  Sparkles, 
  ChevronDown, 
  Wallet, 
  Split 
} from 'lucide-react';
import { analyzeReceipt } from '../services/geminiService';
import { Transaction } from '../types';

interface ScannedItem {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  intent: 'standard' | 'transfer' | 'savings' | 'refund';
  accountId: string;
  targetId?: string; 
  myPart?: number; 
}

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  // RESTRICCIÓN: Solo categorías que existen en los presupuestos
  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];
    const budgetList = budgets
      .filter(b => b.type === (type === 'saving' ? 'expense' : type))
      .map(b => b.category);

    return budgetList.length > 0 ? budgetList : ["Sin Presupuesto"];
  }, [type, budgets]);

  useEffect(() => {
    if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
    if (location.state?.openScanner) {
      fileInputRef.current?.click();
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setSelectedSavingId('');
    setMyPartManual('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);

    const isSavingType = tx.type === 'expense' && !!tx.savingId;
    setType(isSavingType ? 'saving' : tx.type);

    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setSelectedSavingId(tx.savingId || '');
    setIsAdding(true);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  // Fix: Defined handleDeleteFromModal to resolve reference error on line 317
  const handleDeleteFromModal = (id: string) => {
    deleteTransaction(id);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    const finalType = type === 'saving' ? 'expense' : type;
    const finalCategory = type === 'saving' ? 'Ahorro' : category;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date,
        amount: Number(amount),
        description: desc,
        category: finalCategory,
        type: finalType,
        accountId,
        refundId: selectedRefundId || undefined,
        savingId: type === 'saving' ? selectedSavingId : undefined
      });
    } else {
      addTransaction({
        date,
        amount: Number(amount),
        description: desc,
        category: finalCategory,
        type: finalType,
        accountId,
        isRefund: isRefundLink,
        refundId: finalType === 'income' && isRefundLink ? selectedRefundId : undefined,
        savingId: type === 'saving' ? selectedSavingId : undefined
      }, finalType === 'expense' && isRefundLink ? (myPartManual === ' ' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      let matchesType = true;
      const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
      const isRefund = t.type === 'income' && !!t.refundId;

      if (filter === 'income') matchesType = t.type === 'income' && !t.refundId;
      else if (filter === 'expense') matchesType = t.type === 'expense' && !isSaving;
      else if (filter === 'savings') matchesType = isSaving;
      else if (filter === 'refunds') matchesType = isRefund;

      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const getTxStyle = (t: Transaction) => {
    const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
    const isRefund = t.type === 'income' && !!t.refundId;

    if (isSaving) return { color: 'text-amber-600', bg: 'bg-amber-50', icon: <PiggyBank size={18} /> };
    if (isRefund) return { color: 'text-blue-600', bg: 'bg-blue-50', icon: <ArrowUpRight size={18} /> };
    if (t.type === 'income') return { color: 'text-emerald-600', bg: 'bg-emerald-50', icon: <ArrowUpRight size={18} /> };
    return { color: 'text-rose-600', bg: 'bg-rose-50', icon: <ArrowDownRight size={18} /> };
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Transacciones</h2>
          <p className="text-slate-700 font-bold">Historial de movimientos categorizados.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
            <Plus size={20} /> 
            <span>Nuevo Movimiento</span>
          </button>
        </div>
      </div>

      {/* Main Container */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        {/* Filtros Expandidos */}
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col gap-6 bg-slate-50/30">
          <div className="flex flex-wrap items-center gap-1 bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm w-full">
            <button onClick={() => setFilter('all')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>AHORROS</button>
            <button onClick={() => setFilter('refunds')} className={`flex-1 px-4 py-2.5 text-[11px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 text-white shadow-lg' : 'text-slate-600 hover:text-slate-800'}`}>REEMBOLSOS</button>
          </div>

          <div className="flex items-center gap-3 bg-white px-5 py-3 rounded-2xl border border-slate-200 w-full shadow-sm focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <Search size={18} className="text-slate-500" />
            <input 
              type="text" 
              placeholder="Buscar por descripción o categoría..." 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Tabla */}
        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse table-fixed">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] uppercase tracking-[0.15em] text-slate-400 font-black border-b border-slate-100">
                <th className="px-6 py-5 text-left w-[20%]">Fecha</th>
                <th className="px-6 py-5 text-left w-[50%]">Detalle</th>
                <th className="px-6 py-5 text-right w-[30%]">Importe</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => {
                const style = getTxStyle(tx);
                return (
                  <tr 
                    key={tx.id} 
                    onClick={() => { setViewingTx(tx); setConfirmDeleteInModal(false); }}
                    className="hover:bg-slate-50 transition-all group cursor-pointer active:bg-slate-100"
                  >
                    <td className="px-6 py-6 text-[11px] font-black text-slate-500 uppercase">
                      {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex items-center gap-4 overflow-hidden">
                        <div className={`flex w-9 h-9 rounded-xl items-center justify-center flex-shrink-0 shadow-sm ${style.bg} ${style.color}`}>
                          {style.icon}
                        </div>
                        <div className="min-w-0 flex flex-col">
                          <span className="font-black text-slate-800 text-[13px] truncate leading-tight">
                            {tx.description}
                          </span>
                          <span className="text-[9px] font-black text-slate-400 uppercase tracking-wider mt-0.5 truncate">{tx.category}</span>
                        </div>
                      </div>
                    </td>
                    <td className={`px-6 py-6 text-right font-black text-lg ${style.color}`}>
                      {tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTx.length === 0 && (
            <div className="py-24 text-center flex flex-col items-center gap-4">
               <div className="w-16 h-16 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center"><AlertCircle size={32} /></div>
               <p className="text-slate-400 font-bold italic uppercase tracking-widest text-[11px]">No se encontraron movimientos</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal Detalles */}
      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[80] flex items-center justify-center p-4" onClick={() => { setViewingTx(null); setConfirmDeleteInModal(false); }}>
          <div className="bg-white rounded-[3.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100" onClick={e => e.stopPropagation()}>
            <div className="flex flex-col items-center text-center gap-8">
              <div className={`w-24 h-24 rounded-[2rem] flex items-center justify-center shadow-lg ${getTxStyle(viewingTx).bg} ${getTxStyle(viewingTx).color}`}>
                {React.cloneElement(getTxStyle(viewingTx).icon as React.ReactElement, { size: 48 })}
              </div>

              <div>
                <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-2">{viewingTx.category}</p>
                <h3 className="text-2xl font-black text-slate-900 leading-tight">
                  {viewingTx.description}
                </h3>
              </div>

              <div className="w-full bg-slate-50 rounded-[2.5rem] p-8 space-y-5 border border-slate-100">
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-slate-500 uppercase">Monto</span>
                  <span className={`text-3xl font-black ${getTxStyle(viewingTx).color}`}>
                    {viewingTx.type === 'income' ? '+' : '-'}{Math.abs(viewingTx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                  </span>
                </div>
                <div className="h-px bg-slate-200 w-full opacity-50"></div>
                <div className="flex justify-between items-center text-sm font-black text-slate-800">
                  <span className="text-xs font-bold text-slate-500 uppercase">Cuenta</span>
                  <span>{accounts.find(a => a.id === viewingTx.accountId)?.name || 'Desconocida'}</span>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 w-full">
                <button onClick={() => startEdit(viewingTx)} className="py-5 bg-white border-2 border-slate-100 text-slate-800 font-black rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-50">
                  <Edit2 size={18} /> EDITAR
                </button>
                {confirmDeleteInModal ? (
                  <button onClick={() => handleDeleteFromModal(viewingTx.id)} className="py-5 bg-rose-600 text-white font-black rounded-2xl animate-in zoom-in">CONFIRMAR</button>
                ) : (
                  <button onClick={() => setConfirmDeleteInModal(true)} className="py-5 bg-rose-50 text-rose-600 border-2 border-rose-100 font-black rounded-2xl flex items-center justify-center gap-2">
                    <Trash2 size={18} /> BORRAR
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Añadir/Editar */}
      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/75 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-200 overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center mb-10">
                  <h3 className="text-3xl font-black text-slate-900">{editingTx ? 'Editar' : 'Nuevo Movimiento'}</h3>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-4 hover:bg-slate-100 rounded-full text-slate-400"><X size={28} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 p-2 rounded-[1.8rem] border border-slate-200 shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-600' : 'text-slate-500'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>INGRESO</button>
                    <button type="button" onClick={() => setType('saving')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'saving' ? 'bg-white shadow-md text-amber-600' : 'text-slate-500'}`}>AHORRO</button>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Descripción</label>
                      <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none focus:border-blue-400 transition-all placeholder:text-slate-300" placeholder="Ej: Ahorro para vacaciones" required />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Importe (€)</label>
                        <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-black text-xl outline-none" required />
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Fecha</label>
                        <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none" required />
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">
                          {type === 'saving' ? 'Hucha Destino' : 'Categoría'}
                        </label>
                        <div className="relative">
                          {type === 'saving' ? (
                            <select value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none" required>
                              <option value="">Selecciona hucha</option>
                              {savings.map(s => <option key={s.id} value={s.id}>{s.emoji} {s.name}</option>)}
                            </select>
                          ) : (
                            <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none">
                              {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                          )}
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Cuenta Origen</label>
                        <div className="relative">
                          <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none">
                            {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                          </select>
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                    </div>

                    {/* Vínculo a Reembolsos (Solo si no es ahorro) */}
                    {type !== 'saving' && (
                      <div className="pt-4">
                         <button 
                           type="button"
                           onClick={() => setIsRefundLink(!isRefundLink)}
                           className={`w-full flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${isRefundLink ? 'bg-blue-50 border-blue-400 text-blue-700' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                         >
                           <div className="flex items-center gap-3">
                             {type === 'expense' ? <Split size={20} /> : <UserCheck size={20} />}
                             <span className="font-bold text-sm">{type === 'expense' ? 'Dividir gasto / Préstamo' : 'Cobro de reembolso'}</span>
                           </div>
                           <Check size={20} className={isRefundLink ? 'text-blue-600 opacity-100' : 'opacity-0'} />
                         </button>

                         {isRefundLink && (
                           <div className="mt-4 p-5 bg-blue-50 rounded-2xl border-2 border-blue-100 space-y-4">
                             {type === 'expense' ? (
                               <>
                                 <label className="block text-[11px] font-black text-blue-700 uppercase">Tu Parte (Gasto Neto)</label>
                                 <input type="number" value={myPartManual} onChange={e => setMyPartManual(Number(e.target.value))} className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-black outline-none text-center" placeholder="Cuanto pagas tú" />
                               </>
                             ) : (
                               <>
                                 <label className="block text-[11px] font-black text-blue-700 uppercase">Vincular a Deuda</label>
                                 <select value={selectedRefundId} onChange={e => setSelectedRefundId(e.target.value)} className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-bold outline-none" required>
                                   <option value="">Selecciona deuda pendiente</option>
                                   {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} ({r.pendingAmount}€)</option>)}
                                 </select>
                               </>
                             )}
                           </div>
                         )}
                      </div>
                    )}
                  </div>

                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-700 font-black rounded-2xl">CANCELAR</button>
                    <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100">{editingTx ? 'GUARDAR' : 'CONFIRMAR'}</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  X, 
  UserCheck, 
  AlertCircle, 
  Check, 
  PiggyBank, 
  ChevronDown, 
  Split 
} from 'lucide-react';
import { Transaction } from '../types';

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  // RESTRICCIÓN: Solo categorías que existen en los presupuestos
  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];

    // Obtenemos categorías de presupuestos según el tipo de transacción
    const budgetList = budgets
      .filter(b => b.type === (type === 'saving' ? 'expense' : type))
      .map(b => b.category);

    return budgetList.length > 0 ? budgetList : ["Sin Presupuesto"];
  }, [type, budgets]);

  useEffect(() => {
    if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setSelectedSavingId('');
    setMyPartManual('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);

    const isSavingType = tx.type === 'expense' && !!tx.savingId;
    setType(isSavingType ? 'saving' : tx.type);

    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setSelectedSavingId(tx.savingId || '');
    setIsAdding(true);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleDeleteFromModal = (id: string) => {
    deleteTransaction(id);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    const finalType = type === 'saving' ? 'expense' : type;
    const finalCategory = type === 'saving' ? 'Ahorro' : category;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date,
        amount: Number(amount),
        description: desc,
        category: finalCategory,
        type: finalType,
        accountId,
        refundId: selectedRefundId || undefined,
        savingId: type === 'saving' ? selectedSavingId : undefined
      });
    } else {
      addTransaction({
        date,
        amount: Number(amount),
        description: desc,
        category: finalCategory,
        type: finalType,
        accountId,
        isRefund: isRefundLink,
        refundId: finalType === 'income' && isRefundLink ? selectedRefundId : undefined,
        savingId: type === 'saving' ? selectedSavingId : undefined
      }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      let matchesType = true;
      const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
      const isRefund = t.type === 'income' && !!t.refundId;

      if (filter === 'income') matchesType = t.type === 'income' && !t.refundId;
      else if (filter === 'expense') matchesType = t.type === 'expense' && !isSaving;
      else if (filter === 'savings') matchesType = isSaving;
      else if (filter === 'refunds') matchesType = isRefund;

      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  // Estilo visual según los 4 estados requeridos
  const getTxStyle = (t: Transaction) => {
    const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
    const isRefund = t.type === 'income' && !!t.refundId;

    if (isSaving) return { color: 'text-amber-500', bg: 'bg-amber-50', icon: <ArrowUpRight size={18} /> }; // Flecha amarilla/naranja
    if (isRefund) return { color: 'text-blue-600', bg: 'bg-blue-50', icon: <ArrowUpRight size={18} /> }; // Flecha azul
    if (t.type === 'income') return { color: 'text-emerald-600', bg: 'bg-emerald-50', icon: <ArrowUpRight size={18} /> }; // Flecha verde
    return { color: 'text-rose-600', bg: 'bg-rose-50', icon: <ArrowDownRight size={18} /> }; // Flecha roja
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Transacciones</h2>
          <p className="text-slate-700 font-bold text-sm">Historial financiero con filtros avanzados.</p>
        </div>
        <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
          <Plus size={20} /> 
          <span>Nueva Transacción</span>
        </button>
      </div>

      {/* Main Container */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        {/* Filtros en una sola línea */}
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col gap-4 bg-slate-50/30">
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-200 shadow-sm w-full overflow-x-auto no-scrollbar">
            <button onClick={() => setFilter('all')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>AHORROS</button>
            <button onClick={() => setFilter('refunds')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>REEMBOLSOS</button>
          </div>

          <div className="flex items-center gap-3 bg-white px-5 py-3 rounded-2xl border border-slate-200 w-full shadow-sm focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <Search size={18} className="text-slate-500" />
            <input 
              type="text" 
              placeholder="Buscar transacción..." 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Tabla */}
        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse table-fixed">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] uppercase tracking-[0.15em] text-slate-400 font-black border-b border-slate-100">
                <th className="px-6 py-5 text-left w-[25%] md:w-[20%]">Fecha</th>
                <th className="px-6 py-5 text-left w-[45%] md:w-[50%]">Detalle</th>
                <th className="px-6 py-5 text-right w-[30%]">Importe</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => {
                const style = getTxStyle(tx);
                return (
                  <tr 
                    key={tx.id} 
                    onClick={() => { setViewingTx(tx); setConfirmDeleteInModal(false); }}
                    className="hover:bg-slate-50 transition-all group cursor-pointer active:bg-slate-100"
                  >
                    <td className="px-6 py-6 text-[11px] font-black text-slate-500 uppercase">
                      {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex items-center gap-4 overflow-hidden">
                        <div className={`flex w-9 h-9 rounded-xl items-center justify-center flex-shrink-0 shadow-sm ${style.bg} ${style.color}`}>
                          {style.icon}
                        </div>
                        <div className="min-w-0 flex flex-col">
                          <span className="font-black text-slate-800 text-[13px] truncate leading-tight">
                            {tx.description}
                          </span>
                          <span className="text-[9px] font-black text-slate-400 uppercase tracking-wider mt-0.5 truncate">{tx.category}</span>
                        </div>
                      </div>
                    </td>
                    <td className={`px-6 py-6 text-right font-black text-lg ${style.color}`}>
                      {tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTx.length === 0 && (
            <div className="py-24 text-center flex flex-col items-center gap-4">
               <div className="w-16 h-16 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center"><AlertCircle size={32} /></div>
               <p className="text-slate-400 font-bold italic uppercase tracking-widest text-[11px]">No se encontraron movimientos</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal Detalles */}
      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[80] flex items-center justify-center p-4" onClick={() => { setViewingTx(null); setConfirmDeleteInModal(false); }}>
          <div className="bg-white rounded-[3.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100" onClick={e => e.stopPropagation()}>
            <div className="flex flex-col items-center text-center gap-8">
              <div className={`w-24 h-24 rounded-[2rem] flex items-center justify-center shadow-lg ${getTxStyle(viewingTx).bg} ${getTxStyle(viewingTx).color}`}>
                {React.cloneElement(getTxStyle(viewingTx).icon as React.ReactElement, { size: 48 })}
              </div>

              <div>
                <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-2">{viewingTx.category}</p>
                <h3 className="text-2xl font-black text-slate-900 leading-tight">
                  {viewingTx.description}
                </h3>
              </div>

              <div className="w-full bg-slate-50 rounded-[2.5rem] p-8 space-y-5 border border-slate-100">
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-slate-500 uppercase">Monto</span>
                  <span className={`text-3xl font-black ${getTxStyle(viewingTx).color}`}>
                    {viewingTx.type === 'income' ? '+' : '-'}{Math.abs(viewingTx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                  </span>
                </div>
                <div className="h-px bg-slate-200 w-full opacity-50"></div>
                <div className="flex justify-between items-center text-sm font-black text-slate-800">
                  <span className="text-xs font-bold text-slate-500 uppercase">Cuenta</span>
                  <span>{accounts.find(a => a.id === viewingTx.accountId)?.name || 'Desconocida'}</span>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 w-full">
                <button onClick={() => startEdit(viewingTx)} className="py-5 bg-white border-2 border-slate-100 text-slate-800 font-black rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-50">
                  <Edit2 size={18} /> EDITAR
                </button>
                {confirmDeleteInModal ? (
                  <button onClick={() => handleDeleteFromModal(viewingTx.id)} className="py-5 bg-rose-600 text-white font-black rounded-2xl animate-in zoom-in">CONFIRMAR</button>
                ) : (
                  <button onClick={() => setConfirmDeleteInModal(true)} className="py-5 bg-rose-50 text-rose-600 border-2 border-rose-100 font-black rounded-2xl flex items-center justify-center gap-2">
                    <Trash2 size={18} /> BORRAR
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Añadir/Editar */}
      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/75 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-200 overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center mb-10">
                  <h3 className="text-3xl font-black text-slate-900 tracking-tight">{editingTx ? 'Editar' : 'Nuevo Movimiento'}</h3>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-4 hover:bg-slate-100 rounded-full text-slate-400"><X size={28} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 p-2 rounded-[1.8rem] border border-slate-200 shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-600' : 'text-slate-500'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>INGRESO</button>
                    <button type="button" onClick={() => setType('saving')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'saving' ? 'bg-white shadow-md text-amber-500' : 'text-slate-500'}`}>AHORRO</button>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Descripción</label>
                      <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none focus:border-blue-400 transition-all placeholder:text-slate-300" placeholder="Ej: Supermercado..." required />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Importe (€)</label>
                        <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-black text-xl outline-none" required />
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Fecha</label>
                        <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none" required />
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">
                          {type === 'saving' ? 'Hucha Destino' : 'Categoría (Presupuesto)'}
                        </label>
                        <div className="relative">
                          {type === 'saving' ? (
                            <select value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none" required>
                              <option value="">Selecciona hucha</option>
                              {savings.map(s => <option key={s.id} value={s.id}>{s.emoji} {s.name}</option>)}
                            </select>
                          ) : (
                            <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none" required>
                              {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                          )}
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Cuenta Origen</label>
                        <div className="relative">
                          <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none">
                            {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                          </select>
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                    </div>

                    {/* Vínculos Especiales (Reembolsos) */}
                    {type !== 'saving' && (
                      <div className="pt-4">
                         <button 
                           type="button"
                           onClick={() => setIsRefundLink(!isRefundLink)}
                           className={`w-full flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${isRefundLink ? 'bg-blue-50 border-blue-400 text-blue-700' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                         >
                           <div className="flex items-center gap-3">
                             {type === 'expense' ? <Split size={20} /> : <UserCheck size={20} />}
                             <span className="font-bold text-sm">{type === 'expense' ? 'Dividir gasto / Préstamo' : 'Cobro de reembolso'}</span>
                           </div>
                           <Check size={20} className={isRefundLink ? 'text-blue-600 opacity-100' : 'opacity-0'} />
                         </button>

                         {isRefundLink && (
                           <div className="mt-4 p-5 bg-blue-50 rounded-2xl border-2 border-blue-100 space-y-4 animate-in slide-in-from-top-2 duration-300">
                             {type === 'expense' ? (
                               <>
                                 <label className="block text-[11px] font-black text-blue-700 uppercase">Tu Parte (Gasto Neto)</label>
                                 <input type="number" value={myPartManual} onChange={e => setMyPartManual(Number(e.target.value))} className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-black outline-none text-center" placeholder="Cuanto pagas tú" />
                               </>
                             ) : (
                               <>
                                 <label className="block text-[11px] font-black text-blue-700 uppercase">Vincular a Deuda</label>
                                 <select value={selectedRefundId} onChange={e => setSelectedRefundId(e.target.value)} className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-bold outline-none" required>
                                   <option value="">Selecciona deuda pendiente</option>
                                   {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} ({r.pendingAmount}€)</option>)}
                                 </select>
                               </>
                             )}
                           </div>
                         )}
                      </div>
                    )}
                  </div>

                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-700 font-black rounded-2xl">CANCELAR</button>
                    <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100">{editingTx ? 'GUARDAR' : 'CONFIRMAR'}</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  Edit2, 
  Trash2, 
  ShoppingBag, 
  ChevronRight, 
  X, 
  ArrowUpRight, 
  ArrowDownRight, 
  ArrowLeftRight,
  TrendingDown,
  TrendingUp,
  AlertCircle,
  Calendar,
  Wallet,
  Tag,
  ArrowDownLeft,
  ChevronDown,
  History,
  ArrowRight
} from 'lucide-react';
import { Budget, Transaction } from '../types';
import { CATEGORIES, INCOME_CATEGORIES, ICON_MAP } from '../constants';

const BudgetManager: React.FC = () => {
  const { budgets, transactions, currentDate, updateBudget, addBudget, deleteBudget, accounts } = useFinance();

  // UI States
  const [activeTab, setActiveTab] = useState<'expense' | 'income'>('expense');
  const [selectedBudget, setSelectedBudget] = useState<Budget | null>(null);
  const [isEditing, setIsEditing] = useState<Budget | null>(null);
  const [isCreating, setIsCreating] = useState(false);

  // Form States
  const [category, setCategory] = useState('');
  const [limit, setLimit] = useState<number | ''>('');
  const [customCategory, setCustomCategory] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [selectedIcon, setSelectedIcon] = useState('ShoppingBag');

  const filteredBudgets = useMemo(() => {
    return budgets.filter(b => b.type === activeTab);
  }, [budgets, activeTab]);

  const budgetTransactions = useMemo(() => {
    if (!selectedBudget) return [];
    return transactions.filter(t => 
      t.category === selectedBudget.category && 
      t.type === selectedBudget.type &&
      t.date.startsWith(currentDate)
    ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedBudget, transactions, currentDate]);

  const totals = useMemo(() => {
    const b = budgets.filter(x => x.type === activeTab);
    return {
      limit: b.reduce((s, x) => s + x.limit, 0),
      actual: b.reduce((s, x) => s + x.spent, 0)
    };
  }, [budgets, activeTab]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const finalCategory = isCustomMode ? customCategory : category;
    if (!finalCategory || limit === '') return;

    if (isEditing) {
      updateBudget({ ...isEditing, category: finalCategory, limit: Number(limit), icon: selectedIcon });
      setIsEditing(null);
    } else {
      addBudget({ 
        category: finalCategory, 
        limit: Number(limit), 
        type: activeTab,
        spent: 0,
        icon: selectedIcon
      });
      setIsCreating(false);
    }
    resetForm();
  };

  const resetForm = () => {
    setCategory('');
    setLimit('');
    setCustomCategory('');
    setIsCustomMode(false);
    setSelectedIcon('ShoppingBag');
  };

  const openCreate = () => {
    resetForm();
    const defaultCats = activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    setCategory(defaultCats[0].name);
    setSelectedIcon(defaultCats[0].icon);
    setIsCreating(true);
  };

  const openEdit = (b: Budget) => {
    const defaultCats = b.type === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    const isStandard = defaultCats.some(c => c.name === b.category);

    setCategory(isStandard ? b.category : 'Otra');
    setCustomCategory(isStandard ? '' : b.category);
    setIsCustomMode(!isStandard);
    setLimit(b.limit);
    setSelectedIcon(b.icon);
    setIsEditing(b);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Presupuestos</h2>
          <p className="text-slate-500 font-medium">Controla tus finanzas de {currentDate} con precisión.</p>
        </div>
        <button 
          onClick={openCreate}
          className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95"
        >
          <Plus size={20} />
          Nuevo Límite
        </button>
      </div>

      <div className="flex items-center gap-1 bg-slate-100 p-1.5 rounded-3xl w-full md:w-fit border border-slate-200 shadow-inner">
        <button 
          onClick={() => setActiveTab('expense')} 
          className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'expense' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <TrendingDown size={16} /> GASTOS
        </button>
        <button 
          onClick={() => setActiveTab('income')} 
          className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'income' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <TrendingUp size={16} /> INGRESOS
        </button>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className={`p-6 rounded-[2.5rem] border shadow-sm flex items-center gap-4 bg-white border-slate-100`}>
          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${activeTab === 'expense' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
            <ShoppingBag size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total {activeTab === 'expense' ? 'Presupuestado' : 'Objetivo'}</p>
            <p className="text-2xl font-black text-slate-800">{totals.limit.toLocaleString()}€</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-4">
          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center bg-blue-50 text-blue-600`}>
            <ArrowLeftRight size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{activeTab === 'expense' ? 'Consumo Real' : 'Ingreso Real'}</p>
            <p className="text-2xl font-black text-blue-600">{totals.actual.toLocaleString()}€</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {filteredBudgets.map(b => {
          const progress = b.limit > 0 ? Math.min((b.spent / b.limit) * 100, 100) : 0;
          return (
            <div 
              key={b.id} 
              onClick={() => setSelectedBudget(b)}
              className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm hover:shadow-md transition-all group cursor-pointer active:scale-[0.99]"
            >
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner ${activeTab === 'expense' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                    {ICON_MAP[b.icon] || <Tag size={24} />}
                  </div>
                  <div>
                    <h4 className="text-lg font-black text-slate-800 tracking-tight">{b.category}</h4>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{activeTab === 'expense' ? 'Gasto' : 'Ingreso'}</p>
                  </div>
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                  <button onClick={(e) => { e.stopPropagation(); openEdit(b); }} className="p-2.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl"><Edit2 size={18} /></button>
                  <button onClick={(e) => { e.stopPropagation(); if(confirm('¿Seguro que quieres eliminar este presupuesto?')) deleteBudget(b.id); }} className="p-2.5 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl"><Trash2 size={18} /></button>
                </div>
              </div>

              <div className="space-y-5">
                <div className="flex justify-between items-end">
                   <div>
                      <p className={`text-4xl font-black tracking-tight ${activeTab === 'expense' && b.spent > b.limit ? 'text-rose-500' : 'text-slate-900'}`}>{b.spent.toLocaleString('es-ES')}€</p>
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">de {b.limit.toLocaleString()}€ {activeTab === 'expense' ? 'definidos' : 'objetivo'}</p>
                   </div>
                   <div className="text-right">
                      <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider ${activeTab === 'expense' ? (b.spent > b.limit ? 'bg-rose-50 text-rose-500' : progress > 85 ? 'bg-amber-50 text-amber-500' : 'bg-emerald-50 text-emerald-500') : (b.spent >= b.limit ? 'bg-emerald-50 text-emerald-500' : 'bg-blue-50 text-blue-500')}`}>
                        {activeTab === 'expense' ? (b.spent > b.limit ? 'Excedido' : progress > 85 ? 'Cuidado' : 'Correcto') : (b.spent >= b.limit ? 'Logrado' : 'En progreso')}
                      </span>
                   </div>
                </div>
                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                  <div className={`h-full rounded-full transition-all duration-1000 ease-out ${activeTab === 'expense' ? (b.spent > b.limit ? 'bg-rose-500' : progress > 85 ? 'bg-amber-400' : 'bg-blue-500') : (b.spent >= b.limit ? 'bg-emerald-500' : 'bg-blue-500')}`} style={{ width: `${progress}%` }}></div>
                </div>
                <div className="flex items-center justify-between">
                   <p className="text-xs text-slate-400 font-bold flex items-center gap-1"><ChevronRight size={14} className="text-blue-500" /> Ver detalles</p>
                   {activeTab === 'expense' && b.limit > b.spent && (
                     <p className="text-xs font-black text-slate-700">Dispones de {(b.limit - b.spent).toLocaleString()}€ más</p>
                   )}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Modal Ver Detalles (Transacciones de la Categoría) */}
      {selectedBudget && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[60] flex items-center justify-center p-4" onClick={() => setSelectedBudget(null)}>
          <div className="bg-white rounded-[3rem] w-full max-w-lg p-8 md:p-10 shadow-2xl animate-in fade-in zoom-in duration-300 border border-slate-100 overflow-hidden flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-start mb-8 flex-shrink-0">
               <div className="flex items-center gap-5">
                  <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-lg ${selectedBudget.type === 'expense' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                    {React.cloneElement(ICON_MAP[selectedBudget.icon] as React.ReactElement, { size: 28 })}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">{selectedBudget.category}</h3>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Movimientos de {currentDate}</p>
                  </div>
               </div>
               <button onClick={() => setSelectedBudget(null)} className="p-3 hover:bg-slate-100 rounded-full text-slate-400"><X size={24} /></button>
            </div>

            <div className="bg-slate-50 rounded-3xl p-6 mb-8 border border-slate-100 flex-shrink-0">
               <div className="flex justify-between items-end mb-4">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Total acumulado</p>
                    <p className="text-3xl font-black text-slate-900">{selectedBudget.spent.toLocaleString()}€</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Límite</p>
                    <p className="text-lg font-bold text-slate-600">{selectedBudget.limit.toLocaleString()}€</p>
                  </div>
               </div>
               <div className="w-full h-3 bg-white rounded-full overflow-hidden border border-slate-200">
                  <div 
                    className={`h-full rounded-full transition-all duration-1000 ${selectedBudget.type === 'expense' ? (selectedBudget.spent > selectedBudget.limit ? 'bg-rose-500' : 'bg-blue-600') : 'bg-emerald-500'}`} 
                    style={{ width: `${Math.min((selectedBudget.spent / selectedBudget.limit) * 100, 100)}%` }}
                  ></div>
               </div>
            </div>

            <div className="flex items-center gap-2 mb-4 flex-shrink-0">
              <History size={16} className="text-slate-400" />
              <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">Historial Reciente</h4>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 pr-2">
              {budgetTransactions.length > 0 ? budgetTransactions.map(tx => (
                <div key={tx.id} className="flex justify-between items-center p-4 bg-white border border-slate-100 rounded-2xl hover:border-blue-200 transition-colors">
                  <div className="flex items-center gap-4">
                    <div className="text-center bg-slate-50 w-10 py-1.5 rounded-xl border border-slate-100">
                      <p className="text-[8px] font-black text-slate-400 uppercase">{new Date(tx.date).toLocaleDateString('es-ES', { month: 'short' })}</p>
                      <p className="text-xs font-black text-slate-700">{new Date(tx.date).getDate()}</p>
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-800 line-clamp-1">{tx.description}</p>
                      <p className="text-[10px] font-medium text-slate-400">{accounts.find(a => a.id === tx.accountId)?.name || 'Cuenta'}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`font-black ${tx.type === 'income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                      {tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€
                    </p>
                  </div>
                </div>
              )) : (
                <div className="text-center py-12 bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200">
                  <AlertCircle size={32} className="mx-auto text-slate-300 mb-3" />
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">No hay transacciones aún</p>
                </div>
              )}
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 flex-shrink-0">
               <button onClick={() => setSelectedBudget(null)} className="w-full py-4 bg-slate-900 text-white font-black rounded-2xl hover:bg-slate-800 transition-all active:scale-[0.98]">ENTENDIDO</button>
            </div>
          </div>
        </div>
      )}

      {(isCreating || isEditing) && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3.5rem] w-full max-w-md p-10 md:p-14 shadow-2xl animate-in fade-in zoom-in duration-300 border border-slate-100 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-3xl font-black text-slate-900 tracking-tight">{isEditing ? 'Editar Límite' : 'Nueva Categoría'}</h3>
              <button onClick={() => { setIsCreating(false); setIsEditing(null); }} className="p-3 hover:bg-slate-100 rounded-full text-slate-400 transition-colors"><X size={24} /></button>
            </div>

            <form onSubmit={handleSave} className="space-y-8">
              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest pl-1">Seleccionar Icono</label>
                <div className="grid grid-cols-6 gap-2 bg-slate-50 p-4 rounded-2xl border border-slate-100 max-h-48 overflow-y-auto custom-scrollbar">
                  {Object.keys(ICON_MAP).map(iconName => (
                    <button 
                      key={iconName} 
                      type="button" 
                      onClick={() => setSelectedIcon(iconName)}
                      className={`p-2.5 rounded-xl flex items-center justify-center transition-all ${selectedIcon === iconName ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-400 hover:bg-slate-100'}`}
                    >
                      {ICON_MAP[iconName]}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest pl-1">Categoría</label>
                <div className="relative">
                  <select 
                    value={category} 
                    onChange={e => {
                      setCategory(e.target.value);
                      const isAnother = e.target.value === 'Otra';
                      setIsCustomMode(isAnother);
                      if(!isAnother) {
                        const defaultList = activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
                        const match = defaultList.find(c => c.name === e.target.value);
                        if(match) setSelectedIcon(match.icon);
                      }
                    }}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-black text-slate-800 focus:bg-white focus:border-blue-400 outline-none transition-all appearance-none cursor-pointer"
                    required
                  >
                    {(activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES).map(c => (
                      <option key={c.name} value={c.name}>{c.name}</option>
                    ))}
                    <option value="Otra">-- Personalizada --</option>
                  </select>
                  <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={20} />
                </div>
                {isCustomMode && (
                  <input type="text" placeholder="Nombre..." className="w-full bg-blue-50 border-2 border-blue-100 rounded-2xl p-5 font-black text-blue-900 outline-none animate-in slide-in-from-top-2" value={customCategory} onChange={e => setCustomCategory(e.target.value)} required />
                )}
              </div>

              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest pl-1">Importe Mensual (€)</label>
                <input type="number" value={limit} onChange={e => setLimit(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-6 text-center text-4xl font-black text-slate-900 outline-none" placeholder="0" required />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => { setIsCreating(false); setIsEditing(null); }} className="flex-1 py-5 bg-slate-100 text-slate-600 font-black rounded-2xl">CANCELAR</button>
                <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100 flex items-center justify-center gap-2 transition-all active:scale-[0.98]">{isEditing ? <Edit2 size={18}/> : <Plus size={18}/>}{isEditing ? 'GUARDAR' : 'CREAR'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetManager;

import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Wallet, 
  PiggyBank, 
  Receipt, 
  BarChart3, 
  MessageSquare,
  ChevronLeft,
  ChevronRight,
  Menu,
  X,
  Plus,
  Camera
} from 'lucide-react';
import { FinanceState, Account, Saving, Refund, Transaction, Budget, AIChallenge } from './types';
import { INITIAL_DATA } from './constants';
import Dashboard from './components/Dashboard.tsx';
import Accounts from './components/Accounts.tsx';
import Savings from './components/Savings.tsx';
import Refunds from './components/Refunds.tsx';
import Transactions from './components/Transactions.tsx';
import BudgetManager from './components/Budget.tsx';
import AIAdvisor from './components/AIAdvisor.tsx';

interface FinanceContextType extends FinanceState {
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon' | 'type'> & { type?: 'income' | 'expense'; icon?: string }) => void;
  updateBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  changeMonth: (offset: number) => void;
  setMonth: (date: string) => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<FinanceState>(() => {
    const saved = localStorage.getItem('finance_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('finance_data', JSON.stringify(state));
  }, [state]);

  const contextValue: FinanceContextType = {
    ...state,
    addTransaction: (t, myPart) => {
      const id = Math.random().toString(36).substr(2, 9);
      let finalTransaction = { ...t, id };

      setState(prev => {
        let updatedRefunds = [...prev.refunds];
        let updatedSavings = [...prev.savings];

        if (t.type === 'income' && t.refundId) {
          const linkedRefund = prev.refunds.find(r => r.id === t.refundId);
          if (linkedRefund) finalTransaction.category = linkedRefund.category;

          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = Math.max(0, r.pendingAmount - t.amount);
              return { ...r, pendingAmount: newPending, status: newPending <= 0 ? 'closed' : 'open' };
            }
            return r;
          });
        }

        if (t.type === 'expense' && t.isRefund) {
          const refundId = 'ref_' + Date.now();
          const partToPay = myPart !== undefined ? myPart : t.amount / 2;
          updatedRefunds.push({
            id: refundId,
            name: t.description,
            totalAmount: t.amount,
            paidByMe: partToPay, 
            pendingAmount: t.amount - partToPay, 
            status: (t.amount - partToPay) <= 0 ? 'closed' : 'open',
            notes: 'Creado desde gasto: ' + t.description,
            date: t.date,
            category: t.category,
            originTransactionId: id
          });
          finalTransaction.refundId = refundId;
        }

        if (t.type === 'expense' && t.savingId) {
          updatedSavings = updatedSavings.map(s => {
            if (s.id === t.savingId) return { ...s, currentAmount: s.currentAmount + t.amount };
            return s;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? t.amount : -t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        const budgets = prev.budgets.map(b => {
          if (finalTransaction.type === 'income' && finalTransaction.refundId) {
            if (b.type === 'expense' && b.category === finalTransaction.category && finalTransaction.date.startsWith(prev.currentDate)) {
              return { ...b, spent: Math.max(0, b.spent - finalTransaction.amount) };
            }
          } else if (finalTransaction.type === b.type && b.category === finalTransaction.category && finalTransaction.date.startsWith(prev.currentDate)) {
            return { ...b, spent: b.spent + finalTransaction.amount };
          }
          return b;
        });

        return {
          ...prev,
          transactions: [finalTransaction, ...prev.transactions],
          accounts,
          budgets,
          refunds: updatedRefunds,
          savings: updatedSavings
        };
      });
    },
    updateTransaction: (updatedTx) => {
      setState(prev => {
        const oldTx = prev.transactions.find(t => t.id === updatedTx.id);
        if (!oldTx) return prev;

        let updatedSavings = [...prev.savings];
        if (oldTx.type === 'expense' && oldTx.savingId) {
          updatedSavings = updatedSavings.map(s => s.id === oldTx.savingId ? { ...s, currentAmount: s.currentAmount - oldTx.amount } : s);
        }
        if (updatedTx.type === 'expense' && updatedTx.savingId) {
          updatedSavings = updatedSavings.map(s => s.id === updatedTx.savingId ? { ...s, currentAmount: s.currentAmount + updatedTx.amount } : s);
        }

        const accounts = prev.accounts.map(acc => {
          let balance = acc.currentBalance;
          if (acc.id === oldTx.accountId) balance -= (oldTx.type === 'income' ? oldTx.amount : -oldTx.amount);
          if (acc.id === updatedTx.accountId) balance += (updatedTx.type === 'income' ? updatedTx.amount : -updatedTx.amount);
          return { ...acc, currentBalance: balance };
        });

        const budgets = prev.budgets.map(b => {
          let spent = b.spent;
          if (oldTx.type === 'income' && oldTx.refundId) {
             if (b.type === 'expense' && b.category === oldTx.category && oldTx.date.startsWith(prev.currentDate)) spent += oldTx.amount;
          } else if (oldTx.type === b.type && b.category === oldTx.category && oldTx.date.startsWith(prev.currentDate)) {
            spent -= oldTx.amount;
          }
          if (updatedTx.type === 'income' && updatedTx.refundId) {
            if (b.type === 'expense' && b.category === updatedTx.category && updatedTx.date.startsWith(prev.currentDate)) spent -= updatedTx.amount;
          } else if (updatedTx.type === b.type && b.category === updatedTx.category && updatedTx.date.startsWith(prev.currentDate)) {
            spent += updatedTx.amount;
          }
          return { ...b, spent: Math.max(0, spent) };
        });

        return {
          ...prev,
          transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t),
          accounts,
          budgets,
          savings: updatedSavings
        };
      });
    },
    deleteTransaction: (id) => {
      setState(prev => {
        const t = prev.transactions.find(tx => tx.id === id);
        if (!t) return prev;

        let updatedSavings = [...prev.savings];
        if (t.type === 'expense' && t.savingId) {
          updatedSavings = updatedSavings.map(s => s.id === t.savingId ? { ...s, currentAmount: Math.max(0, s.currentAmount - t.amount) } : s);
        }

        let updatedRefunds = prev.refunds.filter(r => r.originTransactionId !== id);
        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) return { ...r, pendingAmount: r.pendingAmount + t.amount, status: 'open' };
            return r;
          });
        }
        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) return { ...acc, currentBalance: acc.currentBalance + (t.type === 'income' ? -t.amount : t.amount) };
          return acc;
        });
        const budgets = prev.budgets.map(b => {
          if (t.type === 'income' && t.refundId) {
            if (b.type === 'expense' && b.category === t.category && t.date.startsWith(prev.currentDate)) return { ...b, spent: b.spent + t.amount };
          } else if (t.type === b.type && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: Math.max(0, b.spent - t.amount) };
          }
          return b;
        });
        return { ...prev, transactions: prev.transactions.filter(tx => tx.id !== id), accounts, refunds: updatedRefunds, budgets, savings: updatedSavings };
      });
    },
    addAccount: (a) => {
      const id = 'acc_' + Date.now();
      setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id, currentBalance: a.initialBalance }] }));
    },
    updateAccount: (a) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) }));
    },
    deleteAccount: (id) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) }));
    },
    addSaving: (s) => {
      const id = 'sav_' + Date.now();
      setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id }] }));
    },
    updateSaving: (s) => {
      setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) }));
    },
    deleteSaving: (id) => {
      setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) }));
    },
    addRefund: (r) => {
      const id = 'ref_' + Date.now();
      setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id }] }));
    },
    updateRefund: (r) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf)
      }));
    },
    deleteRefund: (id) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.filter(r => r.id !== id),
        transactions: prev.transactions.map(t => t.refundId === id ? { ...t, refundId: undefined, isRefund: false } : t)
      }));
    },
    mergeRefunds: (id1, id2) => {
      setState(prev => {
        const r1 = prev.refunds.find(r => r.id === id1);
        const r2 = prev.refunds.find(r => r.id === id2);
        if (!r1 || !r2) return prev;
        const newId = 'ref_merged_' + Date.now();
        const mergedRefund: Refund = {
          id: newId,
          name: `${r1.name} + ${r2.name}`,
          totalAmount: r1.totalAmount + r2.totalAmount,
          paidByMe: r1.paidByMe + r2.paidByMe,
          pendingAmount: r1.pendingAmount + r2.pendingAmount,
          status: (r1.pendingAmount + r2.pendingAmount) > 0 ? 'open' : 'closed',
          notes: `Unificado.`,
          date: new Date().toISOString().split('T')[0],
          category: r1.category
        };
        return {
          ...prev,
          refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), mergedRefund],
          transactions: prev.transactions.map(t => (t.refundId === id1 || t.refundId === id2) ? { ...t, refundId: newId } : t)
        };
      });
    },
    addBudget: (b) => {
      const budgetType = b.type || 'expense';

      // FIX DUPLICACIÓN: Si ya existe la categoría para ese tipo, la actualizamos en lugar de crear una nueva.
      const existing = state.budgets.find(bg => bg.category.toLowerCase() === b.category.toLowerCase() && bg.type === budgetType);

      if (existing) {
        contextValue.updateBudget({ ...existing, limit: b.limit, icon: b.icon || existing.icon });
        return;
      }

      const id = 'budget_' + Date.now();
      const monthTx = state.transactions.filter(t => t.date.startsWith(state.currentDate) && t.category === b.category);
      let spent = 0;
      monthTx.forEach(t => {
        if (t.type === 'expense') {
          if (budgetType === 'expense') spent += t.amount;
        } else if (t.type === 'income') {
          if (t.refundId && budgetType === 'expense') spent -= t.amount;
          else if (!t.refundId && budgetType === 'income') spent += t.amount;
        }
      });
      setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id, spent, type: budgetType, icon: b.icon || 'ShoppingBag' } as Budget] }));
    },
    updateBudget: (updatedBudget) => {
      setState(prev => {
        const monthTx = prev.transactions.filter(t => t.date.startsWith(prev.currentDate) && t.category === updatedBudget.category);
        let spent = 0;
        monthTx.forEach(t => {
          if (t.type === 'expense') {
            if (updatedBudget.type === 'expense') spent += t.amount;
          } else if (t.type === 'income') {
            if (t.refundId && updatedBudget.type === 'expense') spent -= t.amount;
            else if (!t.refundId && updatedBudget.type === 'income') spent += t.amount;
          }
        });
        return { ...prev, budgets: prev.budgets.map(bg => bg.id === updatedBudget.id ? { ...updatedBudget, spent: Math.max(0, spent) } : bg) };
      });
    },
    deleteBudget: (id) => {
      setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) }));
    },
    changeMonth: (offset) => {
      setState(prev => {
        const [year, month] = prev.currentDate.split('-').map(Number);
        const date = new Date(year, month - 1 + offset, 1);
        const newMonthStr = date.toISOString().substring(0, 7);
        const updatedBudgets = prev.budgets.map(b => {
          const monthTx = prev.transactions.filter(t => t.date.startsWith(newMonthStr) && t.category === b.category);
          let spent = 0;
          monthTx.forEach(t => {
            if (t.type === 'expense') { if (b.type === 'expense') spent += t.amount; }
            else if (t.type === 'income') { if (t.refundId && b.type === 'expense') spent -= t.amount; else if (!t.refundId && b.type === 'income') spent += t.amount; }
          });
          return { ...b, spent: Math.max(0, spent) };
        });
        return { ...prev, currentDate: newMonthStr, budgets: updatedBudgets };
      });
    },
    setMonth: (dateStr) => {
      setState(prev => {
        const updatedBudgets = prev.budgets.map(b => {
          const monthTx = prev.transactions.filter(t => t.date.startsWith(dateStr) && t.category === b.category);
          let spent = 0;
          monthTx.forEach(t => {
            if (t.type === 'expense') { if (b.type === 'expense') spent += t.amount; }
            else if (t.type === 'income') { if (t.refundId && b.type === 'expense') spent -= t.amount; else if (!t.refundId && b.type === 'income') spent += t.amount; }
          });
          return { ...b, spent: Math.max(0, spent) };
        });
        return { ...prev, currentDate: dateStr, budgets: updatedBudgets };
      });
    },
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges }))
  };

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);
  const closeMenu = () => setIsMenuOpen(false);

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 overflow-hidden">
          <Sidebar isOpen={isMenuOpen} onClose={closeMenu} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={toggleMenu} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

