          <button onClick={() => changeMonth(1)} className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"><ChevronRight size={18} /></button>
        </div>
      </div>
      <div className="flex items-center gap-3">
        <div className="w-8 h-8 rounded-full bg-blue-100 border-2 border-white shadow-sm overflow-hidden flex items-center justify-center">
          <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Felix" alt="avatar" />
        </div>
      </div>
    </header>
  );
};

const QuickAddButton = () => {
  const [open, setOpen] = useState(false);
  const navigate = useNavigate();
  return (
    <div className="fixed bottom-6 right-6 md:bottom-8 md:right-8 z-40">
      {open && (
        <div className="absolute bottom-16 right-0 mb-2 flex flex-col gap-2 animate-in slide-in-from-bottom-4 duration-300">
          <button onClick={() => { setOpen(false); navigate('/transactions', { state: { openModal: true } }); }} className="flex items-center gap-2 bg-white text-slate-800 px-4 py-3 rounded-2xl shadow-lg hover:bg-slate-50 border border-slate-100 transition-all whitespace-nowrap text-left"><Receipt size={18} className="text-blue-500" /><span className="text-sm font-semibold">Nueva Transacción</span></button>
          <button onClick={() => { setOpen(false); navigate('/transactions', { state: { openScanner: true } }); }} className="flex items-center gap-2 bg-white text-slate-800 px-4 py-3 rounded-2xl shadow-lg hover:bg-slate-50 border border-slate-100 transition-all whitespace-nowrap text-left"><Camera size={18} className="text-emerald-500" /><span className="text-sm font-semibold">Escanear Ticket</span></button>
          <Link to="/advisor" onClick={() => setOpen(false)} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-3 rounded-2xl shadow-lg hover:bg-blue-700 transition-all whitespace-nowrap"><MessageSquare size={18} /><span className="text-sm font-semibold">Hablar con Aura</span></Link>
        </div>
      )}
      <button onClick={() => setOpen(!open)} className={`w-12 h-12 md:w-14 md:h-14 rounded-2xl shadow-xl flex items-center justify-center transition-all duration-300 ${open ? 'bg-slate-800 rotate-45' : 'bg-blue-600'}`}><Plus size={24} className="text-white" /></button>
    </div>
  );
};
export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  X, 
  UserCheck, 
  AlertCircle, 
  Check, 
  PiggyBank, 
  ChevronDown, 
  Split 
} from 'lucide-react';
import { Transaction } from '../types';

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const location = useLocation();

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  // RESTRICCIÓN: Solo categorías únicas que existen en los presupuestos
  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];

    const budgetList = budgets
      .filter(b => b.type === (type === 'saving' ? 'expense' : type))
      .map(b => b.category);

    const uniqueCategories = Array.from(new Set(budgetList));
    return uniqueCategories.length > 0 ? uniqueCategories : ["Sin Presupuesto"];
  }, [type, budgets]);

  useEffect(() => {
    if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || '');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setSelectedSavingId('');
    setMyPartManual('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);

    const isSavingType = tx.type === 'expense' && !!tx.savingId;
    setType(isSavingType ? 'saving' : tx.type);

    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setSelectedSavingId(tx.savingId || '');
    setIsAdding(true);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleDeleteFromModal = (id: string) => {
    deleteTransaction(id);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    const finalType = type === 'saving' ? 'expense' : type;
    const finalCategory = type === 'saving' ? 'Ahorro' : category;

    if (editingTx) {
      updateTransaction({
        ...editingTx,
        date,
        amount: Number(amount),
        description: desc,
        category: finalCategory,
        type: finalType,
        accountId,
        refundId: selectedRefundId || undefined,
        savingId: type === 'saving' ? selectedSavingId : undefined
      });
    } else {
      addTransaction({
        date,
        amount: Number(amount),
        description: desc,
        category: finalCategory,
        type: finalType,
        accountId,
        isRefund: isRefundLink,
        refundId: finalType === 'income' && isRefundLink ? selectedRefundId : undefined,
        savingId: type === 'saving' ? selectedSavingId : undefined
      }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
    }

    setIsAdding(false);
    resetForm();
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      let matchesType = true;
      const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
      const isRefund = t.type === 'income' && !!t.refundId;

      if (filter === 'income') matchesType = t.type === 'income' && !t.refundId;
      else if (filter === 'expense') matchesType = t.type === 'expense' && !isSaving;
      else if (filter === 'savings') matchesType = isSaving;
      else if (filter === 'refunds') matchesType = isRefund;

      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [transactions, filter, searchTerm]);

  const getTxStyle = (t: Transaction) => {
    const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
    const isRefund = t.type === 'income' && !!t.refundId;

    if (isSaving) return { color: 'text-amber-500', bg: 'bg-amber-50', icon: <ArrowUpRight size={18} /> }; 
    if (isRefund) return { color: 'text-blue-600', bg: 'bg-blue-50', icon: <ArrowUpRight size={18} /> }; 
    if (t.type === 'income') return { color: 'text-emerald-600', bg: 'bg-emerald-50', icon: <ArrowUpRight size={18} /> }; 
    return { color: 'text-rose-600', bg: 'bg-rose-50', icon: <ArrowDownRight size={18} /> }; 
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Transacciones</h2>
          <p className="text-slate-700 font-bold text-sm">Historial financiero con filtros avanzados.</p>
        </div>
        <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95">
          <Plus size={20} /> 
          <span>Nueva Transacción</span>
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden">
        <div className="p-4 md:p-6 border-b border-slate-100 flex flex-col gap-4 bg-slate-50/30">
          <div className="flex items-center gap-1 bg-white p-1 rounded-2xl border border-slate-200 shadow-sm w-full overflow-x-auto no-scrollbar">
            <button onClick={() => setFilter('all')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>AHORROS</button>
            <button onClick={() => setFilter('refunds')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800'}`}>REEMBOLSOS</button>
          </div>

          <div className="flex items-center gap-3 bg-white px-5 py-3 rounded-2xl border border-slate-200 w-full shadow-sm focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <Search size={18} className="text-slate-500" />
            <input 
              type="text" 
              placeholder="Buscar transacción..." 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 placeholder:text-slate-300" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse table-fixed">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] uppercase tracking-[0.15em] text-slate-400 font-black border-b border-slate-100">
                <th className="px-6 py-5 text-left w-[25%] md:w-[20%]">Fecha</th>
                <th className="px-6 py-5 text-left w-[45%] md:w-[50%]">Detalle</th>
                <th className="px-6 py-5 text-right w-[30%]">Importe</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredTx.map(tx => {
                const style = getTxStyle(tx);
                return (
                  <tr 
                    key={tx.id} 
                    onClick={() => { setViewingTx(tx); setConfirmDeleteInModal(false); }}
                    className="hover:bg-slate-50 transition-all group cursor-pointer active:bg-slate-100"
                  >
                    <td className="px-6 py-6 text-[11px] font-black text-slate-500 uppercase">
                      {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex items-center gap-4 overflow-hidden">
                        <div className={`flex w-9 h-9 rounded-xl items-center justify-center flex-shrink-0 shadow-sm ${style.bg} ${style.color}`}>
                          {style.icon}
                        </div>
                        <div className="min-w-0 flex flex-col">
                          <span className="font-black text-slate-800 text-[13px] truncate leading-tight">
                            {tx.description}
                          </span>
                          <span className="text-[9px] font-black text-slate-400 uppercase tracking-wider mt-0.5 truncate">{tx.category}</span>
                        </div>
                      </div>
                    </td>
                    <td className={`px-6 py-6 text-right font-black text-lg ${style.color}`}>
                      {tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTx.length === 0 && (
            <div className="py-24 text-center flex flex-col items-center gap-4">
               <div className="w-16 h-16 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center"><AlertCircle size={32} /></div>
               <p className="text-slate-400 font-bold italic uppercase tracking-widest text-[11px]">No se encontraron movimientos</p>
            </div>
          )}
        </div>
      </div>

      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[80] flex items-center justify-center p-4" onClick={() => { setViewingTx(null); setConfirmDeleteInModal(false); }}>
          <div className="bg-white rounded-[3.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100" onClick={e => e.stopPropagation()}>
            <div className="flex flex-col items-center text-center gap-8">
              <div className={`w-24 h-24 rounded-[2rem] flex items-center justify-center shadow-lg ${getTxStyle(viewingTx).bg} ${getTxStyle(viewingTx).color}`}>
                {React.cloneElement(getTxStyle(viewingTx).icon as React.ReactElement, { size: 48 })}
              </div>

              <div>
                <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-2">{viewingTx.category}</p>
                <h3 className="text-2xl font-black text-slate-900 leading-tight">
                  {viewingTx.description}
                </h3>
              </div>

              <div className="w-full bg-slate-50 rounded-[2.5rem] p-8 space-y-5 border border-slate-100">
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-slate-500 uppercase">Monto</span>
                  <span className={`text-3xl font-black ${getTxStyle(viewingTx).color}`}>
                    {viewingTx.type === 'income' ? '+' : '-'}{Math.abs(viewingTx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                  </span>
                </div>
                <div className="h-px bg-slate-200 w-full opacity-50"></div>
                <div className="flex justify-between items-center text-sm font-black text-slate-800">
                  <span className="text-xs font-bold text-slate-500 uppercase">Cuenta</span>
                  <span>{accounts.find(a => a.id === viewingTx.accountId)?.name || 'Desconocida'}</span>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 w-full">
                <button onClick={() => startEdit(viewingTx)} className="py-5 bg-white border-2 border-slate-100 text-slate-800 font-black rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-50">
                  <Edit2 size={18} /> EDITAR
                </button>
                {confirmDeleteInModal ? (
                  <button onClick={() => handleDeleteFromModal(viewingTx.id)} className="py-5 bg-rose-600 text-white font-black rounded-2xl animate-in zoom-in">CONFIRMAR</button>
                ) : (
                  <button onClick={() => setConfirmDeleteInModal(true)} className="py-5 bg-rose-50 text-rose-600 border-2 border-rose-100 font-black rounded-2xl flex items-center justify-center gap-2">
                    <Trash2 size={18} /> BORRAR
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/75 backdrop-blur-md z-50 flex items-center justify-center p-4">
             <div className="bg-white rounded-[3rem] w-full max-w-lg p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-200 overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center mb-10">
                  <h3 className="text-3xl font-black text-slate-900 tracking-tight">{editingTx ? 'Editar' : 'Nuevo Movimiento'}</h3>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-4 hover:bg-slate-100 rounded-full text-slate-400"><X size={28} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 p-2 rounded-[1.8rem] border border-slate-200 shadow-inner">
                    <button type="button" onClick={() => setType('expense')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' ? 'bg-white shadow-md text-rose-600' : 'text-slate-500'}`}>GASTO</button>
                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>INGRESO</button>
                    <button type="button" onClick={() => setType('saving')} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'saving' ? 'bg-white shadow-md text-amber-500' : 'text-slate-500'}`}>AHORRO</button>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Descripción</label>
                      <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none focus:border-blue-400 transition-all placeholder:text-slate-300" placeholder="Ej: Supermercado..." required />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Importe (€)</label>
                        <input type="number" step="0.01" value={amount} onChange={e => setAmount(Number(e.target.value))} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-black text-xl outline-none" required />
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Fecha</label>
                        <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none" required />
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">
                          {type === 'saving' ? 'Hucha Destino' : 'Categoría (Presupuesto)'}
                        </label>
                        <div className="relative">
                          {type === 'saving' ? (
                            <select value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none" required>
                              <option value="">Selecciona hucha</option>
                              {savings.map(s => <option key={s.id} value={s.id}>{s.emoji} {s.name}</option>)}
                            </select>
                          ) : (
                            <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none" required>
                              {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                          )}
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 uppercase tracking-widest mb-3">Cuenta Origen</label>
                        <div className="relative">
                          <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold outline-none appearance-none">
                            {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                          </select>
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                    </div>

                    {type !== 'saving' && (
                      <div className="pt-4">
                         <button 
                           type="button"
                           onClick={() => setIsRefundLink(!isRefundLink)}
                           className={`w-full flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${isRefundLink ? 'bg-blue-50 border-blue-400 text-blue-700' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                         >
                           <div className="flex items-center gap-3">
                             {type === 'expense' ? <Split size={20} /> : <UserCheck size={20} />}
                             <span className="font-bold text-sm">{type === 'expense' ? 'Dividir gasto / Préstamo' : 'Cobro de reembolso'}</span>
                           </div>
                           <Check size={20} className={isRefundLink ? 'text-blue-600 opacity-100' : 'opacity-0'} />
                         </button>

                         {isRefundLink && (
                           <div className="mt-4 p-5 bg-blue-50 rounded-2xl border-2 border-blue-100 space-y-4 animate-in slide-in-from-top-2 duration-300">
                             {type === 'expense' ? (
                               <>
                                 <label className="block text-[11px] font-black text-blue-700 uppercase">Tu Parte (Gasto Neto)</label>
                                 <input type="number" value={myPartManual} onChange={e => setMyPartManual(Number(e.target.value))} className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-black outline-none text-center" placeholder="Cuanto pagas tú" />
                               </>
                             ) : (
                               <>
                                 <label className="block text-[11px] font-black text-blue-700 uppercase">Vincular a Deuda</label>
                                 <select value={selectedRefundId} onChange={e => setSelectedRefundId(e.target.value)} className="w-full bg-white border-2 border-blue-200 rounded-xl p-4 font-bold outline-none" required>
                                   <option value="">Selecciona deuda pendiente</option>
                                   {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name} ({r.pendingAmount}€)</option>)}
                                 </select>
                               </>
                             )}
                           </div>
                         )}
                      </div>
                    )}
                  </div>

                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => { setIsAdding(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-700 font-black rounded-2xl">CANCELAR</button>
                    <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100">{editingTx ? 'GUARDAR' : 'CONFIRMAR'}</button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import { GoogleGenAI, Type, FunctionDeclaration, GenerateContentResponse } from "@google/genai";
import { Transaction, Budget, AIChallenge } from "../types";

export const analyzeReceipt = async (base64Image: string): Promise<any[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: `Analiza esta captura de pantalla de movimientos financieros. Extrae CADA línea de transacción visible.
        Para cada línea, determina con precisión:
        1. Descripción, Monto, Fecha (YYYY-MM-DD), Categoría.
        2. Intención (intent): 
           - 'standard': Gasto o ingreso normal.
           - 'transfer': Movimiento entre dos cuentas bancarias del usuario.
           - 'savings': Dinero enviado a una hucha de ahorro.
           - 'refund': Movimiento vinculado a un préstamo o dinero que te deben/debes.
        3. Tipo (type): 'income' o 'expense'.

        Devuelve un JSON puro con un array de objetos.` }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            type: { type: Type.STRING, description: 'income or expense' },
            intent: { type: Type.STRING, description: 'standard, transfer, savings, or refund' },
            suggestedTarget: { type: Type.STRING, description: 'Nombre sugerido de la cuenta destino o hucha si aplica' }
          },
          required: ['description', 'amount', 'date', 'category', 'type', 'intent']
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

export const generateAIChallenges = async (context: string): Promise<AIChallenge[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Basado en este estado financiero: ${context}, genera 3 retos financieros realistas para este mes. Devuelve un JSON puro con este formato: [{ "id": "string", "title": "string", "target": number, "type": "spending_limit" | "savings_goal" | "income_target", "category": "string (opcional)", "completed": false }].`,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            title: { type: Type.STRING },
            target: { type: Type.NUMBER },
            type: { type: Type.STRING },
            category: { type: Type.STRING },
            completed: { type: Type.BOOLEAN }
          },
          required: ['id', 'title', 'target', 'type', 'completed']
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

