import React, { useState, useRef, useEffect } from 'react';
import { useFinance } from '../App';
import { Send, Bot, User, Sparkles, Loader2, RefreshCcw, CheckCircle2 } from 'lucide-react';
import { getFinancialAdviceWithTools } from '../services/geminiService';

const AIAdvisor: React.FC = () => {
  const financeState = useFinance();
  const { budgets, updateBudget, addTransaction, addBudget, accounts } = financeState;

  const [messages, setMessages] = useState<{role: 'ai' | 'user' | 'system', text: string}[]>([
    { role: 'ai', text: '¡Hola! Soy Aura. Estoy lista para gestionar tus finanzas. Puedo crear presupuestos, editarlos o registrar gastos por ti. ¿Qué necesitas hoy?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const context = `
        Cuentas: ${accounts.map(a => `${a.name} (${a.currentBalance}€)`).join(', ')}
        Presupuestos: ${budgets.map(b => `${b.category} (${b.type === 'income' ? 'Ingreso' : 'Gasto'}): ${b.spent}/${b.limit}€`).join(', ')}
        Fecha: ${financeState.currentDate}
      `;

      const response = await getFinancialAdviceWithTools(context, userMsg);

      if (response.functionCalls && response.functionCalls.length > 0) {
        for (const fc of response.functionCalls) {
          if (fc.name === 'createBudgetCategory') {
            const { categoryName, limit, type } = fc.args as any;
            addBudget({ category: categoryName, limit, type: type as 'income' | 'expense' });
            setMessages(prev => [...prev, { role: 'system', text: `✨ Nueva categoría de ${type === 'income' ? 'ingreso' : 'gasto'} creada: "${categoryName}" con un límite de ${limit}€.` }]);
          }

          if (fc.name === 'updateExistingBudgetLimit') {
            const { categoryName, newLimit } = fc.args as any;
            const budget = budgets.find(b => b.category.toLowerCase().trim() === categoryName.toLowerCase().trim());
            if (budget) {
              updateBudget({ ...budget, limit: newLimit });
              setMessages(prev => [...prev, { role: 'system', text: `✅ Presupuesto de "${budget.category}" actualizado a ${newLimit}€.` }]);
            } else {
              setMessages(prev => [...prev, { role: 'system', text: `⚠️ No encontré la categoría "${categoryName}". Puedes pedirme que la cree.` }]);
            }
          }

          if (fc.name === 'recordNewTransaction') {
            const { description, amount, category, type, accountName } = fc.args as any;
            const account = accounts.find(a => a.name.toLowerCase().trim() === accountName.toLowerCase().trim());
            if (account) {
              addTransaction({
                date: new Date().toISOString().split('T')[0],
                amount,
                description,
                category,
                type: type === 'income' ? 'income' : 'expense',
                accountId: account.id,
                isRefund: false
              });
              setMessages(prev => [...prev, { role: 'system', text: `💸 Transacción registrada en ${account.name}: ${description} (${amount}€).` }]);
            } else {
              setMessages(prev => [...prev, { role: 'system', text: `⚠️ No encontré la cuenta "${accountName}". Por favor, indícame en cuál cuenta quieres registrarlo.` }]);
            }
          }
        }
      }

      if (response.text) {
        setMessages(prev => [...prev, { role: 'ai', text: response.text || '' }]);
      } else if (!response.functionCalls) {
        setMessages(prev => [...prev, { role: 'ai', text: "He procesado tu solicitud correctamente." }]);
      }

    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'ai', text: 'Perdona, ha habido un error en mi sistema. ¿Podrías repetirme eso?' }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-full flex flex-col max-w-4xl mx-auto space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            Aura AI Advisor <Sparkles className="text-blue-500" size={20} />
          </h2>
          <p className="text-slate-500 font-medium">Gestión inteligente de presupuestos e ingresos/gastos.</p>
        </div>
        <button 
          onClick={() => setMessages([messages[0]])}
          className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-xl transition-all"
        >
          <RefreshCcw size={18} />
        </button>
      </div>

      <div className="flex-1 bg-white rounded-3xl border border-slate-100 shadow-sm flex flex-col overflow-hidden relative">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`flex gap-3 max-w-[85%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center ${
                  m.role === 'ai' ? 'bg-blue-600 text-white' : 
                  m.role === 'system' ? 'bg-emerald-100 text-emerald-600' :
                  'bg-slate-200 text-slate-600'
                }`}>
                  {m.role === 'ai' ? <Bot size={16} /> : m.role === 'system' ? <CheckCircle2 size={16} /> : <User size={16} />}
                </div>
                <div className={`p-4 rounded-2xl text-sm leading-relaxed ${
                  m.role === 'ai' 
                    ? 'bg-slate-50 text-slate-800 border border-slate-100' 
                    : m.role === 'system'
                    ? 'bg-emerald-50 text-emerald-800 border border-emerald-100 border-dashed'
                    : 'bg-blue-600 text-white font-medium shadow-md shadow-blue-100'
                }`}>
                  {m.text}
                </div>
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
               <div className="flex gap-3 max-w-[85%] items-center">
                  <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center animate-pulse">
                    <Bot size={16} />
                  </div>
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center gap-2">
                     <Loader2 size={16} className="animate-spin text-blue-500" />
                     <span className="text-xs text-slate-400 font-bold uppercase tracking-widest">Aura está operando...</span>
                  </div>
               </div>
            </div>
          )}
        </div>

        <div className="p-4 bg-slate-50 border-t border-slate-100">
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-1.5 flex items-center gap-2 focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <input 
              type="text" 
              placeholder="Ej: 'Crea un presupuesto de Ocio con 100€'..."
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-3 py-2"
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSend()}
            />
            <button 
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className={`p-2.5 rounded-xl transition-all ${!input.trim() || isLoading ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white shadow-lg shadow-blue-100 hover:bg-blue-700'}`}
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AIAdvisor;

