interface FinanceContextType extends FinanceState {
  addTransaction: (t: Omit<Transaction, 'id'>, myPart?: number) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAccount: (a: Omit<Account, 'id' | 'currentBalance'>) => void;
  updateAccount: (a: Account) => void;
  deleteAccount: (id: string) => void;
  addSaving: (s: Omit<Saving, 'id'>) => void;
  updateSaving: (s: Saving) => void;
  deleteSaving: (id: string) => void;
  addRefund: (r: Omit<Refund, 'id'>) => void;
  updateRefund: (r: Refund) => void;
  deleteRefund: (id: string) => void;
  mergeRefunds: (id1: string, id2: string) => void;
  addBudget: (b: Omit<Budget, 'id' | 'spent' | 'icon' | 'type'> & { type?: 'income' | 'expense'; icon?: string }) => void;
  updateBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  changeMonth: (offset: number) => void;
  setMonth: (date: string) => void;
  updateLayout: (newLayout: string[]) => void;
  setChallenges: (challenges: AIChallenge[]) => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error("useFinance must be used within FinanceProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<FinanceState>(() => {
    const saved = localStorage.getItem('finance_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('finance_data', JSON.stringify(state));
  }, [state]);

  const contextValue: FinanceContextType = {
    ...state,
    addTransaction: (t, myPart) => {
      const id = Math.random().toString(36).substr(2, 9);
      let finalTransaction = { ...t, id };

      setState(prev => {
        let updatedRefunds = [...prev.refunds];
        let updatedSavings = [...prev.savings];

        if (t.type === 'income' && t.refundId) {
          const linkedRefund = prev.refunds.find(r => r.id === t.refundId);
          if (linkedRefund) finalTransaction.category = linkedRefund.category;

          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) {
              const newPending = Math.max(0, r.pendingAmount - t.amount);
              return { ...r, pendingAmount: newPending, status: newPending <= 0 ? 'closed' : 'open' };
            }
            return r;
          });
        }

        if (t.type === 'expense' && t.isRefund) {
          const refundId = 'ref_' + Date.now();
          const partToPay = myPart !== undefined ? myPart : t.amount / 2;
          updatedRefunds.push({
            id: refundId,
            name: t.description,
            totalAmount: t.amount,
            paidByMe: partToPay, 
            pendingAmount: t.amount - partToPay, 
            status: (t.amount - partToPay) <= 0 ? 'closed' : 'open',
            notes: 'Creado desde gasto: ' + t.description,
            date: t.date,
            category: t.category,
            originTransactionId: id
          });
          finalTransaction.refundId = refundId;
        }

        if (t.type === 'expense' && t.savingId) {
          updatedSavings = updatedSavings.map(s => {
            if (s.id === t.savingId) return { ...s, currentAmount: s.currentAmount + t.amount };
            return s;
          });
        }

        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) {
            const delta = t.type === 'income' ? t.amount : -t.amount;
            return { ...acc, currentBalance: acc.currentBalance + delta };
          }
          return acc;
        });

        const budgets = prev.budgets.map(b => {
          if (finalTransaction.type === 'income' && finalTransaction.refundId) {
            if (b.type === 'expense' && b.category === finalTransaction.category && finalTransaction.date.startsWith(prev.currentDate)) {
              return { ...b, spent: Math.max(0, b.spent - finalTransaction.amount) };
            }
          } else if (finalTransaction.type === b.type && b.category === finalTransaction.category && finalTransaction.date.startsWith(prev.currentDate)) {
            return { ...b, spent: b.spent + finalTransaction.amount };
          }
          return b;
        });

        return {
          ...prev,
          transactions: [finalTransaction, ...prev.transactions],
          accounts,
          budgets,
          refunds: updatedRefunds,
          savings: updatedSavings
        };
      });
    },
    updateTransaction: (updatedTx) => {
      setState(prev => {
        const oldTx = prev.transactions.find(t => t.id === updatedTx.id);
        if (!oldTx) return prev;

        let updatedSavings = [...prev.savings];
        if (oldTx.type === 'expense' && oldTx.savingId) {
          updatedSavings = updatedSavings.map(s => s.id === oldTx.savingId ? { ...s, currentAmount: s.currentAmount - oldTx.amount } : s);
        }
        if (updatedTx.type === 'expense' && updatedTx.savingId) {
          updatedSavings = updatedSavings.map(s => s.id === updatedTx.savingId ? { ...s, currentAmount: s.currentAmount + updatedTx.amount } : s);
        }

        const accounts = prev.accounts.map(acc => {
          let balance = acc.currentBalance;
          if (acc.id === oldTx.accountId) balance -= (oldTx.type === 'income' ? oldTx.amount : -oldTx.amount);
          if (acc.id === updatedTx.accountId) balance += (updatedTx.type === 'income' ? updatedTx.amount : -updatedTx.amount);
          return { ...acc, currentBalance: balance };
        });

        const budgets = prev.budgets.map(b => {
          let spent = b.spent;
          if (oldTx.type === 'income' && oldTx.refundId) {
             if (b.type === 'expense' && b.category === oldTx.category && oldTx.date.startsWith(prev.currentDate)) spent += oldTx.amount;
          } else if (oldTx.type === b.type && b.category === oldTx.category && oldTx.date.startsWith(prev.currentDate)) {
            spent -= oldTx.amount;
          }
          if (updatedTx.type === 'income' && updatedTx.refundId) {
            if (b.type === 'expense' && b.category === updatedTx.category && updatedTx.date.startsWith(prev.currentDate)) spent -= updatedTx.amount;
          } else if (updatedTx.type === b.type && b.category === updatedTx.category && updatedTx.date.startsWith(prev.currentDate)) {
            spent += updatedTx.amount;
          }
          return { ...b, spent: Math.max(0, spent) };
        });

        return {
          ...prev,
          transactions: prev.transactions.map(t => t.id === updatedTx.id ? updatedTx : t),
          accounts,
          budgets,
          savings: updatedSavings
        };
      });
    },
    deleteTransaction: (id) => {
      setState(prev => {
        const t = prev.transactions.find(tx => tx.id === id);
        if (!t) return prev;

        let updatedSavings = [...prev.savings];
        if (t.type === 'expense' && t.savingId) {
          updatedSavings = updatedSavings.map(s => s.id === t.savingId ? { ...s, currentAmount: Math.max(0, s.currentAmount - t.amount) } : s);
        }

        let updatedRefunds = prev.refunds.filter(r => r.originTransactionId !== id);
        if (t.type === 'income' && t.refundId) {
          updatedRefunds = updatedRefunds.map(r => {
            if (r.id === t.refundId) return { ...r, pendingAmount: r.pendingAmount + t.amount, status: 'open' };
            return r;
          });
        }
        const accounts = prev.accounts.map(acc => {
          if (acc.id === t.accountId) return { ...acc, currentBalance: acc.currentBalance + (t.type === 'income' ? -t.amount : t.amount) };
          return acc;
        });
        const budgets = prev.budgets.map(b => {
          if (t.type === 'income' && t.refundId) {
            if (b.type === 'expense' && b.category === t.category && t.date.startsWith(prev.currentDate)) return { ...b, spent: b.spent + t.amount };
          } else if (t.type === b.type && b.category === t.category && t.date.startsWith(prev.currentDate)) {
            return { ...b, spent: Math.max(0, b.spent - t.amount) };
          }
          return b;
        });
        return { ...prev, transactions: prev.transactions.filter(tx => tx.id !== id), accounts, refunds: updatedRefunds, budgets, savings: updatedSavings };
      });
    },
    addAccount: (a) => {
      const id = 'acc_' + Date.now();
      setState(prev => ({ ...prev, accounts: [...prev.accounts, { ...a, id, currentBalance: a.initialBalance }] }));
    },
    updateAccount: (a) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.map(acc => acc.id === a.id ? a : acc) }));
    },
    deleteAccount: (id) => {
      setState(prev => ({ ...prev, accounts: prev.accounts.filter(a => a.id !== id) }));
    },
    addSaving: (s) => {
      const id = 'sav_' + Date.now();
      setState(prev => ({ ...prev, savings: [...prev.savings, { ...s, id }] }));
    },
    updateSaving: (s) => {
      setState(prev => ({ ...prev, savings: prev.savings.map(sv => sv.id === s.id ? s : sv) }));
    },
    deleteSaving: (id) => {
      setState(prev => ({ ...prev, savings: prev.savings.filter(s => s.id !== id) }));
    },
    addRefund: (r) => {
      const id = 'ref_' + Date.now();
      setState(prev => ({ ...prev, refunds: [...prev.refunds, { ...r, id }] }));
    },
    updateRefund: (r) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.map(rf => rf.id === r.id ? r : rf)
      }));
    },
    deleteRefund: (id) => {
      setState(prev => ({
        ...prev,
        refunds: prev.refunds.filter(r => r.id !== id),
        transactions: prev.transactions.map(t => t.refundId === id ? { ...t, refundId: undefined, isRefund: false } : t)
      }));
    },
    mergeRefunds: (id1, id2) => {
      setState(prev => {
        const r1 = prev.refunds.find(r => r.id === id1);
        const r2 = prev.refunds.find(r => r.id === id2);
        if (!r1 || !r2) return prev;
        const newId = 'ref_merged_' + Date.now();
        const mergedRefund: Refund = {
          id: newId,
          name: `${r1.name} + ${r2.name}`,
          totalAmount: r1.totalAmount + r2.totalAmount,
          paidByMe: r1.paidByMe + r2.paidByMe,
          pendingAmount: r1.pendingAmount + r2.pendingAmount,
          status: (r1.pendingAmount + r2.pendingAmount) > 0 ? 'open' : 'closed',
          notes: `Unificado.`,
          date: new Date().toISOString().split('T')[0],
          category: r1.category
        };
        return {
          ...prev,
          refunds: [...prev.refunds.filter(r => r.id !== id1 && r.id !== id2), mergedRefund],
          transactions: prev.transactions.map(t => (t.refundId === id1 || t.refundId === id2) ? { ...t, refundId: newId } : t)
        };
      });
    },
    addBudget: (b) => {
      const budgetType = b.type || 'expense';
      const normCategory = b.category.trim().toLowerCase();

      // FIX DUPLICACIÓN: Normalización de nombres y verificación de tipo para evitar ingresos cruzados
      const existing = state.budgets.find(bg => 
        bg.category.trim().toLowerCase() === normCategory && 
        bg.type === budgetType
      );

      if (existing) {
        contextValue.updateBudget({ ...existing, limit: b.limit, icon: b.icon || existing.icon });
        return;
      }

      const id = 'budget_' + Date.now();
      const monthTx = state.transactions.filter(t => t.date.startsWith(state.currentDate) && t.category.trim().toLowerCase() === normCategory);
      let spent = 0;
      monthTx.forEach(t => {
        if (t.type === 'expense') {
          if (budgetType === 'expense') spent += t.amount;
        } else if (t.type === 'income') {
          if (t.refundId && budgetType === 'expense') spent -= t.amount;
          else if (!t.refundId && budgetType === 'income') spent += t.amount;
        }
      });
      setState(prev => ({ ...prev, budgets: [...prev.budgets, { ...b, id, spent, type: budgetType, icon: b.icon || 'ShoppingBag' } as Budget] }));
    },
    updateBudget: (updatedBudget) => {
      setState(prev => {
        const monthTx = prev.transactions.filter(t => t.date.startsWith(prev.currentDate) && t.category.trim().toLowerCase() === updatedBudget.category.trim().toLowerCase());
        let spent = 0;
        monthTx.forEach(t => {
          if (t.type === 'expense') {
            if (updatedBudget.type === 'expense') spent += t.amount;
          } else if (t.type === 'income') {
            if (t.refundId && updatedBudget.type === 'expense') spent -= t.amount;
            else if (!t.refundId && updatedBudget.type === 'income') spent += t.amount;
          }
        });
        return { ...prev, budgets: prev.budgets.map(bg => bg.id === updatedBudget.id ? { ...updatedBudget, spent: Math.max(0, spent) } : bg) };
      });
    },
    deleteBudget: (id) => {
      setState(prev => ({ ...prev, budgets: prev.budgets.filter(b => b.id !== id) }));
    },
    changeMonth: (offset) => {
      setState(prev => {
        const [year, month] = prev.currentDate.split('-').map(Number);
        const date = new Date(year, month - 1 + offset, 1);
        const newMonthStr = date.toISOString().substring(0, 7);
        const updatedBudgets = prev.budgets.map(b => {
          const monthTx = prev.transactions.filter(t => t.date.startsWith(newMonthStr) && t.category.trim().toLowerCase() === b.category.trim().toLowerCase());
          let spent = 0;
          monthTx.forEach(t => {
            if (t.type === 'expense') { if (b.type === 'expense') spent += t.amount; }
            else if (t.type === 'income') { if (t.refundId && b.type === 'expense') spent -= t.amount; else if (!t.refundId && b.type === 'income') spent += t.amount; }
          });
          return { ...b, spent: Math.max(0, spent) };
        });
        return { ...prev, currentDate: newMonthStr, budgets: updatedBudgets };
      });
    },
    setMonth: (dateStr) => {
      setState(prev => {
        const updatedBudgets = prev.budgets.map(b => {
          const monthTx = prev.transactions.filter(t => t.date.startsWith(dateStr) && t.category.trim().toLowerCase() === b.category.trim().toLowerCase());
          let spent = 0;
          monthTx.forEach(t => {
            if (t.type === 'expense') { if (b.type === 'expense') spent += t.amount; }
            else if (t.type === 'income') { if (t.refundId && b.type === 'expense') spent -= t.amount; else if (!t.refundId && b.type === 'income') spent += t.amount; }
          });
          return { ...b, spent: Math.max(0, spent) };
        });
        return { ...prev, currentDate: dateStr, budgets: updatedBudgets };
      });
    },
    updateLayout: (newLayout) => setState(prev => ({ ...prev, dashboardLayout: newLayout })),
    setChallenges: (challenges) => setState(prev => ({ ...prev, challenges }))
  };

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);
  const closeMenu = () => setIsMenuOpen(false);

  return (
    <FinanceContext.Provider value={contextValue}>
      <HashRouter>
        <div className="flex h-screen bg-slate-50 overflow-hidden">
          <Sidebar isOpen={isMenuOpen} onClose={closeMenu} />
          <main className="flex-1 flex flex-col overflow-hidden relative">
            <Header onMenuClick={toggleMenu} />
            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/accounts" element={<Accounts />} />
                <Route path="/savings" element={<Savings />} />
                <Route path="/refunds" element={<Refunds />} />
                <Route path="/transactions" element={<Transactions />} />
                <Route path="/budget" element={<BudgetManager />} />
                <Route path="/advisor" element={<AIAdvisor />} />
              </Routes>
            </div>
            <QuickAddButton />
          </main>
        </div>
      </HashRouter>
    </FinanceContext.Provider>
  );
};

const Sidebar = ({ isOpen, onClose }: { isOpen: boolean, onClose: () => void }) => {
  const location = useLocation();
  const menuItems = [
    { path: '/', icon: <LayoutDashboard size={20} />, label: 'Dashboard' },
    { path: '/accounts', icon: <Wallet size={20} />, label: 'Cuentas' },
    { path: '/savings', icon: <PiggyBank size={20} />, label: 'Ahorro' },
    { path: '/refunds', icon: <Receipt size={20} />, label: 'Reembolsos' },
    { path: '/transactions', icon: <BarChart3 size={20} />, label: 'Transacciones' },
    { path: '/budget', icon: <Receipt size={20} />, label: 'Presupuesto' },
    { path: '/advisor', icon: <MessageSquare size={20} />, label: 'Asesor IA' },
  ];
  return (
    <>
      {isOpen && <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-40 md:hidden" onClick={onClose} />}
      <aside className={`fixed md:static inset-y-0 left-0 w-64 bg-white border-r border-slate-200 shadow-xl md:shadow-sm z-50 flex flex-col transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="p-6 flex items-center justify-between">
          <h1 className="text-xl font-bold text-blue-600 flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white"><Wallet size={18} /></div>
            Finanzas Pro
          </h1>
          <button onClick={onClose} className="md:hidden p-2 text-slate-400 hover:text-slate-600"><X size={20} /></button>
        </div>
        <nav className="flex-1 px-4 space-y-1">
          {menuItems.map((item) => (
            <Link key={item.path} to={item.path} onClick={onClose} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 ${location.pathname === item.path ? 'bg-blue-50 text-blue-600 font-semibold' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}>
              {item.icon} {item.label}
            </Link>
          ))}
        </nav>
      </aside>
    </>
  );
};

const Header = ({ onMenuClick }: { onMenuClick: () => void }) => {
  const { currentDate, changeMonth, setMonth } = useFinance();
  const [showMonthPicker, setShowMonthPicker] = useState(false);
  const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];
  const currentFormatted = useMemo(() => {
    const [year, month] = currentDate.split('-').map(Number);
    return `${monthNames[month - 1]} ${year}`;
  }, [currentDate]);
  return (
    <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 h-16 flex items-center justify-between px-4 md:px-6 sticky top-0 z-20">
      <div className="flex items-center gap-3">
        <button onClick={onMenuClick} className="md:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"><Menu size={22} /></button>
        <div className="flex items-center gap-1 md:gap-2 bg-slate-100 p-1 rounded-xl shadow-inner scale-90 md:scale-100">
          <button onClick={() => changeMonth(-1)} className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"><ChevronLeft size={18} /></button>
          <div className="relative">
            <button onClick={() => setShowMonthPicker(!showMonthPicker)} className="px-2 py-1.5 text-xs font-semibold text-slate-700 min-w-[100px] text-center hover:bg-white/50 rounded-lg transition-colors">{currentFormatted}</button>
            {showMonthPicker && (
              <div className="absolute top-full mt-2 left-0 w-64 bg-white border border-slate-200 rounded-2xl shadow-2xl p-4 grid grid-cols-3 gap-2 z-50 animate-in fade-in zoom-in duration-200">
                {monthNames.map((name, idx) => (
                  <button key={name} onClick={() => { const year = currentDate.split('-')[0]; setMonth(`${year}-${String(idx + 1).padStart(2, '0')}`); setShowMonthPicker(false); }} className={`p-2 text-xs rounded-lg font-medium transition-colors ${currentDate.split('-')[1] === String(idx + 1).padStart(2, '0') ? 'bg-blue-600 text-white' : 'hover:bg-slate-100 text-slate-600'}`}>{name.substring(0, 3)}</button>
                ))}
              </div>
            )}
          </div>
          <button onClick={() => changeMonth(1)} className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"><ChevronRight size={18} /></button>
        </div>
      </div>
      <div className="flex items-center gap-3">
        <div className="w-8 h-8 rounded-full bg-blue-100 border-2 border-white shadow-sm overflow-hidden flex items-center justify-center">
          <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Felix" alt="avatar" />
        </div>
      </div>
    </header>
  );
};

const QuickAddButton = () => {
  const [open, setOpen] = useState(false);
  const navigate = useNavigate();
  return (
    <div className="fixed bottom-6 right-6 md:bottom-8 md:right-8 z-40">
      {open && (
        <div className="absolute bottom-16 right-0 mb-2 flex flex-col gap-2 animate-in slide-in-from-bottom-4 duration-300">
          <button onClick={() => { setOpen(false); navigate('/transactions', { state: { openModal: true } }); }} className="flex items-center gap-2 bg-white text-slate-800 px-4 py-3 rounded-2xl shadow-lg hover:bg-slate-50 border border-slate-100 transition-all whitespace-nowrap text-left"><Receipt size={18} className="text-blue-500" /><span className="text-sm font-semibold">Nueva Transacción</span></button>
          <button onClick={() => { setOpen(false); navigate('/transactions', { state: { openScanner: true } }); }} className="flex items-center gap-2 bg-white text-slate-800 px-4 py-3 rounded-2xl shadow-lg hover:bg-slate-50 border border-slate-100 transition-all whitespace-nowrap text-left"><Camera size={18} className="text-emerald-500" /><span className="text-sm font-semibold">Escanear Ticket</span></button>
          <Link to="/advisor" onClick={() => setOpen(false)} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-3 rounded-2xl shadow-lg hover:bg-blue-700 transition-all whitespace-nowrap"><MessageSquare size={18} /><span className="text-sm font-semibold">Hablar con Aura</span></Link>
        </div>
      )}
      <button onClick={() => setOpen(!open)} className={`w-12 h-12 md:w-14 md:h-14 rounded-2xl shadow-xl flex items-center justify-center transition-all duration-300 ${open ? 'bg-slate-800 rotate-45' : 'bg-blue-600'}`}><Plus size={24} className="text-white" /></button>
    </div>
  );
};
export default App;
